-- V11: Seed ID translations juz06_10

INSERT INTO mst_translation (ayah_id, language_id, translator_name, text,
                             created_at, updated_at)
VALUES
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 4 AND a.ayah_number = 148), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Allah tidak menyukai ucapan buruk, (yang diucapkan) dengan terus terang kecuali oleh orang yang dianiaya. Allah adalah Maha Mendengar lagi Maha Mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 4 AND a.ayah_number = 149), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Jika kamu melahirkan sesuatu kebaikan atau menyembunyikan atau memaafkan sesuatu kesalahan (orang lain), maka sesungguhnya Allah Maha Pemaaf lagi Maha Kuasa.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 4 AND a.ayah_number = 150), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya orang-orang yang kafir kepada Allah dan rasul-rasul-Nya, dan bermaksud memperbedakan antara (keimanan kepada) Allah dan rasul-rasul-Nya, dengan mengatakan: "Kami beriman kepada yang sebahagian dan kami kafir terhadap sebahagian (yang lain)", serta bermaksud (dengan perkataan itu) mengambil jalan (tengah) di antara yang demikian (iman atau kafir),', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 4 AND a.ayah_number = 151), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'merekalah orang-orang yang kafir sebenar-benarnya. Kami telah menyediakan untuk orang-orang yang kafir itu siksaan yang menghinakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 4 AND a.ayah_number = 152), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Orang-orang yang beriman kepada Allah dan para rasul-Nya dan tidak membeda-bedakan seorangpun di antara mereka, kelak Allah akan memberikan kepada mereka pahalanya. Dan adalah Allah Maha Pengampun lagi Maha Penyayang.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 4 AND a.ayah_number = 153), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Ahli Kitab meminta kepadamu agar kamu menurunkan kepada mereka sebuah Kitab dari langit. Maka sesungguhnya mereka telah meminta kepada Musa yang lebih besar dari itu. Mereka berkata: "Perlihatkanlah Allah kepada kami dengan nyata". Maka mereka disambar petir karena kezalimannya, dan mereka menyembah anak sapi, sesudah datang kepada mereka bukti-bukti yang nyata, lalu Kami maafkan (mereka) dari yang demikian. Dan telah Kami berikan kepada Musa keterangan yang nyata.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 4 AND a.ayah_number = 154), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan telah Kami angkat ke atas (kepala) mereka bukit Thursina untuk (menerima) perjanjian (yang telah Kami ambil dari) mereka. Dan kami perintahkan kepada mereka: "Masuklah pintu gerbang itu sambil bersujud", dan Kami perintahkan (pula) kepada mereka: "Janganlah kamu melanggar peraturan mengenai hari Sabtu", dan Kami telah mengambil dari mereka perjanjian yang kokoh.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 4 AND a.ayah_number = 155), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka (Kami lakukan terhadap mereka beberapa tindakan), disebabkan mereka melanggar perjanjian itu, dan karena kekafiran mereka terhadap keterangan-keterangan Allah dan mereka membunuh nabi-nabi tanpa (alasan) yang benar dan mengatakan: "Hati kami tertutup". Bahkan, sebenarnya Allah telah mengunci mati hati mereka karena kekafirannya, karena itu mereka tidak beriman kecuali sebahagian kecil dari mereka.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 4 AND a.ayah_number = 156), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan karena kekafiran mereka (terhadap Isa) dan tuduhan mereka terhadap Maryam dengan kedustaan besar (zina),', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 4 AND a.ayah_number = 157), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan karena ucapan mereka: "Sesungguhnya kami telah membunuh Al Masih, Isa putra Maryam, Rasul Allah", padahal mereka tidak membunuhnya dan tidak (pula) menyalibnya, tetapi (yang mereka bunuh ialah) orang yang diserupakan dengan Isa bagi mereka. Sesungguhnya orang-orang yang berselisih paham tentang (pembunuhan) Isa, benar-benar dalam keragu-raguan tentang yang dibunuh itu. Mereka tidak mempunyai keyakinan tentang siapa yang dibunuh itu, kecuali mengikuti persangkaan belaka, mereka tidak (pula) yakin bahwa yang mereka bunuh itu adalah Isa.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 4 AND a.ayah_number = 158), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tetapi (yang sebenarnya), Allah telah mengangkat Isa kepada-Nya. Dan adalah Allah Maha Perkasa lagi Maha Bijaksana.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 4 AND a.ayah_number = 159), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tidak ada seorangpun dari Ahli Kitab, kecuali akan beriman kepadanya (Isa) sebelum kematiannya. Dan di hari kiamat nanti Isa itu akan menjadi saksi terhadap mereka.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 4 AND a.ayah_number = 160), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka disebabkan kezaliman orang-orang Yahudi, kami haramkan atas (memakan makanan) yang baik-baik (yang dahulunya) dihalalkan bagi mereka, dan karena mereka banyak menghalangi (manusia) dari jalan Allah,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 4 AND a.ayah_number = 161), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan disebabkan mereka memakan riba, padahal sesungguhnya mereka telah dilarang daripadanya, dan karena mereka memakan harta benda orang dengan jalan yang batil. Kami telah menyediakan untuk orang-orang yang kafir di antara mereka itu siksa yang pedih.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 4 AND a.ayah_number = 162), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tetapi orang-orang yang mendalam ilmunya di antara mereka dan orang-orang mukmin, mereka beriman kepada apa yang telah diturunkan kepadamu (Al Quran), dan apa yang telah diturunkan sebelummu dan orang-orang yang mendirikan shalat, menunaikan zakat, dan yang beriman kepada Allah dan hari kemudian. Orang-orang itulah yang akan Kami berikan kepada mereka pahala yang besar.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 4 AND a.ayah_number = 163), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya Kami telah memberikan wahyu kepadamu sebagaimana Kami telah memberikan wahyu kepada Nuh dan nabi-nabi yang kemudiannya, dan Kami telah memberikan wahyu (pula) kepada Ibrahim, Isma''il, Ishak, Ya''qub dan anak cucunya, Isa, Ayyub, Yunus, Harun dan Sulaiman. Dan Kami berikan Zabur kepada Daud.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 4 AND a.ayah_number = 164), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (Kami telah mengutus) rasul-rasul yang sungguh telah Kami kisahkan tentang mereka kepadamu dahulu, dan rasul-rasul yang tidak Kami kisahkan tentang mereka kepadamu. Dan Allah telah berbicara kepada Musa dengan langsung.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 4 AND a.ayah_number = 165), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Mereka Kami utus) selaku rasul-rasul pembawa berita gembira dan pemberi peringatan agar supaya tidak ada alasan bagi manusia membantah Allah sesudah diutusnya rasul-rasul itu. Dan adalah Allah Maha Perkasa lagi Maha Bijaksana.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 4 AND a.ayah_number = 166), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Mereka tidak mau mengakui yang diturunkan kepadamu itu), tetapi Allah mengakui Al Quran yang diturunkan-Nya kepadamu. Allah menurunkannya dengan ilmu-Nya; dan malaikat-malaikat pun menjadi saksi (pula). Cukuplah Allah yang mengakuinya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 4 AND a.ayah_number = 167), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya orang-orang yang kafir dan menghalang-halangi (manusia) dari jalan Allah, benar-benar telah sesat sejauh-jauhnya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 4 AND a.ayah_number = 168), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya orang-orang yang kafir dan melakukan kezaliman, Allah sekali-kali tidak akan mengampuni (dosa) mereka dan tidak (pula) akan menunjukkan jalan kepada mereka,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 4 AND a.ayah_number = 169), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'kecuali jalan ke neraka Jahannam; mereka kekal di dalamnya selama-lamanya. Dan yang demikian itu adalah mudah bagi Allah.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 4 AND a.ayah_number = 170), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Wahai manusia, sesungguhnya telah datang Rasul (Muhammad) itu kepadamu dengan (membawa) kebenaran dari Tuhanmu, maka berimanlah kamu, itulah yang lebih baik bagimu. Dan jika kamu kafir, (maka kekafiran itu tidak merugikan Allah sedikitpun) karena sesungguhnya apa yang di langit dan di bumi itu adalah kepunyaan Allah. Dan adalah Allah Maha Mengetahui lagi Maha Bijaksana.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 4 AND a.ayah_number = 171), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Wahai Ahli Kitab, janganlah kamu melampaui batas dalam agamamu, dan janganlah kamu mengatakan terhadap Allah kecuali yang benar. Sesungguhnya Al Masih, Isa putera Maryam itu, adalah utusan Allah dan (yang diciptakan dengan) kalimat-Nya yang disampaikan-Nya kepada Maryam, dan (dengan tiupan) roh dari-Nya. Maka berimanlah kamu kepada Allah dan rasul-rasul-Nya dan janganlah kamu mengatakan: "(Tuhan itu) tiga", berhentilah (dari ucapan itu). (Itu) lebih baik bagimu. Sesungguhnya Allah Tuhan Yang Maha Esa, Maha Suci Allah dari mempunyai anak, segala yang di langit dan di bumi adalah kepunyaan-Nya. Cukuplah Allah menjadi Pemelihara.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 4 AND a.ayah_number = 172), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Al Masih sekali-kali tidak enggan menjadi hamba bagi Allah, dan tidak (pula enggan) malaikat-malaikat yang terdekat (kepada Allah). Barangsiapa yang enggan dari menyembah-Nya, dan menyombongkan diri, nanti Allah akan mengumpulkan mereka semua kepada-Nya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 4 AND a.ayah_number = 173), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Adapun orang-orang yang beriman dan berbuat amal saleh, maka Allah akan menyempurnakan pahala mereka dan menambah untuk mereka sebagian dari karunia-Nya. Adapun orang-orang yang enggan dan menyombongkan diri, maka Allah akan menyiksa mereka dengan siksaan yang pedih, dan mereka tidak akan memperoleh bagi diri mereka, pelindung dan penolong selain dari pada Allah.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 4 AND a.ayah_number = 174), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai manusia, sesungguhnya telah datang kepadamu bukti kebenaran dari Tuhanmu. (Muhammad dengan mukjizatnya) dan telah Kami turunkan kepadamu cahaya yang terang benderang (Al Quran).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 4 AND a.ayah_number = 175), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Adapun orang-orang yang beriman kepada Allah dan berpegang teguh kepada (agama)-Nya niscaya Allah akan memasukkan mereka ke dalam rahmat yang besar dari-Nya (surga) dan limpahan karunia-Nya. Dan menunjuki mereka kepada jalan yang lurus (untuk sampai) kepada-Nya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 4 AND a.ayah_number = 176), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka meminta fatwa kepadamu (tentang kalalah). Katakanlah: "Allah memberi fatwa kepadamu tentang kalalah (yaitu): jika seorang meninggal dunia, dan ia tidak mempunyai anak dan mempunyai saudara perempuan, maka bagi saudaranya yang perempuan itu seperdua dari harta yang ditinggalkannya, dan saudaranya yang laki-laki mempusakai (seluruh harta saudara perempuan), jika ia tidak mempunyai anak; tetapi jika saudara perempuan itu dua orang, maka bagi keduanya dua pertiga dari harta yang ditinggalkan oleh yang meninggal. Dan jika mereka (ahli waris itu terdiri dari) saudara-saudara laki dan perempuan, maka bahagian seorang saudara laki-laki sebanyak bahagian dua orang saudara perempuan. Allah menerangkan (hukum ini) kepadamu, supaya kamu tidak sesat. Dan Allah Maha Mengetahui segala sesuatu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai orang-orang yang beriman, penuhilah aqad-aqad itu. Dihalalkan bagimu binatang ternak, kecuali yang akan dibacakan kepadamu. (Yang demikian itu) dengan tidak menghalalkan berburu ketika kamu sedang mengerjakan haji. Sesungguhnya Allah menetapkan hukum-hukum menurut yang dikehendaki-Nya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai orang-orang yang beriman, janganlah kamu melanggar syi''ar-syi''ar Allah, dan jangan melanggar kehormatan bulan-bulan haram, jangan (mengganggu) binatang-binatang had-ya, dan binatang-binatang qalaa-id, dan jangan (pula) mengganggu orang-orang yang mengunjungi Baitullah sedang mereka mencari kurnia dan keridhaan dari Tuhannya dan apabila kamu telah menyelesaikan ibadah haji, maka bolehlah berburu. Dan janganlah sekali-kali kebencian(mu) kepada sesuatu kaum karena mereka menghalang-halangi kamu dari Masjidilharam, mendorongmu berbuat aniaya (kepada mereka). Dan tolong-menolonglah kamu dalam (mengerjakan) kebajikan dan takwa, dan jangan tolong-menolong dalam berbuat dosa dan pelanggaran. Dan bertakwalah kamu kepada Allah, sesungguhnya Allah amat berat siksa-Nya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Diharamkan bagimu (memakan) bangkai, darah, daging babi, (daging hewan) yang disembelih atas nama selain Allah, yang tercekik, yang terpukul, yang jatuh, yang ditanduk, dan diterkam binatang buas, kecuali yang sempat kamu menyembelihnya, dan (diharamkan bagimu) yang disembelih untuk berhala. Dan (diharamkan juga) mengundi nasib dengan anak panah, (mengundi nasib dengan anak panah itu) adalah kefasikan. Pada hari ini orang-orang kafir telah putus asa untuk (mengalahkan) agamamu, sebab itu janganlah kamu takut kepada mereka dan takutlah kepada-Ku. Pada hari ini telah Kusempurnakan untuk kamu agamamu, dan telah Ku-cukupkan kepadamu nikmat-Ku, dan telah Ku-ridhai Islam itu jadi agama bagimu. Maka barang siapa terpaksa karena kelaparan tanpa sengaja berbuat dosa, sesungguhnya Allah Maha Pengampun lagi Maha Penyayang.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka menanyakan kepadamu: "Apakah yang dihalalkan bagi mereka?". Katakanlah: "Dihalalkan bagimu yang baik-baik dan (buruan yang ditangkap) oleh binatang buas yang telah kamu ajar dengan melatih nya untuk berburu; kamu mengajarnya menurut apa yang telah diajarkan Allah kepadamu. Maka makanlah dari apa yang ditangkapnya untukmu, dan sebutlah nama Allah atas binatang buas itu (waktu melepaskannya). Dan bertakwalah kepada Allah, sesungguhnya Allah amat cepat hisab-Nya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Pada hari ini dihalalkan bagimu yang baik-baik. Makanan (sembelihan) orang-orang yang diberi Al Kitab itu halal bagimu, dan makanan kamu halal (pula) bagi mereka. (Dan dihalalkan mangawini) wanita yang menjaga kehormatan diantara wanita-wanita yang beriman dan wanita-wanita yang menjaga kehormatan di antara orang-orang yang diberi Al Kitab sebelum kamu, bila kamu telah membayar mas kawin mereka dengan maksud menikahinya, tidak dengan maksud berzina dan tidak (pula) menjadikannya gundik-gundik. Barangsiapa yang kafir sesudah beriman (tidak menerima hukum-hukum Islam) maka hapuslah amalannya dan ia di hari kiamat termasuk orang-orang merugi.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai orang-orang yang beriman, apabila kamu hendak mengerjakan shalat, maka basuhlah mukamu dan tanganmu sampai dengan siku, dan sapulah kepalamu dan (basuh) kakimu sampai dengan kedua mata kaki, dan jika kamu junub maka mandilah, dan jika kamu sakit atau dalam perjalanan atau kembali dari tempat buang air (kakus) atau menyentuh perempuan, lalu kamu tidak memperoleh air, maka bertayammumlah dengan tanah yang baik (bersih); sapulah mukamu dan tanganmu dengan tanah itu. Allah tidak hendak menyulitkan kamu, tetapi Dia hendak membersihkan kamu dan menyempurnakan nikmat-Nya bagimu, supaya kamu bersyukur.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan ingatlah karunia Allah kepadamu dan perjanjian-Nya yang telah diikat-Nya dengan kamu, ketika kamu mengatakan: "Kami dengar dan kami taati". Dan bertakwalah kepada Allah, sesungguhnya Allah Mengetahui isi hati(mu).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai orang-orang yang beriman hendaklah kamu jadi orang-orang yang selalu menegakkan (kebenaran) karena Allah, menjadi saksi dengan adil. Dan janganlah sekali-kali kebencianmu terhadap sesuatu kaum, mendorong kamu untuk berlaku tidak adil. Berlaku adillah, karena adil itu lebih dekat kepada takwa. Dan bertakwalah kepada Allah, sesungguhnya Allah Maha Mengetahui apa yang kamu kerjakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Allah telah menjanjikan kepada orang-orang yang beriman dan yang beramal saleh, (bahwa) untuk mereka ampunan dan pahala yang besar.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Adapun orang-orang yang kafir dan mendustakan ayat-ayat Kami, mereka itu adalah penghuni neraka.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai orang-orang yang beriman, ingatlah kamu akan nikmat Allah (yang diberikan-Nya) kepadamu, di waktu suatu kaum bermaksud hendak menggerakkan tangannya kepadamu (untuk berbuat jahat), maka Allah menahan tangan mereka dari kamu. Dan bertakwalah kepada Allah, dan hanya kepada Allah sajalah orang-orang mukmin itu harus bertawakkal.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya Allah telah mengambil perjanjian (dari) Bani Israil dan telah Kami angkat diantara mereka 12 orang pemimpin dan Allah berfirman: "Sesungguhnya Aku beserta kamu, sesungguhnya jika kamu mendirikan shalat dan menunaikan zakat serta beriman kepada rasul-rasul-Ku dan kamu bantu mereka dan kamu pinjamkan kepada Allah pinjaman yang baik sesungguhnya Aku akan menutupi dosa-dosamu. Dan sesungguhnya kamu akan Kumasukkan ke dalam surga yang mengalir air didalamnya sungai-sungai. Maka barangsiapa yang kafir di antaramu sesudah itu, sesungguhnya ia telah tersesat dari jalan yang lurus.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Tetapi) karena mereka melanggar janjinya, Kami kutuki mereka, dan Kami jadikan hati mereka keras membatu. Mereka suka merubah perkataan (Allah) dari tempat-tempatnya, dan mereka (sengaja) melupakan sebagian dari apa yang mereka telah diperingatkan dengannya, dan kamu (Muhammad) senantiasa akan melihat kekhianatan dari mereka kecuali sedikit diantara mereka (yang tidak berkhianat), maka maafkanlah mereka dan biarkan mereka, sesungguhnya Allah menyukai orang-orang yang berbuat baik.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan diantara orang-orang yang mengatakan: "Sesungguhnya kami ini orang-orang Nasrani", ada yang telah kami ambil perjanjian mereka, tetapi mereka (sengaja) melupakan sebagian dari apa yang mereka telah diberi peringatan dengannya; maka Kami timbulkan di antara mereka permusuhan dan kebencian sampai hari kiamat. Dan kelak Allah akan memberitakan kepada mereka apa yang mereka kerjakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai Ahli Kitab, sesungguhnya telah datang kepadamu Rasul Kami, menjelaskan kepadamu banyak dari isi Al Kitab yang kamu sembunyi kan, dan banyak (pula yang) dibiarkannya. Sesungguhnya telah datang kepadamu cahaya dari Allah, dan Kitab yang menerangkan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dengan kitab itulah Allah menunjuki orang-orang yang mengikuti keridhaan-Nya ke jalan keselamatan, dan (dengan kitab itu pula) Allah mengeluarkan orang-orang itu dari gelap gulita kepada cahaya yang terang benderang dengan seizin-Nya, dan menunjuki mereka ke jalan yang lurus.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya telah kafirlah orang-orang yang berkata: "Sesungguhnya Allah itu ialah Al Masih putera Maryam". Katakanlah: "Maka siapakah (gerangan) yang dapat menghalang-halangi kehendak Allah, jika Dia hendak membinasakan Al Masih putera Maryam itu beserta ibunya dan seluruh orang-orang yang berada di bumi kesemuanya?". Kepunyaan Allahlah kerajaan langit dan bumi dan apa yang ada diantara keduanya; Dia menciptakan apa yang dikehendaki-Nya. Dan Allah Maha Kuasa atas segala sesuatu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Orang-orang Yahudi dan Nasrani mengatakan: "Kami ini adalah anak-anak Allah dan kekasih-kekasih-Nya". Katakanlah: "Maka mengapa Allah menyiksa kamu karena dosa-dosamu?" (Kamu bukanlah anak-anak Allah dan kekasih-kekasih-Nya), tetapi kamu adalah manusia(biasa) diantara orang-orang yang diciptakan-Nya. Dia mengampuni bagi siapa yang dikehendaki-Nya dan menyiksa siapa yang dikehendaki-Nya. Dan Kepunyaan Allah-lah kerajaan antara keduanya. Dan kepada Allah-lah kembali (segala sesuatu).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai Ahli Kitab, sesungguhnya telah datang kepada kamu Rasul Kami, menjelaskan (syari''at Kami) kepadamu ketika terputus (pengiriman) rasul-rasul agar kamu tidak mengatakan: "Tidak ada datang kepada kami baik seorang pembawa berita gembira maupun seorang pemberi peringatan". Sesungguhnya telah datang kepadamu pembawa berita gembira dan pemberi peringatan. Allah Maha Kuasa atas segala sesuatu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (ingatlah) ketika Musa berkata kepada kaumnya: "Hai kaumku, ingatlah nikmat Allah atasmu ketika Dia mengangkat nabi nabi diantaramu, dan dijadikan-Nya kamu orang-orang merdeka, dan diberikan-Nya kepadamu apa yang belum pernah diberikan-Nya kepada seorangpun diantara umat-umat yang lain".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai kaumku, masuklah ke tanah suci (Palestina) yang telah ditentukan Allah bagimu, dan janganlah kamu lari kebelakang (karena takut kepada musuh), maka kamu menjadi orang-orang yang merugi.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka berkata: "Hai Musa, sesungguhnya dalam negeri itu ada orang-orang yang gagah perkasa, sesungguhnya kami sekali-kali tidak akan memasukinya sebelum mereka ke luar daripadanya. Jika mereka ke luar daripadanya, pasti kami akan memasukinya".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Berkatalah dua orang diantara orang-orang yang takut (kepada Allah) yang Allah telah memberi nikmat atas keduanya: "Serbulah mereka dengan melalui pintu gerbang (kota) itu, maka bila kamu memasukinya niscaya kamu akan menang. Dan hanya kepada Allah hendaknya kamu bertawakkal, jika kamu benar-benar orang yang beriman".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka berkata: "Hai Musa, kami sekali sekali tidak akan memasukinya selama-lamanya, selagi mereka ada didalamnya, karena itu pergilah kamu bersama Tuhanmu, dan berperanglah kamu berdua, sesungguhnya kami hanya duduk menanti disini saja".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Berkata Musa: "Ya Tuhanku, aku tidak menguasai kecuali diriku sendiri dan saudaraku. Sebab itu pisahkanlah antara kami dengan orang-orang yang fasik itu".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Allah berfirman: "(Jika demikian), maka sesungguhnya negeri itu diharamkan atas mereka selama empat puluh tahun, (selama itu) mereka akan berputar-putar kebingungan di bumi (padang Tiih) itu. Maka janganlah kamu bersedih hati (memikirkan nasib) orang-orang yang fasik itu".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Ceritakanlah kepada mereka kisah kedua putera Adam (Habil dan Qabil) menurut yang sebenarnya, ketika keduanya mempersembahkan korban, maka diterima dari salah seorang dari mereka berdua (Habil) dan tidak diterima dari yang lain (Qabil). Ia berkata (Qabil): "Aku pasti membunuhmu!". Berkata Habil: "Sesungguhnya Allah hanya menerima (korban) dari orang-orang yang bertakwa".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '"Sungguh kalau kamu menggerakkan tanganmu kepadaku untuk membunuhku, aku sekali-kali tidak akan menggerakkan tanganku kepadamu untuk membunuhmu. Sesungguhnya aku takut kepada Allah, Tuhan seru sekalian alam".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '"Sesungguhnya aku ingin agar kamu kembali dengan (membawa) dosa (membunuh)ku dan dosamu sendiri, maka kamu akan menjadi penghuni neraka, dan yang demikian itulah pembalasan bagi orang-orang yang zalim".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka hawa nafsu Qabil menjadikannya menganggap mudah membunuh saudaranya, sebab itu dibunuhnyalah, maka jadilah ia seorang diantara orang-orang yang merugi.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kemudian Allah menyuruh seekor burung gagak menggali-gali di bumi untuk memperlihatkan kepadanya (Qabil) bagaimana seharusnya menguburkan mayat saudaranya. Berkata Qabil: "Aduhai celaka aku, mengapa aku tidak mampu berbuat seperti burung gagak ini, lalu aku dapat menguburkan mayat saudaraku ini?" Karena itu jadilah dia seorang diantara orang-orang yang menyesal.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Oleh karena itu Kami tetapkan (suatu hukum) bagi Bani Israil, bahwa: barangsiapa yang membunuh seorang manusia, bukan karena orang itu (membunuh) orang lain, atau bukan karena membuat kerusakan dimuka bumi, maka seakan-akan dia telah membunuh manusia seluruhnya. Dan barangsiapa yang memelihara kehidupan seorang manusia, maka seolah-olah dia telah memelihara kehidupan manusia semuanya. Dan sesungguhnya telah datang kepada mereka rasul-rasul Kami dengan (membawa) keterangan-keterangan yang jelas, kemudian banyak diantara mereka sesudah itu sungguh-sungguh melampaui batas dalam berbuat kerusakan dimuka bumi.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya pembalasan terhadap orang-orang yang memerangi Allah dan Rasul-Nya dan membuat kerusakan di muka bumi, hanyalah mereka dibunuh atau disalib, atau dipotong tangan dan kaki mereka dengan bertimbal balik, atau dibuang dari negeri (tempat kediamannya). Yang demikian itu (sebagai) suatu penghinaan untuk mereka didunia, dan di akhirat mereka beroleh siksaan yang besar,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'kecuali orang-orang yang taubat (di antara mereka) sebelum kamu dapat menguasai (menangkap) mereka; maka ketahuilah bahwasanya Allah Maha Pengampun lagi Maha Penyayang.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai orang-orang yang beriman, bertakwalah kepada Allah dan carilah jalan yang mendekatkan diri kepada-Nya, dan berjihadlah pada jalan-Nya, supaya kamu mendapat keberuntungan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya orang-orang yang kafir sekiranya mereka mempunyai apa yang dibumi ini seluruhnya dan mempunyai yang sebanyak itu (pula) untuk menebusi diri mereka dengan itu dari azab hari kiamat, niscaya (tebusan itu) tidak akan diterima dari mereka, dan mereka beroleh azab yang pedih.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka ingin keluar dari neraka, padahal mereka sekali-kali tidak dapat keluar daripadanya, dan mereka beroleh azab yang kekal.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Laki-laki yang mencuri dan perempuan yang mencuri, potonglah tangan keduanya (sebagai) pembalasan bagi apa yang mereka kerjakan dan sebagai siksaan dari Allah. Dan Allah Maha Perkasa lagi Maha Bijaksana.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka barangsiapa bertaubat (di antara pencuri-pencuri itu) sesudah melakukan kejahatan itu dan memperbaiki diri, maka sesungguhnya Allah menerima taubatnya. Sesungguhnya Allah Maha Pengampun lagi Maha Penyayang.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tidakkah kamu tahu, sesungguhnya Allah-lah yang mempunyai kerajaan langit dan bumi, disiksa-Nya siapa yang dikehendaki-Nya dan diampuni-Nya bagi siapa yang dikehendaki-Nya. Dan Allah Maha Kuasa atas segala sesuatu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hari Rasul, janganlah hendaknya kamu disedihkan oleh orang-orang yang bersegera (memperlihatkan) kekafirannya, yaitu diantara orang-orang yang mengatakan dengan mulut mereka: "Kami telah beriman", padahal hati mereka belum beriman; dan (juga) di antara orang-orang Yahudi. (Orang-orang Yahudi itu) amat suka mendengar (berita-berita) bohong dan amat suka mendengar perkataan-perkataan orang lain yang belum pernah datang kepadamu; mereka merubah perkataan-perkataan (Taurat) dari tempat-tempatnya. Mereka mengatakan: "Jika diberikan ini (yang sudah di rubah-rubah oleh mereka) kepada kamu, maka terimalah, dan jika kamu diberi yang bukan ini maka hati-hatilah". Barangsiapa yang Allah menghendaki kesesatannya, maka sekali-kali kamu tidak akan mampu menolak sesuatupun (yang datang) daripada Allah. Mereka itu adalah orang-orang yang Allah tidak hendak mensucikan hati mereka. Mereka beroleh kehinaan di dunia dan di akhirat mereka beroleh siksaan yang besar.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka itu adalah orang-orang yang suka mendengar berita bohong, banyak memakan yang haram. Jika mereka (orang Yahudi) datang kepadamu (untuk meminta putusan), maka putuskanlah (perkara itu) diantara mereka, atau berpalinglah dari mereka; jika kamu berpaling dari mereka maka mereka tidak akan memberi mudharat kepadamu sedikitpun. Dan jika kamu memutuskan perkara mereka, maka putuskanlah (perkara itu) diantara mereka dengan adil, sesungguhnya Allah menyukai orang-orang yang adil.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan bagaimanakah mereka mengangkatmu menjadi hakim mereka, padahal mereka mempunyai Taurat yang didalamnya (ada) hukum Allah, kemudian mereka berpaling sesudah itu (dari putusanmu)? Dan mereka sungguh-sungguh bukan orang yang beriman.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 44), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya Kami telah menurunkan Kitab Taurat di dalamnya (ada) petunjuk dan cahaya (yang menerangi), yang dengan Kitab itu diputuskan perkara orang-orang Yahudi oleh nabi-nabi yang menyerah diri kepada Allah, oleh orang-orang alim mereka dan pendeta-pendeta mereka, disebabkan mereka diperintahkan memelihara kitab-kitab Allah dan mereka menjadi saksi terhadapnya. Karena itu janganlah kamu takut kepada manusia, (tetapi) takutlah kepada-Ku. Dan janganlah kamu menukar ayat-ayat-Ku dengan harga yang sedikit. Barangsiapa yang tidak memutuskan menurut apa yang diturunkan Allah, maka mereka itu adalah orang-orang yang kafir.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 45), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Kami telah tetapkan terhadap mereka di dalamnya (At Taurat) bahwasanya jiwa (dibalas) dengan jiwa, mata dengan mata, hidung dengan hidung, telinga dengan telinga, gigi dengan gigi, dan luka luka (pun) ada qishaashnya. Barangsiapa yang melepaskan (hak qishaash)nya, maka melepaskan hak itu (menjadi) penebus dosa baginya. Barangsiapa tidak memutuskan perkara menurut apa yang diturunkan Allah, maka mereka itu adalah orang-orang yang zalim.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 46), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Kami iringkan jejak mereka (nabi nabi Bani Israil) dengan Isa putera Maryam, membenarkan Kitab yang sebelumnya, yaitu: Taurat. Dan Kami telah memberikan kepadanya Kitab Injil sedang didalamnya (ada) petunjuk dan dan cahaya (yang menerangi), dan membenarkan kitab yang sebelumnya, yaitu Kitab Taurat. Dan menjadi petunjuk serta pengajaran untuk orang-orang yang bertakwa.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 47), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan hendaklah orang-orang pengikut Injil, memutuskan perkara menurut apa yang diturunkan Allah didalamnya. Barangsiapa tidak memutuskan perkara menurut apa yang diturunkan Allah, maka mereka itu adalah orang-orang yang fasik.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 48), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Kami telah turunkan kepadamu Al Quran dengan membawa kebenaran, membenarkan apa yang sebelumnya, yaitu kitab-kitab (yang diturunkan sebelumnya) dan batu ujian terhadap kitab-kitab yang lain itu; maka putuskanlah perkara mereka menurut apa yang Allah turunkan dan janganlah kamu mengikuti hawa nafsu mereka dengan meninggalkan kebenaran yang telah datang kepadamu. Untuk tiap-tiap umat diantara kamu, Kami berikan aturan dan jalan yang terang. Sekiranya Allah menghendaki, niscaya kamu dijadikan-Nya satu umat (saja), tetapi Allah hendak menguji kamu terhadap pemberian-Nya kepadamu, maka berlomba-lombalah berbuat kebajikan. Hanya kepada Allah-lah kembali kamu semuanya, lalu diberitahukan-Nya kepadamu apa yang telah kamu perselisihkan itu,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 49), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan hendaklah kamu memutuskan perkara di antara mereka menurut apa yang diturunkan Allah, dan janganlah kamu mengikuti hawa nafsu mereka. Dan berhati-hatilah kamu terhadap mereka, supaya mereka tidak memalingkan kamu dari sebahagian apa yang telah diturunkan Allah kepadamu. Jika mereka berpaling (dari hukum yang telah diturunkan Allah), maka ketahuilah bahwa sesungguhnya Allah menghendaki akan menimpakan mushibah kepada mereka disebabkan sebahagian dosa-dosa mereka. Dan sesungguhnya kebanyakan manusia adalah orang-orang yang fasik.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 50), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Apakah hukum Jahiliyah yang mereka kehendaki, dan (hukum) siapakah yang lebih baik daripada (hukum) Allah bagi orang-orang yang yakin?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 51), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai orang-orang yang beriman, janganlah kamu mengambil orang-orang Yahudi dan Nasrani menjadi pemimpin-pemimpin(mu); sebahagian mereka adalah pemimpin bagi sebahagian yang lain. Barangsiapa diantara kamu mengambil mereka menjadi pemimpin, maka sesungguhnya orang itu termasuk golongan mereka. Sesungguhnya Allah tidak memberi petunjuk kepada orang-orang yang zalim.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 52), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka kamu akan melihat orang-orang yang ada penyakit dalam hatinya (orang-orang munafik) bersegera mendekati mereka (Yahudi dan Nasrani), seraya berkata: "Kami takut akan mendapat bencana". Mudah-mudahan Allah akan mendatangkan kemenangan (kepada Rasul-Nya), atau sesuatu keputusan dari sisi-Nya. Maka karena itu, mereka menjadi menyesal terhadap apa yang mereka rahasiakan dalam diri mereka.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 53), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan orang-orang yang beriman akan mengatakan: "Inikah orang-orang yang bersumpah sungguh-sungguh dengan nama Allah, bahwasanya mereka benar-benar beserta kamu?" Rusak binasalah segala amal mereka, lalu mereka menjadi orang-orang yang merugi.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 54), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai orang-orang yang beriman, barangsiapa di antara kamu yang murtad dari agamanya, maka kelak Allah akan mendatangkan suatu kaum yang Allah mencintai mereka dan merekapun mencintai-Nya, yang bersikap lemah lembut terhadap orang yang mukmin, yang bersikap keras terhadap orang-orang kafir, yang berjihad dijalan Allah, dan yang tidak takut kepada celaan orang yang suka mencela. Itulah karunia Allah, diberikan-Nya kepada siapa yang dikehendaki-Nya, dan Allah Maha Luas (pemberian-Nya), lagi Maha Mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 55), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya penolong kamu hanyalah Allah, Rasul-Nya, dan orang-orang yang beriman, yang mendirikan shalat dan menunaikan zakat, seraya mereka tunduk (kepada Allah).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 56), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan barangsiapa mengambil Allah, Rasul-Nya dan orang-orang yang beriman menjadi penolongnya, maka sesungguhnya pengikut (agama) Allah itulah yang pasti menang.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 57), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai orang-orang yang beriman, janganlah kamu mengambil jadi pemimpinmu, orang-orang yang membuat agamamu jadi buah ejekan dan permainan, (yaitu) di antara orang-orang yang telah diberi kitab sebelummu, dan orang-orang yang kafir (orang-orang musyrik). Dan bertakwalah kepada Allah jika kamu betul-betul orang-orang yang beriman.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 58), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan apabila kamu menyeru (mereka) untuk (mengerjakan) sembahyang, mereka menjadikannya buah ejekan dan permainan. Yang demikian itu adalah karena mereka benar-benar kaum yang tidak mau mempergunakan akal.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 59), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Hai Ahli Kitab, apakah kamu memandang kami salah, hanya lantaran kami beriman kepada Allah, kepada apa yang diturunkan kepada kami dan kepada apa yang diturunkan sebelumnya, sedang kebanyakan di antara kamu benar-benar orang-orang yang fasik?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 60), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Apakah akan aku beritakan kepadamu tentang orang-orang yang lebih buruk pembalasannya dari (orang-orang fasik) itu disisi Allah, yaitu orang-orang yang dikutuki dan dimurkai Allah, di antara mereka (ada) yang dijadikan kera dan babi dan (orang yang) menyembah thaghut?". Mereka itu lebih buruk tempatnya dan lebih tersesat dari jalan yang lurus.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 61), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan apabila orang-orang (Yahudi atau munafik) datang kepadamu, mereka mengatakan: "Kami telah beriman", padahal mereka datang kepadamu dengan kekafirannya dan mereka pergi (daripada kamu) dengan kekafirannya (pula); dan Allah lebih mengetahui apa yang mereka sembunyikan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 62), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan kamu akan melihat kebanyakan dari mereka (orang-orang Yahudi) bersegera membuat dosa, permusuhan dan memakan yang haram. Sesungguhnya amat buruk apa yang mereka telah kerjakan itu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 63), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mengapa orang-orang alim mereka, pendeta-pendeta mereka tidak melarang mereka mengucapkan perkataan bohong dan memakan yang haram? Sesungguhnya amat buruk apa yang telah mereka kerjakan itu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 64), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Orang-orang Yahudi berkata: "Tangan Allah terbelenggu", sebenarnya tangan merekalah yang dibelenggu dan merekalah yang dilaknat disebabkan apa yang telah mereka katakan itu. (Tidak demikian), tetapi kedua-dua tangan Allah terbuka; Dia menafkahkan sebagaimana Dia kehendaki. Dan Al Quran yang diturunkan kepadamu dari Tuhanmu sungguh-sungguh akan menambah kedurhakaan dan kekafiran bagi kebanyakan di antara mereka. Dan Kami telah timbulkan permusuhan dan kebencian di antara mereka sampai hari kiamat. Setiap mereka menyalakan api peperangan Allah memadamkannya dan mereka berbuat kerusakan dimuka bumi dan Allah tidak menyukai orang-orang yang membuat kerusakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 65), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sekiranya Ahli Kitab beriman dan bertakwa, tentulah Kami tutup (hapus) kesalahan-kesalahan mereka dan tentulah Kami masukkan mereka kedalam surga-surga yang penuh kenikmatan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 66), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sekiranya mereka sungguh-sungguh menjalankan (hukum) Taurat dan Injil dan (Al Quran) yang diturunkan kepada mereka dari Tuhannya, niscaya mereka akan mendapat makanan dari atas dan dari bawah kaki mereka. Diantara mereka ada golongan yang pertengahan. Dan alangkah buruknya apa yang dikerjakan oleh kebanyakan mereka.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 67), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai Rasul, sampaikanlah apa yang diturunkan kepadamu dari Tuhanmu. Dan jika tidak kamu kerjakan (apa yang diperintahkan itu, berarti) kamu tidak menyampaikan amanat-Nya. Allah memelihara kamu dari (gangguan) manusia. Sesungguhnya Allah tidak memberi petunjuk kepada orang-orang yang kafir.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 68), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Hai Ahli Kitab, kamu tidak dipandang beragama sedikitpun hingga kamu menegakkan ajaran-ajaran Taurat, Injil, dan Al Quran yang diturunkan kepadamu dari Tuhanmu". Sesungguhnya apa yang diturunkan kepadamu (Muhammad) dari Tuhanmu akan menambah kedurhakaan dan kekafiran kepada kebanyakan dari mereka; maka janganlah kamu bersedih hati terhadap orang-orang yang kafir itu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 69), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya orang-orang mukmin, orang-orang Yahudi, Shabiin dan orang-orang Nasrani, siapa saja (diantara mereka) yang benar-benar saleh, maka tidak ada kekhawatiran terhadap mereka dan tidak (pula) mereka bersedih hati.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 70), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya Kami telah mengambil perjanjian dari Bani Israil, dan telah Kami utus kepada mereka rasul-rasul. Tetapi setiap datang seorang rasul kepada mereka dengan membawa apa yang yang tidak diingini oleh hawa nafsu mereka, (maka) sebagian dari rasul-rasul itu mereka dustakan dan sebagian yang lain mereka bunuh.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 71), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan mereka mengira bahwa tidak akan terjadi suatu bencanapun (terhadap mereka dengan membunuh nabi-nabi itu), maka (karena itu) mereka menjadi buta dan pekak, kemudian Allah menerima taubat mereka, kemudian kebanyakan dari mereka buta dan tuli (lagi). Dan Allah Maha Melihat apa yang mereka kerjakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 72), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya telah kafirlah orang-orang yang berkata: "Sesungguhnya Allah ialah Al Masih putera Maryam", padahal Al Masih (sendiri) berkata: "Hai Bani Israil, sembahlah Allah Tuhanku dan Tuhanmu". Sesungguhnya orang yang mempersekutukan (sesuatu dengan) Allah, maka pasti Allah mengharamkan kepadanya surga, dan tempatnya ialah neraka, tidaklah ada bagi orang-orang zalim itu seorang penolongpun.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 73), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya kafirlah orang0orang yang mengatakan: "Bahwasanya Allah salah seorang dari yang tiga", padahal sekali-kali tidak ada Tuhan selain dari Tuhan Yang Esa. Jika mereka tidak berhenti dari apa yang mereka katakan itu, pasti orang-orang yang kafir diantara mereka akan ditimpa siksaan yang pedih.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 74), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka mengapa mereka tidak bertaubat kepada Allah dan memohon ampun kepada-Nya?. Dan Allah Maha Pengampun lagi Maha Penyayang.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 75), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Al Masih putera Maryam itu hanyalah seorang Rasul yang sesungguhnya telah berlalu sebelumnya beberapa rasul, dan ibunya seorang yang sangat benar, kedua-duanya biasa memakan makanan. Perhatikan bagaimana Kami menjelaskan kepada mereka (ahli kitab) tanda-tanda kekuasaan (Kami), kemudian perhatikanlah bagaimana mereka berpaling (dari memperhatikan ayat-ayat Kami itu).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 76), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Mengapa kamu menyembah selain daripada Allah, sesuatu yang tidak dapat memberi mudharat kepadamu dan tidak (pula) memberi manfaat?" Dan Allah-lah Yang Maha Mendengar lagi Maha Mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 77), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Hai Ahli Kitab, janganlah kamu berlebih-lebihan (melampaui batas) dengan cara tidak benar dalam agamamu. Dan janganlah kamu mengikuti hawa nafsu orang-orang yang telah sesat dahulunya (sebelum kedatangan Muhammad) dan mereka telah menyesatkan kebanyakan (manusia), dan mereka tersesat dari jalan yang lurus".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 78), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Telah dilaknati orang-orang kafir dari Bani Israil dengan lisan Daud dan Isa putera Maryam. Yang demikian itu, disebabkan mereka durhaka dan selalu melampaui batas.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 79), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka satu sama lain selalu tidak melarang tindakan munkar yang mereka perbuat. Sesungguhnya amat buruklah apa yang selalu mereka perbuat itu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 80), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kamu melihat kebanyakan dari mereka tolong-menolong dengan orang-orang yang kafir (musyrik). Sesungguhnya amat buruklah apa yang mereka sediakan untuk diri mereka, yaitu kemurkaan Allah kepada mereka; dan mereka akan kekal dalam siksaan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 81), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sekiranya mereka beriman kepada Allah, kepada Nabi (Musa) dan kepada apa yang diturunkan kepadanya (Nabi), niscaya mereka tidak akan mengambil orang-orang musyrikin itu menjadi penolong-penolong, tapi kebanyakan dari mereka adalah orang-orang yang fasik.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 82), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya kamu dapati orang-orang yang paling keras permusuhannya terhadap orang-orang yang beriman ialah orang-orang Yahudi dan orang-orang musyrik. Dan sesungguhnya kamu dapati yang paling dekat persahabatannya dengan orang-orang yang beriman ialah orang-orang yang berkata: "Sesungguhnya kami ini orang Nasrani". Yang demikian itu disebabkan karena di antara mereka itu (orang-orang Nasrani) terdapat pendeta-pendeta dan rahib-rahib, (juga) karena sesungguhnya mereka tidak menymbongkan diri.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 83), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan apabila mereka mendengarkan apa yang diturunkan kepada Rasul (Muhammad), kamu lihat mata mereka mencucurkan air mata disebabkan kebenaran (Al Quran) yang telah mereka ketahui (dari kitab-kitab mereka sendiri); seraya berkata: "Ya Tuhan kami, kami telah beriman, maka catatlah kami bersama orang-orang yang menjadi saksi (atas kebenaran Al Quran dan kenabian Muhammad s. a. w.).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 84), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mengapa kami tidak akan beriman kepada Allah dan kepada kebenaran yang datang kepada kami, padahal kami sangat ingin agar Tuhan kami memasukkan kami ke dalam golongan orang-orang yang saleh?".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 85), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka Allah memberi mereka pahala terhadap perkataan yang mereka ucapkan, (yaitu) surga yang mengalir sungai-sungai di dalamnya, sedang mereka kekal di dalamnya. Dan itulah balasan (bagi) orang-orang yang berbuat kebaikan (yang ikhlas keimanannya).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 86), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan orang-orang kafir serta mendustakan ayat-ayat Kami, mereka itulah penghuni neraka.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 87), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai orang-orang yang beriman, janganlah kamu haramkan apa-apa yang baik yang telah Allah halalkan bagi kamu, dan janganlah kamu melampaui batas. Sesungguhnya Allah tidak menyukai orang-orang yang melampaui batas.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 88), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan makanlah makanan yang halal lagi baik dari apa yang Allah telah rezekikan kepadamu, dan bertakwalah kepada Allah yang kamu beriman kepada-Nya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 89), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Allah tidak menghukum kamu disebabkan sumpah-sumpahmu yang tidak dimaksud (untuk bersumpah), tetapi Dia menghukum kamu disebabkan sumpah-sumpah yang kamu sengaja, maka kaffarat (melanggar) sumpah itu, ialah memberi makan sepuluh orang miskin, yaitu dari makanan yang biasa kamu berikan kepada keluargamu, atau memberi pakaian kepada mereka atau memerdekakan seorang budak. Barang siapa tidak sanggup melakukan yang demikian, maka kaffaratnya puasa selama tiga hari. Yang demikian itu adalah kaffarat sumpah-sumpahmu bila kamu bersumpah (dan kamu langgar). Dan jagalah sumpahmu. Demikianlah Allah menerangkan kepadamu hukum-hukum-Nya agar kamu bersyukur (kepada-Nya).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 90), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai orang-orang yang beriman, sesungguhnya (meminum) khamar, berjudi, (berkorban untuk) berhala, mengundi nasib dengan panah, adalah termasuk perbuatan syaitan. Maka jauhilah perbuatan-perbuatan itu agar kamu mendapat keberuntungan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 91), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya syaitan itu bermaksud hendak menimbulkan permusuhan dan kebencian di antara kamu lantaran (meminum) khamar dan berjudi itu, dan menghalangi kamu dari mengingat Allah dan sembahyang; maka berhentilah kamu (dari mengerjakan pekerjaan itu).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 92), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan taatlah kamu kepada Allah dan taatlah kamu kepada Rasul-(Nya) dan berhati-hatilah. Jika kamu berpaling, maka ketahuilah bahwa sesungguhnya kewajiban Rasul Kami, hanyalah menyampaikan (amanat Allah) dengan terang.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 93), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tidak ada dosa bagi orang-orang yang beriman dan mengerjakan amalan yang saleh karena memakan makanan yang telah mereka makan dahulu, apabila mereka bertakwa serta beriman, dan mengerjakan amalan-amalan yang saleh, kemudian mereka tetap bertakwa dan beriman, kemudian mereka (tetap juga) bertakwa dan berbuat kebajikan. Dan Allah menyukai orang-orang yang berbuat kebajikan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 94), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai orang-orang yang beriman, sesungguhnya Allah akan menguji kamu dengan sesuatu dari binatang buruan yang mudah didapat oleh tangan dan tombakmu supaya Allah mengetahui orang yang takut kepada-Nya, biarpun ia tidak dapat melihat-Nya. Barang siapa yang melanggar batas sesudah itu, maka baginya azab yang pedih.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 95), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai orang-orang yang beriman, janganlah kamu membunuh binatang buruan, ketika kamu sedang ihram. Barangsiapa di antara kamu membunuhnya dengan sengaja, maka dendanya ialah mengganti dengan binatang ternak seimbang dengan buruan yang dibunuhnya, menurut putusan dua orang yang adil di antara kamu sebagai had-yad yang dibawa sampai ke Ka''bah atau (dendanya) membayar kaffarat dengan memberi makan orang-orang miskin atau berpuasa seimbang dengan makanan yang dikeluarkan itu, supaya dia merasakan akibat buruk dari perbuatannya. Allah telah memaafkan apa yang telah lalu. Dan barangsiapa yang kembali mengerjakannya, niscaya Allah akan menyiksanya. Allah Maha Kuasa lagi mempunyai (kekuasaan untuk) menyiksa.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 96), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dihalalkan bagimu binatang buruan laut dan makanan (yang berasal) dari laut sebagai makanan yang lezat bagimu, dan bagi orang-orang yang dalam perjalanan; dan diharamkan atasmu (menangkap) binatang buruan darat, selama kamu dalam ihram. Dan bertakwalah kepada Allah Yang kepada-Nya-lah kamu akan dikumpulkan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 97), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Allah telah menjadikan Ka''bah, rumah suci itu sebagai pusat (peribadatan dan urusan dunia) bagi manusia, dan (demikian pula) bulan Haram, had-ya, qalaid. (Allah menjadikan yang) demikian itu agar kamu tahu, bahwa sesungguhnya Allah mengetahui apa yang ada di langit dan apa yang ada di bumi dan bahwa sesungguhnya Allah Maha Mengetahui segala sesuatu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 98), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Ketahuilah, bahwa sesungguhnya Allah amat berat siksa-Nya dan bahwa sesungguhnya Allah Maha Pengampun lagi Maha Penyayang.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 99), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kewajiban Rasul tidak lain hanyalah menyampaikan, dan Allah mengetahui apa yang kamu lahirkan dan apa yang kamu sembunyikan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 100), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Tidak sama yang buruk dengan yang baik, meskipun banyaknya yang buruk itu menarik hatimu, maka bertakwalah kepada Allah hai orang-orang berakal, agar kamu mendapat keberuntungan".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 101), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai orang-orang yang beriman, janganlah kamu menanyakan (kepada Nabimu) hal-hal yang jika diterangkan kepadamu akan menyusahkan kamu dan jika kamu menanyakan di waktu Al Quran itu diturunkan, niscaya akan diterangkan kepadamu, Allah memaafkan (kamu) tentang hal-hal itu. Allah Maha Pengampun lagi Maha Penyantun.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 102), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya telah ada segolongsn manusia sebelum kamu menanyakan hal-hal yang serupa itu (kepada Nabi mereka), kemudian mereka tidak percaya kepadanya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 103), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Allah sekali-kali tidak pernah mensyari''atkan adanya bahiirah, saaibah, washiilah dan haam. Akan tetapi orang-orang kafir membuat-buat kedustaan terhadap Allah, dan kebanyakan mereka tidak mengerti.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 104), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Apabila dikatakan kepada mereka: "Marilah mengikuti apa yang diturunkan Allah dan mengikuti Rasul". Mereka menjawab: "Cukuplah untuk kami apa yang kami dapati bapak-bapak kami mengerjakannya". Dan apakah mereka itu akan mengikuti nenek moyang mereka walaupun nenek moyang mereka itu tidak mengetahui apa-apa dan tidak (pula) mendapat petunjuk?.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 105), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai orang-orang yang beriman, jagalah dirimu; tiadalah orang yang sesat itu akan memberi mudharat kepadamu apabila kamu telah mendapat petunjuk. Hanya kepada Allah kamu kembali semuanya, maka Dia akan menerangkan kepadamu apa yang telah kamu kerjakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 106), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai orang-orang yang beriman, apabila salah seorang kamu menghadapi kematian, sedang dia akan berwasiat, maka hendaklah (wasiat itu) disaksikan oleh dua orang yang adil di antara kamu, atau dua orang yang berlainan agama dengan kamu, jika kamu dalam perjalanan dimuka bumi lalu kamu ditimpa bahaya kematian. Kamu tahan kedua saksi itu sesudah sembahyang (untuk bersumpah), lalu mereka keduanya bersumpah dengan nama Allah, jika kamu ragu-ragu: "(Demi Allah) kami tidak akan membeli dengan sumpah ini harga yang sedikit (untuk kepentingan seseorang), walaupun dia karib kerabat, dan tidak (pula) kami menyembunyikan persaksian Allah; sesungguhnya kami kalau demikian tentulah termasuk orang-orang yang berdosa".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 107), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Jika diketahui bahwa kedua (saksi itu) membuat dosa, maka dua orang yang lain di antara ahli waris yang berhak yang lebih dekat kepada orang yang meninggal (memajukan tuntutan) untuk menggantikannya, lalu keduanya bersumpah dengan nama Allah: "Sesungguhnya persaksian kami labih layak diterima daripada persaksian kedua saksi itu, dan kami tidak melanggar batas, sesungguhnya kami kalau demikian tentulah termasuk orang yang menganiaya diri sendiri".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 108), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Itu lebih dekat untuk (menjadikan para saksi) mengemukakan persaksiannya menurut apa yang sebenarnya, dan (lebih dekat untuk menjadikan mereka) merasa takut akan dikembalikan sumpahnya (kepada ahli waris) sesudah mereka bersumpah. Dan bertakwalah kepada Allah dan dengarkanlah (perintah-Nya). Allah tidak memberi petunjuk kepada orang-orang yang fasik.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 109), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Ingatlah), hari di waktu Allah mengumpulkan para rasul lalu Allah bertanya (kepada mereka): "Apa jawaban kaummu terhadap (seruan)mu?". Para rasul menjawab: "Tidak ada pengetahuan kami (tentang itu); sesungguhnya Engkau-lah yang mengetahui perkara yang ghaib".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 110), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Ingatlah), ketika Allah mengatakan: "Hai Isa putra Maryam, ingatlah nikmat-Ku kepadamu dan kepada ibumu di waktu Aku menguatkan kamu dengan ruhul qudus. Kamu dapat berbicara dengan manusia di waktu masih dalam buaian dan sesudah dewasa; dan (ingatlah) di waktu Aku mengajar kamu menulis, hikmah, Taurat dan Injil, dan (ingatlah pula) diwaktu kamu membentuk dari tanah (suatu bentuk) yang berupa burung dengan ijin-Ku, kemudian kamu meniup kepadanya, lalu bentuk itu menjadi burung (yang sebenarnya) dengan seizin-Ku. Dan (ingatlah) di waktu kamu menyembuhkan orang yang buta sejak dalam kandungan ibu dan orang yang berpenyakit sopak dengan seizin-Ku, dan (ingatlah) di waktu kamu mengeluarkan orang mati dari kubur (menjadi hidup) dengan seizin-Ku, dan (ingatlah) di waktu Aku menghalangi Bani Israil (dari keinginan mereka membunuh kamu) di kala kamu mengemukakan kepada mereka keterangan-keterangan yang nyata, lalu orang-orang kafir diantara mereka berkata: "Ini tidak lain melainkan sihir yang nyata".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 111), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (ingatlah), ketika Aku ilhamkan kepada pengikut Isa yang setia: "Berimanlah kamu kepada-Ku dan kepada rasul-Ku". Mereka menjawab: Kami telah beriman dan saksikanlah (wahai rasul) bahwa sesungguhnya kami adalah orang-orang yang patuh (kepada seruanmu)".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 112), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Ingatlah), ketika pengikut-pengikut Isa berkata: "Hai Isa putera Maryam, sanggupkah Tuhanmu menurunkan hidangan dari langit kepada kami?". Isa menjawab: "Bertakwalah kepada Allah jika kamu betul-betul orang yang beriman".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 113), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka berkata: "Kami ingin memakan hidangan itu dan supaya tenteram hati kami dan supaya kami yakin bahwa kamu telah berkata benar kepada kami, dan kami menjadi orang-orang yang menyaksikan hidangan itu".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 114), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Isa putera Maryam berdoa: "Ya Tuhan kami turunkanlah kiranya kepada kami suatu hidangan dari langit (yang hari turunnya) akan menjadi hari raya bagi kami yaitu orang-orang yang bersama kami dan yang datang sesudah kami, dan menjadi tanda bagi kekuasaan Engkau; beri rzekilah kami, dan Engkaulah pemberi rezeki Yang Paling Utama".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 115), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Allah berfirman: "Sesungguhnya Aku akan menurunkan hidangan itu kepadamu, barangsiapa yang kafir di antaramu sesudah (turun hidangan itu), maka sesungguhnya Aku akan menyiksanya dengan siksaan yang tidak pernah Aku timpakan kepada seorangpun di antara umat manusia".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 116), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (ingatlah) ketika Allah berfirman: "Hai Isa putera Maryam, adakah kamu mengatakan kepada manusia: "Jadikanlah aku dan ibuku dua orang tuhan selain Allah?". Isa menjawab: "Maha Suci Engkau, tidaklah patut bagiku mengatakan apa yang bukan hakku (mengatakannya). Jika aku pernah mengatakan maka tentulah Engkau mengetahui apa yang ada pada diriku dan aku tidak mengetahui apa yang ada pada diri Engkau. Sesungguhnya Engkau Maha Mengetahui perkara yang ghaib-ghaib".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 117), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Aku tidak pernah mengatakan kepada mereka kecuali apa yang Engkau perintahkan kepadaku (mengatakan)nya yaitu: "Sembahlah Allah, Tuhanku dan Tuhanmu", dan adalah aku menjadi saksi terhadap mereka, selama aku berada di antara mereka. Maka setelah Engkau wafatkan aku, Engkau-lah yang mengawasi mereka. Dan Engkau adalah Maha Menyaksikan atas segala sesuatu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 118), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Jika Engkau menyiksa mereka, maka sesungguhnya mereka adalah hamba-hamba Engkau, dan jika Engkau mengampuni mereka, maka sesungguhnya Engkaulah Yang Maha Perkasa lagi Maha Bijaksana.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 119), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Allah berfirman: "Ini adalah suatu hari yang bermanfaat bagi orang-orang yang benar kebenaran mereka. Bagi mereka surga yang dibawahnya mengalir sungai-sungai; mereka kekal di dalamnya selama-lamanya; Allah ridha terhadap-Nya. Itulah keberuntungan yang paling besar".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 5 AND a.ayah_number = 120), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kepunyaan Allah-lah kerajaan langit dan bumi dan apa yang ada di dalamnya; dan Dia Maha Kuasa atas segala sesuatu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Segala puji bagi Allah Yang telah menciptakan langit dan bumi dan mengadakan gelap dan terang, namun orang-orang yang kafir mempersekutukan (sesuatu) dengan Tuhan mereka.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dialah Yang menciptakan kamu dari tanah, sesudah itu ditentukannya ajal (kematianmu), dan ada lagi suatu ajal yang ada pada sisi-Nya (yang Dia sendirilah mengetahuinya), kemudian kamu masih ragu-ragu (tentang berbangkit itu).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Dialah Allah (yang disembah), baik di langit maupun di bumi; Dia mengetahui apa yang kamu rahasiakan dan apa yang kamu lahirkan dan mengetahui (pula) apa yang kamu usahakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan tidak ada suatu ayatpun dari ayat-ayat Tuhan sampai kepada mereka, melainkan mereka selalu berpaling dari padanya (mendustakannya).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya mereka telah mendustakan yang haq (Al-Quran) tatkala sampai kepada mereka, maka kelak akan sampai kepada mereka (kenyataan dari) berita-berita yang selalu mereka perolok-olokkan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Apakah mereka tidak memperhatikan berapa banyak generasi yang telah Kami binasakan sebelum mereka, padahal (generasi itu) telah Kami teguhkan kedudukan mereka di muka bumi, yaitu keteguhan yang belum pernah Kami berikan kepadamu, dan Kami curahkan hujan yang lebat atas mereka dan Kami jadikan sungai-sungai mengalir di bawah mereka, kemudian Kami binasakan mereka karena dosa mereka sendiri, dan Kami ciptakan sesudah mereka generasi yang lain.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan kalau Kami turunkan kepadamu tulisan di atas kertas, lalu mereka dapat menyentuhnya dengan tangan mereka sendiri, tentulah orang-orang kafir itu berkata: "Ini tidak lain hanyalah sihir yang nyata".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan mereka berkata: "Mengapa tidak diturunkan kepadanya (Muhammad) malaikat?" dan kalau Kami turunkan (kepadanya) malaikat, tentulah selesai urusan itu, kemudian mereka tidak diberi tangguh (sedikitpun).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan kalau Kami jadikan rasul itu malaikat, tentulah Kami jadikan dia seorang laki-laki dan (kalau Kami jadikan ia seorang laki-laki), tentulah Kami meragu-ragukan atas mereka apa yang mereka ragu-ragukan atas diri mereka sendiri.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sungguh telah diperolok-olokkan beberapa rasul sebelum kamu, maka turunlah kepada orang-orang yang mencemoohkan di antara mereka balasan (azab) olok-olokan mereka.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Berjalanlah di muka bumi, kemudian perhatikanlah bagaimana kesudahan orang-orang yang mendustakan itu".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Kepunyaan siapakah apa yang ada di langit dan di bumi". Katakanlah: "Kepunyaan Allah". Dia telah menetapkan atas Diri-Nya kasih sayang. Dia sungguh akan menghimpun kamu pada hari kiamat yang tidak ada keraguan padanya. Orang-orang yang meragukan dirinya mereka itu tidak beriman.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan kepunyaan Allah-lah segala yang ada pada malam dan siang. Dan Dialah Yang Maha Mendengar lagi Maha Mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Apakah akan aku jadikan pelindung selain dari Allah yang menjadikan langit dan bumi, padahal Dia memberi makan dan tidak memberi makan?" Katakanlah: "Sesungguhnya aku diperintah supaya aku menjadi orang yang pertama kali menyerah diri (kepada Allah), dan jangan sekali-kali kamu masuk golongan orang musyrik".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Sesungguhnya aku takut akan azab hari yang besar (hari kiamat), jika aku mendurhakai Tuhanku".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Barang siapa yang dijauhkan azab dari padanya pada hari itu, maka sungguh Allah telah memberikan rahmat kepadanya. Dan itulah keberuntungan yang nyata.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan jika Allah menimpakan sesuatu kemudharatan kepadamu, maka tidak ada yang menghilangkannya melainkan Dia sendiri. Dan jika Dia mendatangkan kebaikan kepadamu, maka Dia Maha Kuasa atas tiap-tiap sesuatu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Dialah yang berkuasa atas sekalian hamba-hamba-Nya. Dan Dialah Yang Maha Bijaksana lagi Maha Mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Siapakah yang lebih kuat persaksiannya?" Katakanlah: "Allah". Dia menjadi saksi antara aku dan kamu. Dan Al Quran ini diwahyukan kepadaku supaya dengan dia aku memberi peringatan kepadamu dan kepada orang-orang yang sampai Al-Quran (kepadanya). Apakah sesungguhnya kamu mengakui bahwa ada tuhan-tuhan lain di samping Allah?" Katakanlah: "Aku tidak mengakui". Katakanlah: "Sesungguhnya Dia adalah Tuhan Yang Maha Esa dan sesungguhnya aku berlepas diri dari apa yang kamu persekutukan (dengan Allah)".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Orang-orang yang telah Kami berikan kitab kepadanya, mereka mengenalnya (Muhammad) seperti mereka mengenal anak-anaknya sendiri. Orang-orang yang merugikan dirinya, mereka itu tidak beriman (kepada Allah).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan siapakah yang lebih aniaya daripada orang yang membuat-buat suatu kedustaan terhadap Allah, atau mendustakan ayat-ayat-Nya? Sesungguhnya orang-orang yang aniaya itu tidak mendapat keberuntungan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (ingatlah), hari yang di waktu itu Kami menghimpun mereka semuanya kemudian Kami berkata kepada orang-orang musyrik: "Di manakah sembahan-sembahan kamu yang dulu kamu katakan (sekutu-sekutu) Kami?".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kemudian tiadalah fitnah mereka, kecuali mengatakan: "Demi Allah, Tuhan kami, tiadalah kami mempersekutukan Allah".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Lihatlah bagaimana mereka telah berdusta kepada diri mereka sendiri dan hilanglah daripada mereka sembahan-sembahan yang dahulu mereka ada-adakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan di antara mereka ada orang yang mendengarkani (bacaan)mu, padahal Kami telah meletakkan tutupan di atas hati mereka (sehingga mereka tidak) memahaminya dan (Kami letakkan) sumbatan di telinganya. Dan jikapun mereka melihat segala tanda (kebenaran), mereka tetap tidak mau beriman kepadanya. Sehingga apabila mereka datang kepadamu untuk membantahmu, orang-orang kafir itu berkata: "Al-Quran ini tidak lain hanyalah dongengan orang-orang dahulu".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan mereka melarang (orang lain) mendengarkan Al-Quran dan mereka sendiri menjauhkan diri daripadanya, dan mereka hanyalah membinasakan diri mereka sendiri, sedang mereka tidak menyadari.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan jika kamu (Muhammad) melihat ketika mereka dihadapkan ke neraka, lalu mereka berkata: "Kiranya kami dikembalikan (ke dunia) dan tidak mendustakan ayat-ayat Tuhan kami, serta menjadi orang-orang yang beriman", (tentulah kamu melihat suatu peristiwa yang mengharukan).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tetapi (sebenarnya) telah nyata bagi mereka kejahatan yang mereka dahulu selalu menyembunyikannya. Sekiranya mereka dikembalikan ke dunia, tentulah mereka kembali kepada apa yang mereka telah dilarang mengerjakannya. Dan sesungguhnya mereka itu adalah pendusta belaka.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan tentu mereka akan mengatakan (pula): "Hidup hanyalah kehidupan kita di dunia ini saja, dan kita sekali-sekali tidak akan dibangkitkan".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan seandainya kamu melihat ketika mereka dihadapkan kepada Tuhannya (tentulah kamu melihat peristiwa yang mengharukan). Berfirman Allah: "Bukankah (kebangkitan ini benar?" Mereka menjawab: "Sungguh benar, demi Tuhan kami". Berfirman Allah: "Karena itu rasakanlah azab ini, disebabkan kamu mengingkari(nya)".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sungguh telah rugilah orang-orang yang mendustakan pertemuan mereka dengan Tuhan; sehingga apabila kiamat datang kepada mereka dengan tiba-tiba, mereka berkata: "Alangkah besarnya penyesalan kami, terhadap kelalaian kami tentang kiamat itu!", sambil mereka memikul dosa-dosa di atas punggungnya. Ingatlah, amat buruklah apa yang mereka pikul itu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan tiadalah kehidupan dunia ini, selain dari main-main dan senda gurau belaka. Dan sungguh kampung akhirat itu lebih baik bagi orang-orang yang bertakwa. Maka tidakkah kamu memahaminya?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya Kami mengetahui bahwasanya apa yang mereka katakan itu menyedihkan hatimu, (janganlah kamu bersedih hati), karena mereka sebenarnya bukan mendustakan kamu, akan tetapi orang-orang yang zalim itu mengingkari ayat-ayat Allah.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya telah didustakan (pula) rasul-rasul sebelum kamu, akan tetapi mereka sabar terhadap pendustaan dan penganiayaan (yang dilakukan) terhadap mereka, sampai datang pertolongan Allah kepada mereka. Tak ada seorangpun yang dapat merubah kalimat-kalimat (janji-janji) Allah. Dan sesungguhnya telah datang kepadamu sebahagian dari berita rasul-rasul itu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan jika perpalingan mereka (darimu) terasa amat berat bagimu, maka jika kamu dapat membuat lobang di bumi atau tangga ke langit lalu kamu dapat mendatangkan mukjizat kepada mereka (maka buatlah). Kalau Allah menghendaki, tentu saja Allah menjadikan mereka semua dalam petunjuk sebab itu janganlah sekali-kali kamu termasuk orang-orang yang jahil', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hanya mereka yang mendengar sajalah yang mematuhi (seruan Allah), dan orang-orang yang mati (hatinya), akan dibangkitkan oleh Allah, kemudian kepada-Nya-lah mereka dikembalikan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan mereka (orang-orang musyrik Mekah) berkata: "Mengapa tidak diturunkan kepadanya (Muhammad) suatu mukjizat dari Tuhannya?" Katakanlah: "Sesungguhnya Allah kuasa menurunkan suatu mukjizat, tetapi kebanyakan mereka tidak mengetahui".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan tiadalah binatang-binatang yang ada di bumi dan burung-burung yang terbang dengan kedua sayapnya, melainkan umat (juga) seperti kamu. Tiadalah Kami alpakan sesuatupun dalam Al-Kitab, kemudian kepada Tuhanlah mereka dihimpunkan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan orang-orang yang mendustakan ayat-ayat Kami adalah pekak, bisu dan berada dalam gelap gulita. Barangsiapa yang dikehendaki Allah (kesesatannya), niscaya disesatkan-Nya. Dan barangsiapa yang dikehendaki Allah (untuk diberi-Nya petunjuk), niscaya Dia menjadikan-Nya berada di atas jalan yang lurus.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Terangkanlah kepadaku jika datang siksaan Allah kepadamu, atau datang kepadamu hari kiamat, apakah kamu menyeru (tuhan) selain Allah; jika kamu orang-orang yang benar!"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Tidak), tetapi hanya Dialah yang kamu seru, maka Dia menghilangkan bahaya yang karenanya kamu berdoa kepada-Nya, jika Dia menghendaki, dan kamu tinggalkan sembahan-sembahan yang kamu sekutukan (dengan Allah).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya Kami telah mengutus (rasul-rasul) kepada umat-umat yang sebelum kamu, kemudian Kami siksa mereka dengan (menimpakan) kesengsaraan dan kemelaratan, supaya mereka memohon (kepada Allah) dengan tunduk merendahkan diri.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka mengapa mereka tidak memohon (kepada Allah) dengan tunduk merendahkan diri ketika datang siksaan Kami kepada mereka, bahkan hati mereka telah menjadi keras, dan syaitanpun menampakkan kepada mereka kebagusan apa yang selalu mereka kerjakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 44), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka tatkala mereka melupakan peringatan yang telah diberikan kepada mereka, Kamipun membukakan semua pintu-pintu kesenangan untuk mereka; sehingga apabila mereka bergembira dengan apa yang telah diberikan kepada mereka, Kami siksa mereka dengan sekonyong-konyong, maka ketika itu mereka terdiam berputus asa.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 45), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka orang-orang yang zalim itu dimusnahkan sampai ke akar-akarnya. Segala puji bagi Allah, Tuhan semesta alam.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 46), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Terangkanlah kepadaku jika Allah mencabut pendengaran dan penglihatan serta menutup hatimu, siapakah tuhan selain Allah yang kuasa mengembalikannya kepadamu?" Perhatikanlah bagaimana Kami berkali-kali memperlihatkan tanda-tanda kebesaran (Kami), kemudian mereka tetap berpaling (juga).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 47), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Terangkanlah kepadaku jika datang siksaan Allah kepadamu dengan sekonyong-konyong, atau terang-terangan, maka adakah yang dibinasakan (Allah) selain dari orang yang zalim?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 48), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan tidaklah Kami mengutus para rasul itu melainkan untuk memberikan kabar gembira dan memberi peringatan. Barangsiapa yang beriman dan mengadakan perbaikan, maka tak ada kekhawatiran terhadap mereka dan tidak pula mereka bersedih hati.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 49), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan orang-orang yang mendustakan ayat-ayat Kami, mereka akan ditimpa siksa disebabkan mereka selalu berbuat fasik.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 50), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: Aku tidak mengatakan kepadamu, bahwa perbendaharaan Allah ada padaku, dan tidak (pula) aku mengetahui yang ghaib dan tidak (pula) aku mengatakan kepadamu bahwa aku seorang malaikat. Aku tidak mengikuti kecuali apa yang diwahyukan kepadaku. Katakanlah: "Apakah sama orang yang buta dengan yang melihat?" Maka apakah kamu tidak memikirkan(nya)?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 51), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan berilah peringatan dengan apa yang diwahyukan itu kepada orang-orang yang takut akan dihimpunkan kepada Tuhannya (pada hari kiamat), sedang bagi mereka tidak ada seorang pelindung dan pemberi syafa''atpun selain daripada Allah, agar mereka bertakwa.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 52), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan janganlah kamu mengusir orang-orang yang menyeru Tuhannya di pagi dan petang hari, sedang mereka menghendaki keridhaan-Nya. Kamu tidak memikul tanggung jawab sedikitpun terhadap perbuatan mereka dan merekapun tidak memikul tanggung jawab sedikitpun terhadap perbuatanmu, yang menyebabkan kamu (berhak) mengusir mereka, (sehingga kamu termasuk orang-orang yang zalim).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 53), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan demikianlah telah Kami uji sebahagian mereka (orang-orang kaya) dengan sebahagian mereka (orang-orang miskin), supaya (orang-orang yang kaya itu) berkata: "Orang-orang semacam inikah di antara kita yang diberi anugerah Allah kepada mereka?" (Allah berfirman): "Tidakkah Allah lebih mengetahui tentang orang-orang yang bersyukur (kepada-Nya)?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 54), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Apabila orang-orang yang beriman kepada ayat-ayat Kami itu datang kepadamu, maka katakanlah: "Salaamun alaikum. Tuhanmu telah menetapkan atas diri-Nya kasih sayang, (yaitu) bahwasanya barang siapa yang berbuat kejahatan di antara kamu lantaran kejahilan, kemudian ia bertaubat setelah mengerjakannya dan mengadakan perbaikan, maka sesungguhnya Allah Maha Pengampun lagi Maha Penyayang.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 55), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan demikianlah Kami terangkan ayat-ayat Al-Quran (supaya jelas jalan orang-orang yang saleh, dan supaya jelas (pula) jalan orang-orang yang berdosa.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 56), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Sesungguhnya aku dilarang menyembah tuhan-tuhan yang kamu sembah selain Allah". Katakanlah: "Aku tidak akan mengikuti hawa nafsumu, sungguh tersesatlah aku jika berbuat demikian dan tidaklah (pula) aku termasuk orang-orang yang mendapat petunjuk".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 57), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Sesungguhnya aku berada di atas hujjah yang nyata (Al Quran) dari Tuhanku, sedang kamu mendustakannya. Tidak ada padaku apa (azab) yang kamu minta supaya disegerakan kedatangannya. Menetapkan hukum itu hanyalah hak Allah. Dia menerangkan yang sebenarnya dan Dia Pemberi keputusan yang paling baik".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 58), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Kalau sekiranya ada padaku apa (azab) yang kamu minta supaya disegerakan, tentu telah diselesaikan Allah urusan yang ada antara aku dan kamu. Dan Allah lebih mengetahui tentang orang-orang yang zalim.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 59), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan pada sisi Allah-lah kunci-kunci semua yang ghaib; tidak ada yang mengetahuinya kecuali Dia sendiri, dan Dia mengetahui apa yang di daratan dan di lautan, dan tiada sehelai daun pun yang gugur melainkan Dia mengetahuinya (pula), dan tidak jatuh sebutir biji-pun dalam kegelapan bumi, dan tidak sesuatu yang basah atau yang kering, melainkan tertulis dalam kitab yang nyata (Lauh Mahfudz)"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 60), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Dialah yang menidurkan kamu di malam hari dan Dia mengetahui apa yang kamu kerjakan di siang hari, kemudian Dia membangunkan kamu pada siang hari untuk disempurnakan umur(mu) yang telah ditentukan, kemudian kepada Allah-lah kamu kembali, lalu Dia memberitahukan kepadamu apa yang dahulu kamu kerjakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 61), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Dialah yang mempunyai kekuasaan tertinggi di atas semua hamba-Nya, dan diutus-Nya kepadamu malaikat-malaikat penjaga, sehingga apabila datang kematian kepada salah seorang di antara kamu, ia diwafatkan oleh malaikat-malaikat Kami, dan malaikat-malaikat Kami itu tidak melalaikan kewajibannya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 62), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kemudian mereka (hamba Allah) dikembalikan kepada Allah, Penguasa mereka yang sebenarnya. Ketahuilah bahwa segala hukum (pada hari itu) kepunyaan-Nya. Dan Dialah Pembuat Perhitungan yang paling cepat.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 63), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Siapakah yang dapat menyelamatkan kamu dari bencana di darat dan di laut, yang kamu berdoa kepada-Nya dengan rendah diri dengan suara yang lembut (dengan mengatakan: "Sesungguhnya jika Dia menyelamatkan kami dari (bencana) ini, tentulah kami menjadi orang-orang yang bersyukur"".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 64), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Allah menyelamatkan kamu dari bencana itu dan dari segala macam kesusahan, kemudian kamu kembali mempersekutukan-Nya".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 65), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Dialah yang berkuasa untuk mengirimkan azab kepadamu, dari atas kamu atau dari bawah kakimu atau Dia mencampurkan kamu dalam golongan-golongan (yang saling bertentangan) dan merasakan kepada sebahagian kamu keganasan sebahagian yang lain. Perhatikanlah, betapa Kami mendatangkan tanda-tanda kebesaran Kami silih berganti agar mereka memahami(nya)".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 66), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan kaummu mendustakannya (azab) padahal azab itu benar adanya. Katakanlah: "Aku ini bukanlah orang yang diserahi mengurus urusanmu".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 67), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Untuk setiap berita (yang dibawa oleh rasul-rasul) ada (waktu) terjadinya dan kelak kamu akan mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 68), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan apabila kamu melihat orang-orang memperolok-olokkan ayat-ayat Kami, maka tinggalkanlah mereka sehingga mereka membicarakan pembicaraan yang lain. Dan jika syaitan menjadikan kamu lupa (akan larangan ini), maka janganlah kamu duduk bersama orang-orang yang zalim itu sesudah teringat (akan larangan itu).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 69), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan tidak ada pertanggungjawaban sedikitpun atas orang-orang yang bertakwa terhadap dosa mereka; akan tetapi (kewajiban mereka ialah) mengingatkan agar mereka bertakwa.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 70), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan tinggalkan lah orang-orang yang menjadikan agama mereka sebagai main-main dan senda gurau, dan mereka telah ditipu oleh kehidupan dunia. Peringatkanlah (mereka) dengan Al-Quran itu agar masing-masing diri tidak dijerumuskan ke dalam neraka, karena perbuatannya sendiri. Tidak akan ada baginya pelindung dan tidak pula pemberi syafa''at selain daripada Allah. Dan jika ia menebus dengan segala macam tebusanpun, niscaya tidak akan diterima itu daripadanya. Mereka itulah orang-orang yang dijerumuskan ke dalam neraka. Bagi mereka (disediakan) minuman dari air yang sedang mendidih dan azab yang pedih disebabkan kekafiran mereka dahulu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 71), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Apakah kita akan menyeru selain daripada Allah, sesuatu yang tidak dapat mendatangkan kemanfaatan kepada kita dan tidak (pula) mendatangkan kemudharatan kepada kita dan (apakah) kita akan kembali ke belakang, sesudah Allah memberi petunjuk kepada kita, seperti orang yang telah disesatkan oleh syaitan di pesawangan yang menakutkan; dalam keadaan bingung, dia mempunyai kawan-kawan yang memanggilnya kepada jalan yang lurus (dengan mengatakan): "Marilah ikuti kami". Katakanlah: "Sesungguhnya petunjuk Allah itulah (yang sebenarnya) petunjuk; dan kita disuruh agar menyerahkan diri kepada Tuhan semesta alam,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 72), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan agar mendirikan sembahyang serta bertakwa kepada-Nya". Dan Dialah Tuhan yang kepada-Nya-lah kamu akan dihimpunkan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 73), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Dialah yang menciptakan langit dan bumi dengan benar. Dan benarlah perkataan-Nya di waktu Dia mengatakan: "Jadilah, lalu terjadilah", dan di tangan-Nya-lah segala kekuasaan di waktu sangkakala ditiup. Dia mengetahui yang ghaib dan yang nampak. Dan Dialah Yang Maha Bijaksana lagi Maha Mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 74), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (ingatlah) di waktu Ibrahim berkata kepada bapaknya, Aazar, "Pantaskah kamu menjadikan berhala-berhala sebagai tuhan-tuhan? Sesungguhnya aku melihat kamu dan kaummu dalam kesesatan yang nyata".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 75), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan demikianlah Kami perlihatkan kepada Ibrahim tanda-tanda keagungan (Kami yang terdapat) di langit dan bumi dan (Kami memperlihatkannya) agar dia termasuk orang yang yakin.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 76), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Ketika malam telah gelap, dia melihat sebuah bintang (lalu) dia berkata: "Inilah Tuhanku", tetapi tatkala bintang itu tenggelam dia berkata: "Saya tidak suka kepada yang tenggelam".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 77), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kemudian tatkala dia melihat bulan terbit dia berkata: "Inilah Tuhanku". Tetapi setelah bulan itu terbenam, dia berkata: "Sesungguhnya jika Tuhanku tidak memberi petunjuk kepadaku, pastilah aku termasuk orang yang sesat".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 78), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kemudian tatkala ia melihat matahari terbit, dia berkata: "Inilah Tuhanku, ini yang lebih besar". Maka tatkala matahari itu terbenam, dia berkata: "Hai kaumku, sesungguhnya aku berlepas diri dari apa yang kamu persekutukan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 79), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya aku menghadapkan diriku kepada Rabb yang menciptakan langit dan bumi, dengan cenderung kepada agama yang benar, dan aku bukanlah termasuk orang-orang yang mempersekutukan Tuhan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 80), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan dia dibantah oleh kaumnya. Dia berkata: "Apakah kamu hendak membantah tentang Allah, padahal sesungguhnya Allah telah memberi petunjuk kepadaku". Dan aku tidak takut kepada (malapetaka dari) sembahan-sembahan yang kamu persekutukan dengan Allah, kecuali di kala Tuhanku menghendaki sesuatu (dari malapetaka) itu. Pengetahuan Tuhanku meliputi segala sesuatu. Maka apakah kamu tidak dapat mengambil pelajaran (daripadanya)?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 81), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Bagaimana aku takut kepada sembahan-sembahan yang kamu persekutukan (dengan Allah), padahal kamu tidak mempersekutukan Allah dengan sembahan-sembahan yang Allah sendiri tidak menurunkan hujjah kepadamu untuk mempersekutukan-Nya. Maka manakah di antara dua golongan itu yang lebih berhak memperoleh keamanan (dari malapetaka), jika kamu mengetahui?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 82), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Orang-orang yang beriman dan tidak mencampuradukkan iman mereka dengan kezaliman (syirik), mereka itulah yang mendapat keamanan dan mereka itu adalah orang-orang yang mendapat petunjuk.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 83), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan itulah hujjah Kami yang Kami berikan kepada Ibrahim untuk menghadapi kaumnya. Kami tinggikan siapa yang Kami kehendaki beberapa derajat. Sesungguhnya Tuhanmu Maha Bijaksana lagi Maha Mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 84), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Kami telah menganugerahkan Ishak dan Ya''qub kepadanya. Kepada keduanya masing-masing telah Kami beri petunjuk; dan kepada Nuh sebelum itu (juga) telah Kami beri petunjuk, dan kepada sebahagian dari keturunannya (Nuh) yaitu Daud, Sulaiman, Ayyub, Yusuf, Musa dan Harun. Demikianlah Kami memberi balasan kepada orang-orang yang berbuat baik.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 85), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan Zakaria, Yahya, Isa dan Ilyas. Semuanya termasuk orang-orang yang shaleh.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 86), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan Ismail, Alyasa'', Yunus dan Luth. Masing-masing Kami lebihkan derajatnya di atas umat (di masanya),', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 87), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Kami lebihkan (pula) derajat sebahagian dari bapak-bapak mereka, keturunan dan saudara-saudara mereka. Dan Kami telah memilih mereka (untuk menjadi nabi-nabi dan rasul-rasul) dan Kami menunjuki mereka ke jalan yang lurus.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 88), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Itulah petunjuk Allah, yang dengannya Dia memberi petunjuk kepada siapa yang dikehendaki-Nya di antara hamba-hamba-Nya. Seandainya mereka mempersekutukan Allah, niscaya lenyaplah dari mereka amalan yang telah mereka kerjakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 89), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka itulah orang-orang yang telah Kami berikan kitab, hikmat dan kenabian Jika orang-orang (Quraisy) itu mengingkarinya, maka sesungguhnya Kami akan menyerahkannya kepada kaum yang sekali-kali tidak akan mengingkarinya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 90), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka itulah orang-orang yang telah diberi petunjuk oleh Allah, maka ikutilah petunjuk mereka. Katakanlah: "Aku tidak meminta upah kepadamu dalam menyampaikan (Al-Quran)". Al-Quran itu tidak lain hanyalah peringatan untuk seluruh ummat.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 91), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan mereka tidak menghormati Allah dengan penghormatan yang semestinya, di kala mereka berkata: "Allah tidak menurunkan sesuatupun kepada manusia". Katakanlah: "Siapakah yang menurunkan kitab (Taurat) yang dibawa oleh Musa sebagai cahaya dan petunjuk bagi manusia, kamu jadikan kitab itu lembaran-lembaran kertas yang bercerai-berai, kamu perlihatkan (sebahagiannya) dan kamu sembunyikan sebahagian besarnya, padahal telah diajarkan kepadamu apa yang kamu dan bapak-bapak kamu tidak mengetahui(nya)?" Katakanlah: "Allah-lah (yang menurunkannya)", kemudian (sesudah kamu menyampaikan Al Quran kepada mereka), biarkanlah mereka bermain-main dalam kesesatannya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 92), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan ini (Al Quran) adalah kitab yang telah Kami turunkan yang diberkahi; membenarkan kitab-kitab yang (diturunkan) sebelumnya dan agar kamu memberi peringatan kepada (penduduk) Ummul Qura (Mekah) dan orang-orang yang di luar lingkungannya. Orang-orang yang beriman kepada adanya kehidupan akhirat tentu beriman kepadanya (Al Quran) dan mereka selalu memelihara sembahyangnya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 93), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan siapakah yang lebih zalim daripada orang yang membuat kedustaan terhadap Allah atau yang berkata: "Telah diwahyukan kepada saya", padahal tidak ada diwahyukan sesuatupun kepadanya, dan orang yang berkata: "Saya akan menurunkan seperti apa yang diturunkan Allah". Alangkah dahsyatnya sekiranya kamu melihat di waktu orang-orang yang zalim berada dalam tekanan sakratul maut, sedang para malaikat memukul dengan tangannya, (sambil berkata): "Keluarkanlah nyawamu" Di hari ini kamu dibalas dengan siksa yang sangat menghinakan, karena kamu selalu mengatakan terhadap Allah (perkataan) yang tidak benar dan (karena) kamu selalu menyombongkan diri terhadap ayat-ayat-Nya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 94), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya kamu datang kepada Kami sendiri-sendiri sebagaimana kamu Kami ciptakan pada mulanya, dan kamu tinggalkan di belakangmu (di dunia) apa yang telah Kami karuniakan kepadamu; dan Kami tiada melihat besertamu pemberi syafa''at yang kamu anggap bahwa mereka itu sekutu-sekutu Tuhan di antara kamu. Sungguh telah terputuslah (pertalian) antara kamu dan telah lenyap daripada kamu apa yang dahulu kamu anggap (sebagai sekutu Allah).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 95), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya Allah menumbuhkan butir tumbuh-tumbuhan dan biji buah-buahan. Dia mengeluarkan yang hidup dari yang mati dan mengeluarkan yang mati dari yang hidup. (Yang memiliki sifat-sifat) demikian ialah Allah, maka mengapa kamu masih berpaling?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 96), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dia menyingsingkan pagi dan menjadikan malam untuk beristirahat, dan (menjadikan) matahari dan bulan untuk perhitungan. Itulah ketentuan Allah Yang Maha Perkasa lagi Maha Mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 97), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Dialah yang menjadikan bintang-bintang bagimu, agar kamu menjadikannya petunjuk dalam kegelapan di darat dan di laut. Sesungguhnya Kami telah menjelaskan tanda-tanda kebesaran (Kami) kepada orang-orang yang mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 98), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Dialah yang menciptakan kamu dari seorang diri, maka (bagimu) ada tempat tetap dan tempat simpanan. Sesungguhnya telah Kami jelaskan tanda-tanda kebesaran Kami kepada orang-orang yang mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 99), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Dialah yang menurunkan air hujan dari langit, lalu Kami tumbuhkan dengan air itu segala macam tumbuh-tumbuhan maka Kami keluarkan dari tumbuh-tumbuhan itu tanaman yang menghijau. Kami keluarkan dari tanaman yang menghijau itu butir yang banyak; dan dari mayang korma mengurai tangkai-tangkai yang menjulai, dan kebun-kebun anggur, dan (Kami keluarkan pula) zaitun dan delima yang serupa dan yang tidak serupa. Perhatikanlah buahnya di waktu pohonnya berbuah dan (perhatikan pulalah) kematangannya. Sesungguhnya pada yang demikian itu ada tanda-tanda (kekuasaan Allah) bagi orang-orang yang beriman.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 100), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan mereka (orang-orang musyrik) menjadikan jin itu sekutu bagi Allah, padahal Allah-lah yang menciptakan jin-jin itu, dan mereka membohong (dengan mengatakan): "Bahwasanya Allah mempunyai anak laki-laki dan perempuan", tanpa (berdasar) ilmu pengetahuan. Maha Suci Allah dan Maha Tinggi dari sifat-sifat yang mereka berikan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 101), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dia Pencipta langit dan bumi. Bagaimana Dia mempunyai anak padahal Dia tidak mempunyai isteri. Dia menciptakan segala sesuatu; dan Dia mengetahui segala sesuatu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 102), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Yang memiliki sifat-sifat yang) demikian itu ialah Allah Tuhan kamu; tidak ada Tuhan selain Dia; Pencipta segala sesuatu, maka sembahlah Dia; dan Dia adalah Pemelihara segala sesuatu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 103), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dia tidak dapat dicapai oleh penglihatan mata, sedang Dia dapat melihat segala yang kelihatan; dan Dialah Yang Maha Halus lagi Maha Mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 104), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya telah datang dari Tuhanmu bukti-bukti yang terang; maka barangsiapa melihat (kebenaran itu), maka (manfaatnya) bagi dirinya sendiri; dan barangsiapa buta (tidak melihat kebenaran itu), maka kemudharatannya kembali kepadanya. Dan aku (Muhammad) sekali-kali bukanlah pemelihara(mu).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 105), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Demikianlah Kami mengulang-ulangi ayat-ayat Kami supaya (orang-orang yang beriman mendapat petunjuk) dan supaya orang-orang musyrik mengatakan: "Kamu telah mempelajari ayat-ayat itu (dari Ahli Kitab)", dan supaya Kami menjelaskan Al Quran itu kepada orang-orang yang mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 106), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Ikutilah apa yang telah diwahyukan kepadamu dari Tuhanmu; tidak ada Tuhan selain Dia; dan berpalinglah dari orang-orang musyrik.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 107), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan kalau Allah menghendaki, niscaya mereka tidak memperkutukan(Nya). Dan Kami tidak menjadikan kamu pemelihara bagi mereka; dan kamu sekali-kali bukanlah pemelihara bagi mereka.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 108), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan janganlah kamu memaki sembahan-sembahan yang mereka sembah selain Allah, karena mereka nanti akan memaki Allah dengan melampaui batas tanpa pengetahuan. Demikianlah Kami jadikan setiap umat menganggap baik pekerjaan mereka. Kemudian kepada Tuhan merekalah kembali mereka, lalu Dia memberitakan kepada mereka apa yang dahulu mereka kerjakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 109), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka bersumpah dengan nama Allah dengan segala kesungguhan, bahwa sungguh jika datang kepada mereka sesuatu mu jizat, pastilah mereka beriman kepada-Nya. Katakanlah: "Sesungguhnya mukjizat-mukjizat itu hanya berada di sisi Allah". Dan apakah yang memberitahukan kepadamu bahwa apabila mukjizat datang mereka tidak akan beriman.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 110), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (begitu pula) Kami memalingkan hati dan penglihatan mereka seperti mereka belum pernah beriman kepadanya (Al Quran) pada permulaannya, dan Kami biarkan mereka bergelimang dalam kesesatannya yang sangat.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 111), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kalau sekiranya Kami turunkan malaikat kepada mereka, dan orang-orang yang telah mati berbicara dengan mereka dan Kami kumpulkan (pula) segala sesuatu ke hadapan mereka, niscaya mereka tidak (juga) akan beriman, kecuali jika Allah menghendaki, tetapi kebanyakan mereka tidak mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 112), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan demikianlah Kami jadikan bagi tiap-tiap nabi itu musuh, yaitu syaitan-syaitan (dari jenis) manusia dan (dan jenis) jin, sebahagian mereka membisikkan kepada sebahagian yang lain perkataan-perkataan yang indah-indah untuk menipu (manusia). Jikalau Tuhanmu menghendaki, niscaya mereka tidak mengerjakannya, maka tinggalkanlah mereka dan apa yang mereka ada-adakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 113), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (juga) agar hati kecil orang-orang yang tidak beriman kepada kehidupan akhirat cenderung kepada bisikan itu, mereka merasa senang kepadanya dan supaya mereka mengerjakan apa yang mereka (syaitan) kerjakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 114), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka patutkah aku mencari hakim selain daripada Allah, padahal Dialah yang telah menurunkan kitab (Al Quran) kepadamu dengan terperinci? Orang-orang yang telah Kami datangkan kitab kepada mereka, mereka mengetahui bahwa Al Quran itu diturunkan dari Tuhanmu dengan sebenarnya. Maka janganlah kamu sekali-kali termasuk orang yang ragu-ragu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 115), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Telah sempurnalah kalimat Tuhanmu (Al-Quran) sebagai kalimat yang benar dan adil. Tidak ada yang dapat merubah rubah kalimat-kalimat-Nya dan Dialah yang Maha Mendenyar lagi Maha Mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 116), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan jika kamu menuruti kebanyakan orang-orang yang di muka bumi ini, niscaya mereka akan menyesatkanmu dari jalan Allah. Mereka tidak lain hanyalah mengikuti persangkaan belaka, dan mereka tidak lain hanyalah berdusta (terhadap Allah).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 117), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya Tuhanmu, Dialah yang lebih mengetahui tentang orang yang tersesat dari jalan-Nya dan Dia lebih mengetahui tentang orang orang yang mendapat petunjuk.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 118), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka makanlah binatang-binatang (yang halal) yang disebut nama Allah ketika menyembelihnya, jika kamu beriman kepada ayat-ayat-Nya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 119), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mengapa kamu tidak mau memakan (binatang-binatang yang halal) yang disebut nama Allah ketika menyembelihnya, padahal sesungguhnya Allah telah menjelaskan kepada kamu apa yang diharamkan-Nya atasmu, kecuali apa yang terpaksa kamu memakannya. Dan sesungguhnya kebanyakan (dari manusia) benar benar hendak menyesatkan (orang lain) dengan hawa nafsu mereka tanpa pengetahuan. Sesungguhnya Tuhanmu, Dialah yang lebih mengetahui orang-orang yang melampaui batas.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 120), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan tinggalkanlah dosa yang nampak dan yang tersembunyi. Sesungguhnya orang yang mengerjakan dosa, kelak akan diberi pembalasan (pada hari kiamat), disebabkan apa yang mereka telah kerjakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 121), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan janganlah kamu memakan binatang-binatang yang tidak disebut nama Allah ketika menyembelihnya. Sesungguhnya perbuatan yang semacam itu adalah suatu kefasikan. Sesungguhnya syaitan itu membisikkan kepada kawan-kawannya agar mereka membantah kamu; dan jika kamu menuruti mereka, sesungguhnya kamu tentulah menjadi orang-orang yang musyrik.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 122), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan apakah orang yang sudah mati kemudian dia Kami hidupkan dan Kami berikan kepadanya cahaya yang terang, yang dengan cahaya itu dia dapat berjalan di tengah-tengah masyarakat manusia, serupa dengan orang yang keadaannya berada dalam gelap gulita yang sekali-kali tidak dapat keluar dari padanya? Demikianlah Kami jadikan orang yang kafir itu memandang baik apa yang telah mereka kerjakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 123), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan demikianlah Kami adakan pada tiap-tiap negeri penjahat-penjahat yang terbesar agar mereka melakukan tipu daya dalam negeri itu. Dan mereka tidak memperdayakan melainkan dirinya sendiri, sedang mereka tidak menyadarinya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 124), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Apabila datang sesuatu ayat kepada mereka, mereka berkata: "Kami tidak akan beriman sehingga diberikan kepada kami yang serupa dengan apa yang telah diberikan kepada utusan-utusan Allah". Allah lebih mengetahui di mana Dia menempatkan tugas kerasulan. Orang-orang yang berdosa, nanti akan ditimpa kehinaan di sisi Allah dan siksa yang keras disebabkan mereka selalu membuat tipu daya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 125), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Barangsiapa yang Allah menghendaki akan memberikan kepadanya petunjuk, niscaya Dia melapangkan dadanya untuk (memeluk agama) Islam. Dan barangsiapa yang dikehendaki Allah kesesatannya, niscaya Allah menjadikan dadanya sesak lagi sempit, seolah-olah ia sedang mendaki langit. Begitulah Allah menimpakan siksa kepada orang-orang yang tidak beriman.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 126), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan inilah jalan Tuhanmu; (jalan) yang lurus. Sesungguhnya Kami telah menjelaskan ayat-ayat (Kami) kepada orang-orang yang mengambil pelajaran.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 127), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Bagi mereka (disediakan) darussalam (surga) pada sisi Tuhannya dan Dialah Pelindung mereka disebabkan amal-amal saleh yang selalu mereka kerjakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 128), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (ingatlah) hari diwaktu Allah menghimpunkan mereka semuanya (dan Allah berfirman): "Hai golongan jin, sesungguhnya kamu telah banyak menyesatkan manusia", lalu berkatalah kawan-kawan meraka dari golongan manusia: "Ya Tuhan kami, sesungguhnya sebahagian daripada kami telah dapat kesenangan dari sebahagian (yang lain) dan kami telah sampai kepada waktu yang telah Engkau tentukan bagi kami". Allah berfirman: "Neraka itulah tempat diam kamu, sedang kamu kekal di dalamnya, kecuali kalau Allah menghendaki (yang lain)". Sesungguhnya Tuhanmu Maha Bijaksana lagi Maha Mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 129), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan demikianlah Kami jadikan sebahagian orang-orang yang zalim itu menjadi teman bagi sebahagian yang lain disebabkan apa yang mereka usahakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 130), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai golongan jin dan manusia, apakah belum datang kepadamu rasul-rasul dari golongan kamu sendiri, yang menyampaikan kepadamu ayat-ayat-Ku dan memberi peringatan kepadamu terhadap pertemuanmu dengan hari ini? Mereka berkata: "Kami menjadi saksi atas diri kami sendiri", kehidupan dunia telah menipu mereka, dan mereka menjadi saksi atas diri mereka sendiri, bahwa mereka adalah orang-orang yang kafir.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 131), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Yang demikian itu adalah karena Tuhanmu tidaklah membinasakan kota-kota secara aniaya, sedang penduduknya dalam keadaan lengah.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 132), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan masing-masing orang memperoleh derajat-derajat (seimbang) dengan apa yang dikerjakannya. Dan Tuhanmu tidak lengah dari apa yang mereka kerjakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 133), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Tuhanmu Maha Kaya lagi mempunyai rahmat. Jika Dia menghendaki niscaya Dia memusnahkan kamu dan menggantimu dengan siapa yang dikehendaki-Nya setelah kamu (musnah), sebagaimana Dia telah menjadikan kamu dari keturunan orang-orang lain.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 134), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya apa yang dijanjikan kepadamu pasti datang, dan kamu sekali-kali tidak sanggup menolaknya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 135), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Hai kaumku, berbuatlah sepenuh kemampuanmu, sesungguhnya akupun berbuat (pula). Kelak kamu akan mengetahui, siapakah (di antara kita) yang akan memperoleh hasil yang baik di dunia ini. Sesungguhnya orang-orang yang zalim itu tidak akan mendapatkan keberuntungan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 136), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan mereka memperuntukkan bagi Allah satu bagian dari tanaman dan ternak yang telah diciptakan Allah, lalu mereka berkata sesuai dengan persangkaan mereka: "Ini untuk Allah dan ini untuk berhala-berhala kami". Maka saji-sajian yang diperuntukkan bagi berhala-berhala mereka tidak sampai kepada Allah; dan saji-sajian yang diperuntukkan bagi Allah, maka sajian itu sampai kepada berhala-berhala mereka. Amat buruklah ketetapan mereka itu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 137), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan demikianlah pemimpin-pemimpin mereka telah menjadikan kebanyakan dari orang-orang musyrik itu memandang baik membunuh anak-anak mereka untuk membinasakan mereka dan untuk mengaburkan bagi mereka agama-Nya. Dan kalau Allah menghendaki, niscaya mereka tidak mengerjakannya, maka tinggallah mereka dan apa yang mereka ada-adakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 138), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan mereka mengatakan: "Inilah hewan ternak dan tanaman yang dilarang; tidak boleh memakannya, kecuali orang yang kami kehendaki", menurut anggapan mereka, dan ada binatang ternak yang diharamkan menungganginya dan ada binatang ternak yang mereka tidak menyebut nama Allah waktu menyembelihnya, semata-mata membuat-buat kedustaan terhadap Allah. Kelak Allah akan membalas mereka terhadap apa yang selalu mereka ada-adakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 139), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan mereka mengatakan: "Apa yang ada dalam perut binatang ternak ini adalah khusus untuk pria kami dan diharamkan atas wanita kami," dan jika yang dalam perut itu dilahirkan mati, maka pria dan wanita sama-sama boleh memakannya. Kelak Allah akan membalas mereka terhadap ketetapan mereka. Sesungguhnya Allah Maha Bijaksana lagi Maha Mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 140), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya rugilah orang yang membunuh anak-anak mereka, karena kebodohan lagi tidak mengetahui dan mereka mengharamkan apa yang Allah telah rezeki-kan pada mereka dengan semata-mata mengada-adakan terhadap Allah. Sesungguhnya mereka telah sesat dan tidaklah mereka mendapat petunjuk.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 141), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Dialah yang menjadikan kebun-kebun yang berjunjung dan yang tidak berjunjung, pohon korma, tanam-tanaman yang bermacam-macam buahnya, zaitun dan delima yang serupa (bentuk dan warnanya) dan tidak sama (rasanya). Makanlah dari buahnya (yang bermacam-macam itu) bila dia berbuah, dan tunaikanlah haknya di hari memetik hasilnya (dengan disedekahkan kepada fakir miskin); dan janganlah kamu berlebih-lebihan. Sesungguhnya Allah tidak menyukai orang yang berlebih-lebihan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 142), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan di antara hewan ternak itu ada yang dijadikan untuk pengangkutan dan ada yang untuk disembelih. Makanlah dari rezeki yang telah diberikan Allah kepadamu, dan janganlah kamu mengikuti langkah-langkah syaitan. Sesungguhnya syaitan itu musuh yang nyata bagimu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 143), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(yaitu) delapan binatang yang berpasangan, sepasang domba, sepasang dari kambing. Katakanlah: "Apakah dua yang jantan yang diharamkan Allah ataukah dua yang betina, ataukah yang ada dalam kandungan dua betinanya?" Terangkanlah kepadaku dengan berdasar pengetahuan jika kamu memang orang-orang yang benar,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 144), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan sepasang dari unta dan sepasang dari lembu. Katakanlah: "Apakah dua yang jantan yang diharamkan ataukah dua yang betina, ataukah yang ada dalam kandungan dua betinanya? Apakah kamu menyaksikan di waktu Allah menetapkan ini bagimu? Maka siapakah yang lebih zalim daripada orang-orang yang membuat-buat dusta terhadap Allah untuk menyesatkan manusia tanpa pengetahuan?" Sesungguhnya Allah tidak memberi petunjuk kepada orang-orang yang zalim.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 145), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Tiadalah aku peroleh dalam wahyu yang diwahyukan kepadaku, sesuatu yang diharamkan bagi orang yang hendak memakannya, kecuali kalau makanan itu bangkai, atau darah yang mengalir atau daging babi -- karena sesungguhnya semua itu kotor -- atau binatang yang disembelih atas nama selain Allah. Barangsiapa yang dalam keadaan terpaksa, sedang dia tidak menginginkannya dan tidak (pula) melampaui batas, maka sesungguhnya Tuhanmu Maha Pengampun lagi Maha Penyayang".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 146), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan kepada orang-orang Yahudi, Kami haramkan segala binatang yang berkuku dan dari sapi dan domba, Kami haramkan atas mereka lemak dari kedua binatang itu, selain lemak yang melekat di punggung keduanya atau yang di perut besar dan usus atau yang bercampur dengan tulang. Demikianlah Kami hukum mereka disebabkan kedurhakaan mereka; dan sesungguhnya Kami adalah Maha Benar.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 147), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka jika mereka mendustakan kamu, katakanlah: "Tuhanmu mempunyai rahmat yang luas; dan siksa-Nya tidak dapat ditolak dari kaum yang berdosa".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 148), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Orang-orang yang mempersekutukan Tuhan, akan mengatakan: "Jika Allah menghendaki, niscaya kami dan bapak-bapak kami tidak mempersekutukan-Nya dan tidak (pula) kami mengharamkan barang sesuatu apapun". Demikian pulalah orang-orang sebelum mereka telah mendustakan (para rasul) sampai mereka merasakan siksaan Kami. Katakanlah: "Adakah kamu mempunyai sesuatu pengetahuan sehingga dapat kamu mengemukakannya kepada Kami?" Kamu tidak mengikuti kecuali persangkaan belaka, dan kamu tidak lain hanyalah berdusta.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 149), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Allah mempunyai hujjah yang jelas lagi kuat; maka jika Dia menghendaki, pasti Dia memberi petunjuk kepada kamu semuanya".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 150), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Bawalah kemari saksi-saksi kamu yang dapat mempersaksikan bahwasanya Allah telah mengharamkan (makanan yang kamu) haramkan ini" Jika mereka mempersaksikan, maka janganlah kamu ikut pula menjadi saksi bersama mereka; dan janganlah kamu mengikuti hawa nafsu orang-orang yang mendustakan ayat-ayat Kami, dan orang-orang yang tidak beriman kepada kehidupan akhirat, sedang mereka mempersekutukan Tuhan mereka.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 151), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Marilah kubacakan apa yang diharamkan atas kamu oleh Tuhanmu yaitu: janganlah kamu mempersekutukan sesuatu dengan Dia, berbuat baiklah terhadap kedua orang ibu bapa, dan janganlah kamu membunuh anak-anak kamu karena takut kemiskinan, Kami akan memberi rezeki kepadamu dan kepada mereka, dan janganlah kamu mendekati perbuatan-perbuatan yang keji, baik yang nampak di antaranya maupun yang tersembunyi, dan janganlah kamu membunuh jiwa yang diharamkan Allah (membunuhnya) melainkan dengan sesuatu (sebab) yang benar". Demikian itu yang diperintahkan kepadamu supaya kamu memahami(nya).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 152), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan janganlah kamu dekati harta anak yatim, kecuali dengan cara yang lebih bermanfaat, hingga sampai ia dewasa. Dan sempurnakanlah takaran dan timbangan dengan adil. Kami tidak memikulkan beban kepada sesorang melainkan sekedar kesanggupannya. Dan apabila kamu berkata, maka hendaklah kamu berlaku adil, kendatipun ia adalah kerabat(mu), dan penuhilah janji Allah. Yang demikian itu diperintahkan Allah kepadamu agar kamu ingat.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 153), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan bahwa (yang Kami perintahkan ini) adalah jalan-Ku yang lurus, maka ikutilah dia, dan janganlah kamu mengikuti jalan-jalan (yang lain), karena jalan-jalan itu mencerai beraikan kamu dari jalan-Nya. Yang demikian itu diperintahkan Allah agar kamu bertakwa.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 154), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kemudian Kami telah memberikan Al Kitab (Taurat) kepada Musa untuk menyempurnakan (nikmat Kami) kepada orang yang berbuat kebaikan, dan untuk menjelaskan segala sesuatu dan sebagai petunjuk dan rahmat, agar mereka beriman (bahwa) mereka akan menemui Tuhan mereka.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 155), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Al-Quran itu adalah kitab yang Kami turunkan yang diberkati, maka ikutilah dia dan bertakwalah agar kamu diberi rahmat.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 156), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Kami turunkan al-Quran itu) agar kamu (tidak) mengatakan: "Bahwa kitab itu hanya diturunkan kepada dua golongan saja sebelum kami, dan sesungguhnya kami tidak memperhatikan apa yang mereka baca.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 157), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Atau agar kamu (tidak) mengatakan: "Sesungguhnya jikalau kitab ini diturunkan kepada kami, tentulah kami lebih mendapat petunjuk dari mereka". Sesungguhnya telah datang kepada kamu keterangan yang nyata dari Tuhanmu, petunjuk dan rahmat. Maka siapakah yang lebih zalim daripada orang yang mendustakan ayat-ayat Allah dan berpaling daripadanya? Kelak Kami akan memberi balasan kepada orang-orang yang berpaling dari ayat-ayat Kami dengan siksa yang buruk, disebabkan mereka selalu berpaling.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 158), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Yang mereka nanti-nanti tidak lain hanyalah kedatangan malaikat kepada mereka (untuk mencabut nyawa mereka) atau kedatangan (siksa) Tuhanmu atau kedatangan beberapa ayat Tuhanmu. Pada hari datangnya ayat dari Tuhanmu, tidaklah bermanfaat lagi iman seseorang kepada dirinya sendiri yang belum beriman sebelum itu, atau dia (belum) mengusahakan kebaikan dalam masa imannya. Katakanlah: "Tunggulah olehmu sesungguhnya Kamipun menunggu (pula)".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 159), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya orang-orang yang memecah belah agama-Nya dan mereka menjadi bergolongan, tidak ada sedikitpun tanggung jawabmu kepada mereka. Sesungguhnya urusan mereka hanyalah terserah kepada Allah, kemudian Allah akan memberitahukan kepada mereka apa yang telah mereka perbuat.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 160), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Barangsiapa membawa amal yang baik, maka baginya (pahala) sepuluh kali lipat amalnya; dan barangsiapa yang membawa perbuatan jahat maka dia tidak diberi pembalasan melainkan seimbang dengan kejahatannya, sedang mereka sedikitpun tidak dianiaya (dirugikan).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 161), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Sesungguhnya aku telah ditunjuki oleh Tuhanku kepada jalan yang lurus, (yaitu) agama yang benar, agama Ibrahim yang lurus, dan Ibrahim itu bukanlah termasuk orang-orang musyrik".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 162), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: sesungguhnya sembahyangku, ibadatku, hidupku dan matiku hanyalah untuk Allah, Tuhan semesta alam.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 163), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tiada sekutu bagi-Nya; dan demikian itulah yang diperintahkan kepadaku dan aku adalah orang yang pertama-tama menyerahkan diri (kepada Allah)".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 164), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Apakah aku akan mencari Tuhan selain Allah, padahal Dia adalah Tuhan bagi segala sesuatu. Dan tidaklah seorang membuat dosa melainkan kemudharatannya kembali kepada dirinya sendiri; dan seorang yang berdosa tidak akan memikul dosa orang lain. Kemudian kepada Tuhanmulah kamu kembali, dan akan diberitakan-Nya kepadamu apa yang kamu perselisihkan".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 6 AND a.ayah_number = 165), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Dialah yang menjadikan kamu penguasa-penguasa di bumi dan Dia meninggikan sebahagian kamu atas sebahagian (yang lain) beberapa derajat, untuk mengujimu tentang apa yang diberikan-Nya kepadamu. Sesungguhnya Tuhanmu amat cepat siksaan-Nya dan sesungguhnya Dia Maha Pengampun lagi Maha Penyayang.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Alif laam mim shaad.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Ini adalah sebuah kitab yang diturunkan kepadamu, maka janganlah ada kesempitan di dalam dadamu karenanya, supaya kamu memberi peringatan dengan kitab itu (kepada orang kafir), dan menjadi pelajaran bagi orang-orang yang beriman.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Ikutilah apa yang diturunkan kepadamu dari Tuhanmu dan janganlah kamu mengikuti pemimpin-pemimpin selain-Nya. Amat sedikitlah kamu mengambil pelajaran (daripadanya).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Betapa banyaknya negeri yang telah Kami binasakan, maka datanglah siksaan Kami (menimpa penduduk)nya di waktu mereka berada di malam hari, atau di waktu mereka beristirahat di tengah hari.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka tidak adalah keluhan mereka di waktu datang kepada mereka siksaan Kami, kecuali mengatakan: "Sesungguhnya kami adalah orang-orang yang zalim".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka sesungguhnya Kami akan menanyai umat-umat yang telah diutus rasul-rasul kepada mereka dan sesungguhnya Kami akan menanyai (pula) rasul-rasul (Kami),', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'maka sesungguhnya akan Kami kabarkan kepada mereka (apa-apa yang telah mereka perbuat), sedang (Kami) mengetahui (keadaan mereka), dan Kami sekali-kali tidak jauh (dari mereka).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Timbangan pada hari itu ialah kebenaran (keadilan), maka barangsiapa berat timbangan kebaikannya, maka mereka itulah orang-orang yang beruntung.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan siapa yang ringan timbangan kebaikannya, maka itulah orang-orang yang merugikan dirinya sendiri, disebabkan mereka selalu mengingkari ayat-ayat Kami.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya Kami telah menempatkan kamu sekalian di muka bumi dan Kami adakan bagimu di muka bumi (sumber) penghidupan. Amat sedikitlah kamu bersyukur.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya Kami telah menciptakan kamu (Adam), lalu Kami bentuk tubuhmu, kemudian Kami katakan kepada para malaikat: "Bersujudlah kamu kepada Adam", maka merekapun bersujud kecuali iblis. Dia tidak termasuk mereka yang bersujud.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Allah berfirman: "Apakah yang menghalangimu untuk bersujud (kepada Adam) di waktu Aku menyuruhmu?" Menjawab iblis "Saya lebih baik daripadanya: Engkau ciptakan saya dari api sedang dia Engkau ciptakan dari tanah".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Allah berfirman: "Turunlah kamu dari surga itu; karena kamu sepatutnya menyombongkan diri di dalamnya, maka keluarlah, sesungguhnya kamu termasuk orang-orang yang hina".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Iblis menjawab: "Beri tangguhlah saya sampai waktu mereka dibangkitkan".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Allah berfirman: "Sesungguhnya kamu termasuk mereka yang diberi tangguh".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Iblis menjawab: "Karena Engkau telah menghukum saya tersesat, saya benar-benar akan (menghalang-halangi) mereka dari jalan Engkau yang lurus,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'kemudian saya akan mendatangi mereka dari muka dan dari belakang mereka, dari kanan dan dari kiri mereka. Dan Engkau tidak akan mendapati kebanyakan mereka bersyukur (taat).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Allah berfirman: "Keluarlah kamu dari surga itu sebagai orang terhina lagi terusir. Sesungguhnya barangsiapa di antara mereka mengikuti kamu, benar-benar Aku akan mengisi neraka Jahannam dengan kamu semuanya".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Dan Allah berfirman): "Hai Adam bertempat tinggallah kamu dan isterimu di surga serta makanlah olehmu berdua (buah-buahan) di mana saja yang kamu sukai, dan janganlah kamu berdua mendekati pohon ini, lalu menjadilah kamu berdua termasuk orang-orang yang zalim".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka syaitan membisikkan pikiran jahat kepada keduanya untuk menampakkan kepada keduanya apa yang tertutup dari mereka yaitu auratnya dan syaitan berkata: "Tuhan kamu tidak melarangmu dan mendekati pohon ini, melainkan supaya kamu berdua tidak menjadi malaikat atau tidak menjadi orang-orang yang kekal (dalam surga)".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan dia (syaitan) bersumpah kepada keduanya. "Sesungguhnya saya adalah termasuk orang yang memberi nasehat kepada kamu berdua",', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'maka syaitan membujuk keduanya (untuk memakan buah itu) dengan tipu daya. Tatkala keduanya telah merasai buah kayu itu, nampaklah bagi keduanya aurat-auratnya, dan mulailah keduanya menutupinya dengan daun-daun surga. Kemudian Tuhan mereka menyeru mereka: "Bukankah Aku telah melarang kamu berdua dari pohon kayu itu dan Aku katakan kepadamu: "Sesungguhnya syaitan itu adalah musuh yang nyata bagi kamu berdua?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Keduanya berkata: "Ya Tuhan kami, kami telah menganiaya diri kami sendiri, dan jika Engkau tidak mengampuni kami dan memberi rahmat kepada kami, niscaya pastilah kami termasuk orang-orang yang merugi.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Allah berfirman: "Turunlah kamu sekalian, sebahagian kamu menjadi musuh bagi sebahagian yang lain. Dan kamu mempunyai tempat kediaman dan kesenangan (tempat mencari kehidupan) di muka bumi sampai waktu yang telah ditentukan".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Allah berfirman: "Di bumi itu kamu hidup dan di bumi itu kamu mati, dan dari bumi itu (pula) kamu akan dibangkitkan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai anak Adam, sesungguhnya Kami telah menurunkan kepadamu pakaian untuk menutup auratmu dan pakaian indah untuk perhiasan. Dan pakaian takwa itulah yang paling baik. Yang demikian itu adalah sebahagian dari tanda-tanda kekuasaan Allah, mudah-mudahan mereka selalu ingat.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai anak Adam, janganlah sekali-kali kamu dapat ditipu oleh syaitan sebagaimana ia telah mengeluarkan kedua ibu bapamu dari surga, ia menanggalkan dari keduanya pakaiannya untuk memperlihatkan kepada keduanya auratnya. Sesungguhnya ia dan pengikut-pengikutnya melihat kamu dan suatu tempat yang kamu tidak bisa melihat mereka. Sesungguhnya Kami telah menjadikan syaitan-syaitan itu pemimpin-pemimpim bagi orang-orang yang tidak beriman.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan apabila mereka melakukan perbuatan keji, mereka berkata: "Kami mendapati nenek moyang kami mengerjakan yang demikian itu, dan Allah menyuruh kami mengerjakannya". Katakanlah: "Sesungguhnya Allah tidak menyuruh (mengerjakan) perbuatan yang keji". Mengapa kamu mengada-adakan terhadap Allah apa yang tidak kamu ketahui?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Tuhanku menyuruh menjalankan keadilan". Dan (katakanlah): "Luruskanlah muka (diri)mu di setiap sembahyang dan sembahlah Allah dengan mengikhlaskan ketaatanmu kepada-Nya. Sebagaimana Dia telah menciptakan kamu pada permulaan (demikian pulalah kamu akan kembali kepada-Nya)".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sebahagian diberi-Nya petunjuk dan sebahagian lagi telah pasti kesesatan bagi mereka. Sesungguhnya mereka menjadikan syaitan-syaitan pelindung (mereka) selain Allah, dan mereka mengira bahwa mereka mendapat petunjuk.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai anak Adam, pakailah pakaianmu yang indah di setiap (memasuki) mesjid, makan dan minumlah, dan janganlah berlebih-lebihan. Sesungguhnya Allah tidak menyukai orang-orang yang berlebih-lebihan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Siapakah yang mengharamkan perhiasan dari Allah yang telah dikeluarkan-Nya untuk hamba-hamba-Nya dan (siapa pulakah yang mengharamkan) rezeki yang baik?" Katakanlah: "Semuanya itu (disediakan) bagi orang-orang yang beriman dalam kehidupan dunia, khusus (untuk mereka saja) di hari kiamat". Demikianlah Kami menjelaskan ayat-ayat itu bagi orang-orang yang mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Tuhanku hanya mengharamkan perbuatan yang keji, baik yang nampak ataupun yang tersembunyi, dan perbuatan dosa, melanggar hak manusia tanpa alasan yang benar, (mengharamkan) mempersekutukan Allah dengan sesuatu yang Allah tidak menurunkan hujjah untuk itu dan (mengharamkan) mengada-adakan terhadap Allah apa yang tidak kamu ketahui".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tiap-tiap umat mempunyai batas waktu; maka apabila telah datang waktunya mereka tidak dapat mengundurkannya barang sesaatpun dan tidak dapat (pula) memajukannya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai anak-anak Adam, jika datang kepadamu rasul-rasul daripada kamu yang menceritakan kepadamu ayat-ayat-Ku, maka barangsiapa yang bertakwa dan mengadakan perbaikan, tidaklah ada kekhawatiran terhadap mereka dan tidak (pula) mereka bersedih hati.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan orang-orang yang mendustakan ayat-ayat Kami dan menyombongkan diri terhadapnya, mereka itu penghuni-penghuni neraka; mereka kekal di dalamnya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka siapakah yang lebih zalim daripada orang yang membuat-buat dusta terhadap Allah atau mendustakan ayat-ayat-Nya? Orang-orang itu akan memperoleh bahagian yang telah ditentukan untuknya dalam Kitab (Lauh Mahfuzh); hingga bila datang kepada mereka utusan-utusan Kami (malaikat) untuk mengambil nyawanya, (di waktu itu) utusan Kami bertanya: "Di mana (berhala-berhala) yang biasa kamu sembah selain Allah?" Orang-orang musyrik itu menjawab: "Berhala-berhala itu semuanya telah lenyap dari kami," dan mereka mengakui terhadap diri mereka bahwa mereka adalah orang-orang yang kafir.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Allah berfirman: "Masuklah kamu sekalian ke dalam neraka bersama umat-umat jin dan manusia yang telah terdahulu sebelum kamu. Setiap suatu umat masuk (ke dalam neraka), dia mengutuk kawannya (menyesatkannya); sehingga apabila mereka masuk semuanya berkatalah orang-orang yang masuk kemudian di antara mereka kepada orang-orang yang masuk terdahulu: "Ya Tuhan kami, mereka telah menyesatkan kami, sebab itu datangkanlah kepada mereka siksaan yang berlipat ganda dari neraka". Allah berfirman: "Masing-masing mendapat (siksaan) yang berlipat ganda, akan tetapi kamu tidak mengetahui".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan berkata orang-orang yang masuk terdahulu di antara mereka kepada orang-orang yang masuk kemudian: "Kamu tidak mempunyai kelebihan sedikitpun atas kami, maka rasakanlah siksaan karena perbuatan yang telah kamu lakukan".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya orang-orang yang mendustakan ayat-ayat Kami dan menyombongkan diri terhadapnya, sekali-kali tidak akan dibukakan bagi mereka pintu-pintu langit dan tidak (pula) mereka masuk surga, hingga unta masuk ke lubang jarum. Demikianlah Kami memberi pembalasan kepada orang-orang yang berbuat kejahatan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka mempunyai tikar tidur dari api neraka dan di atas mereka ada selimut (api neraka). Demikianlah Kami memberi balasan kepada orang-orang yang zalim,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan orang-orang yang beriman dan mengerjakan amal-amal yang saleh, Kami tidak memikulkan kewajiban kepada diri seseorang melainkan sekedar kesanggupannya, mereka itulah penghuni-penghuni surga; mereka kekal di dalamnya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Kami cabut segala macam dendam yang berada di dalam dada mereka; mengalir di bawah mereka sungai-sungai dan mereka berkata: "Segala puji bagi Allah yang telah menunjuki kami kepada (surga) ini. Dan kami sekali-kali tidak akan mendapat petunjuk kalau Allah tidak memberi kami petunjuk. Sesungguhnya telah datang rasul-rasul Tuhan kami, membawa kebenaran". Dan diserukan kepada mereka: "ltulah surga yang diwariskan kepadamu, disebabkan apa yang dahulu kamu kerjakan".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 44), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan penghuni-penghuni surga berseru kepada Penghuni-penghuni neraka (dengan mengatakan): "Sesungguhnya kami dengan sebenarnya telah memperoleh apa yang Tuhan kami menjanjikannya kepada kami. Maka apakah kamu telah memperoleh dengan sebenarnya apa (azab) yang Tuhan kamu menjanjikannya (kepadamu)?" Mereka (penduduk neraka) menjawab: "Betul". Kemudian seorang penyeru (malaikat) mengumumkan di antara kedua golongan itu: "Kutukan Allah ditimpakan kepada orang-orang yang zalim,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 45), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(yaitu) orang-orang yang menghalang-halangi (manusia) dari jalan Allah dan menginginkan agar jalan itu menjadi bengkok, dan mereka kafir kepada kehidupan akhirat".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 46), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan di antara keduanya (penghuni surga dan neraka) ada batas; dan di atas A''raaf itu ada orang-orang yang mengenal masing-masing dari dua golongan itu dengan tanda-tanda mereka. Dan mereka menyeru penduduk surga: "Salaamun ''alaikum". Mereka belum lagi memasukinya, sedang mereka ingin segera (memasukinya).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 47), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan apabila pandangan mereka dialihkan ke arah penghuni neraka, mereka berkata: "Ya Tuhan kami, janganlah Engkau tempatkan kami bersama-sama orang-orang yang zalim itu".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 48), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan orang-orang yang di atas A''raaf memanggil beberapa orang (pemuka-pemuka orang kafir) yang mereka mengenalnya dengan tanda-tandanya dengan mengatakan: "Harta yang kamu kumpulkan dan apa yang selalu kamu sombongkan itu, tidaklah memberi manfaat kepadamu".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 49), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Orang-orang di atas A''raaf bertanya kepada penghuni neraka): "Itukah orang-orang yang kamu telah bersumpah bahwa mereka tidak akan mendapat rahmat Allah?". (Kepada orang mukmin itu dikatakan): "Masuklah ke dalam surga, tidak ada kekhawatiran terhadapmu dan tidak (pula) kamu bersedih hati".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 50), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan penghuni neraka menyeru penghuni surga: "Limpahkanlah kepada kami sedikit air atau makanan yang telah direzekikan Allah kepadamu". Mereka (penghuni surga) menjawab: "Sesungguhnya Allah telah mengharamkan keduanya itu atas orang-orang kafir,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 51), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(yaitu) orang-orang yang menjadikan agama mereka sebagai main-main dan senda gurau, dan kehidupan dunia telah menipu mereka". Maka pada hari (kiamat) ini, Kami melupakan mereka sebagaimana mereka melupakan pertemuan mereka dengan hari ini, dan (sebagaimana) mereka selalu mengingkari ayat-ayat Kami.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 52), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya Kami telah mendatangkan sebuah Kitab (Al Quran) kepada mereka yang Kami telah menjelaskannya atas dasar pengetahuan Kami; menjadi petunjuk dan rahmat bagi orang-orang yang beriman.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 53), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tiadalah mereka menunggu-nunggu kecuali (terlaksananya kebenaran) Al Quran itu. Pada hari datangnya kebenaran pemberitaan Al Quran itu, berkatalah orang-orang yang melupakannya sebelum itu: "Sesungguhnya telah datang rasul-rasul Tuhan kami membawa yang hak, maka adakah bagi kami pemberi syafa''at yang akan memberi syafa''at bagi kami, atau dapatkah kami dikembalikan (ke dunia) sehingga kami dapat beramal yang lain dari yang pernah kami amalkan?". Sungguh mereka telah merugikan diri mereka sendiri dan telah lenyaplah dari mereka tuhan-tuhan yang mereka ada-adakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 54), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya Tuhan kamu ialah Allah yang telah menciptakan langit dan bumi dalam enam masa, lalu Dia bersemayam di atas ''Arsy. Dia menutupkan malam kepada siang yang mengikutinya dengan cepat, dan (diciptakan-Nya pula) matahari, bulan dan bintang-bintang (masing-masing) tunduk kepada perintah-Nya. Ingatlah, menciptakan dan memerintah hanyalah hak Allah. Maha Suci Allah, Tuhan semesta alam.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 55), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Berdoalah kepada Tuhanmu dengan berendah diri dan suara yang lembut. Sesungguhnya Allah tidak menyukai orang-orang yang melampaui batas.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 56), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan janganlah kamu membuat kerusakan di muka bumi, sesudah (Allah) memperbaikinya dan berdoalah kepada-Nya dengan rasa takut (tidak akan diterima) dan harapan (akan dikabulkan). Sesungguhnya rahmat Allah amat dekat kepada orang-orang yang berbuat baik.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 57), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Dialah yang meniupkan angin sebagai pembawa berita gembira sebelum kedatangan rahmat-Nya (hujan); hingga apabila angin itu telah membawa awan mendung, Kami halau ke suatu daerah yang tandus, lalu Kami turunkan hujan di daerah itu, maka Kami keluarkan dengan sebab hujan itu pelbagai macam buah-buahan. Seperti itulah Kami membangkitkan orang-orang yang telah mati, mudah-mudahan kamu mengambil pelajaran.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 58), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan tanah yang baik, tanaman-tanamannya tumbuh subur dengan seizin Allah; dan tanah yang tidak subur, tanaman-tanamannya hanya tumbuh merana. Demikianlah Kami mengulangi tanda-tanda kebesaran (Kami) bagi orang-orang yang bersyukur.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 59), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya Kami telah mengutus Nuh kepada kaumnya lalu ia berkata: "Wahai kaumku sembahlah Allah, sekali-kali tak ada Tuhan bagimu selain-Nya". Sesungguhnya (kalau kamu tidak menyembah Allah), aku takut kamu akan ditimpa azab hari yang besar (kiamat).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 60), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Pemuka-pemuka dari kaumnya berkata: "Sesungguhnya kami memandang kamu berada dalam kesesatan yang nyata".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 61), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Nuh menjawab: "Hai kaumku, tak ada padaku kesesatan sedikitpun tetapi aku adalah utusan dari Tuhan semesta alam".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 62), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '"Aku sampaikan kepadamu amanat-amanat Tuhanku dan aku memberi nasehat kepadamu. dan aku mengetahui dari Allah apa yang tidak kamu ketahui".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 63), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan apakah kamu (tidak percaya) dan heran bahwa datang kepada kamu peringatan dari Tuhanmu dengan perantaraan seorang laki-laki dari golonganmu agar dia memberi peringatan kepadamu dan mudah-mudahan kamu bertakwa dan supaya kamu mendapat rahmat?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 64), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka mereka mendustakan Nuh, kemudian Kami selamatkan dia dan orang-orang yang bersamanya dalam bahtera, dan Kami tenggelamkan orang-orang yang mendustakan ayat-ayat Kami. Sesungguhnya mereka adalah kaum yang buta (mata hatinya).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 65), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (Kami telah mengutus) kepada kaum ''Aad saudara mereka, Hud. Ia berkata: "Hai kaumku, sembahlah Allah, sekali-kali tidak ada Tuhan bagimu selain dari-Nya. Maka mengapa kamu tidak bertakwa kepada-Nya?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 66), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Pemuka-pemuka yang kafir dari kaumnya berkata: "Sesungguhnya kami benar benar memandang kamu dalam keadaan kurang akal dan sesungguhnya kami menganggap kamu termasuk orang orang yang berdusta".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 67), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hud herkata "Hai kaumku, tidak ada padaku kekurangan akal sedikitpun, tetapi aku ini adalah utusan dari Tuhan semesta alam.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 68), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Aku menyampaikan amanat-amanat Tuhanku kepadamu dan aku hanyalah pemberi nasehat yang terpercaya bagimu".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 69), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Apakah kamu (tidak percaya) dan heran bahwa datang kepadamu peringatan dari Tuhanmu yang dibawa oleh seorang laki-laki di antaramu untuk memberi peringatan kepadamu? Dan ingatlah oleh kamu sekalian di waktu Allah menjadikan kamu sebagai pengganti-pengganti (yang berkuasa) sesudah lenyapnya kaum Nuh, dan Tuhan telah melebihkan kekuatan tubuh dan perawakanmu (daripada kaum Nuh itu). Maka ingatlah nikmat-nikmat Allah supaya kamu mendapat keberuntungan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 70), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka berkata: "Apakah kamu datang kepada kami, agar kami hanya menyembah Allah saja dan meninggalkan apa yang biasa disembah oleh bapak-bapak kami? maka datangkanlah azab yang kamu ancamkan kepada kami jika kamu termasuk orang-orang yang benar".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 71), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Ia berkata: "Sungguh sudah pasti kamu akan ditimpa azab dan kemarahan dari Tuhanmu". Apakah kamu sekalian hendak berbantah dengan aku tentang nama-nama (berhala) yang kamu beserta nenek moyangmu menamakannya, padahal Allah sekali-kali tidak menurunkan hujjah untuk itu? Maka tunggulah (azab itu), sesungguhnya aku juga termasuk orang yamg menunggu bersama kamu".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 72), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka kami selamatkan Hud beserta orang-orang yang bersamanya dengan rahmat yang besar dari Kami, dan Kami tumpas orang-orang yang mendustakan ayat-ayat Kami, dan tiadalah mereka orang-orang yang beriman.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 73), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (Kami telah mengutus) kepada kaum Tsamud saudara mereka Shaleh. Ia berkata: "Hai kaumku, sembahlah Allah, sekali-kali tidak ada Tuhan bagimu selain-Nya. Sesungguhnya telah datang bukti yang nyata kepadamu dari Tuhanmu. Unta betina Allah ini menjadi tanda bagimu, maka biarkanlah dia makan di bumi Allah, dan janganlah kamu mengganggunya dengan gangguan apapun, (yang karenanya) kamu akan ditimpa siksaan yang pedih".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 74), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan ingatlah olehmu di waktu Tuhan menjadikam kamu pengganti-pengganti (yang berkuasa) sesudah kaum ''Aad dan memberikan tempat bagimu di bumi. Kamu dirikan istana-istana di tanah-tanahnya yang datar dan kamu pahat gunung-gunungnya untuk dijadikan rumah; maka ingatlah nikmat-nikmat Allah dan janganlah kamu merajalela di muka bumi membuat kerusakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 75), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Pemuka-pemuka yang menyombongkan diri di antara kaumnya berkata kepada orang-orang yang dianggap lemah yang telah beriman di antara mereka: "Tahukah kamu bahwa Shaleh di utus (menjadi rasul) oleh Tuhannya?". Mereka menjawab: "Sesungguhnya kami beriman kepada wahyu, yang Shaleh diutus untuk menyampaikannya".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 76), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Orang-orang yang menyombongkan diri berkata: "Sesungguhnya kami adalah orang yang tidak percaya kepada apa yang kamu imani itu".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 77), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kemudian mereka sembelih unta betina itu, dan mereka berlaku angkuh terhadap perintah Tuhan. Dan mereka berkata: "Hai Shaleh, datangkanlah apa yang kamu ancamkan itu kepada kami, jika (betul) kamu termasuk orang-orang yang diutus (Allah)".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 78), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Karena itu mereka ditimpa gempa, maka jadilah mereka mayat-mayat yang bergelimpangan di tempat tinggal mereka.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 79), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka Shaleh meninggalkan mereka seraya berkata: "Hai kaumku sesungguhnya aku telah menyampaikan kepadamu amanat Tuhanku, dan aku telah memberi nasehat kepadamu, tetapi kamu tidak menyukai orang-orang yang memberi nasehat".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 80), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (Kami juga telah mengutus) Luth (kepada kaumnya). (Ingatlah) tatkala dia berkata kepada mereka: "Mengapa kamu mengerjakan perbuatan faahisyah itu, yang belum pernah dikerjakan oleh seorangpun (di dunia ini) sebelummu?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 81), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya kamu mendatangi lelaki untuk melepaskan nafsumu (kepada mereka), bukan kepada wanita, malah kamu ini adalah kaum yang melampaui batas.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 82), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Jawab kaumnya tidak lain hanya mengatakan: "Usirlah mereka (Luth dan pengikut-pengikutnya) dari kotamu ini; sesungguhnya mereka adalah orang-orang yang berpura-pura mensucikan diri".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 83), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kemudian Kami selamatkan dia dan pengikut-pengikutnya kecuali isterinya; dia termasuk orang-orang yang tertinggal (dibinasakan).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 84), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Kami turunkan kepada mereka hujan (batu); maka perhatikanlah bagaimana kesudahan orang-orang yang berdosa itu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 85), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (Kami telah mengutus) kepada penduduk Mad-yan saudara mereka, Syu''aib. Ia berkata: "Hai kaumku, sembahlah Allah, sekali-kali tidak ada Tuhan bagimu selain-Nya. Sesungguhnya telah datang kepadamu bukti yang nyata dari Tuhanmu. Maka sempurnakanlah takaran dan timbangan dan janganlah kamu kurangkan bagi manusia barang-barang takaran dan timbangannya, dan janganlah kamu membuat kerusakan di muka bumi sesudah Tuhan memperbaikinya. Yang demikian itu lebih baik bagimu jika betul-betul kamu orang-orang yang beriman".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 86), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan janganlah kamu duduk di tiap-tiap jalan dengan menakut-nakuti dan menghalang-halangi orang yang beriman dari jalan Allah, dan menginginkan agar jalan Allah itu menjadi bengkok. Dan ingatlah di waktu dahulunya kamu berjumlah sedikit, lalu Allah memperbanyak jumlah kamu. Dan perhatikanlah bagaimana kesudahan orang-orang yang berbuat kerusakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 87), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Jika ada segolongan daripada kamu beriman kepada apa yang aku diutus untuk menyampaikannya dan ada (pula) segolongan yang tidak beriman, maka bersabarlah, hingga Allah menetapkan hukumnya di antara kita; dan Dia adalah Hakim yang sebaik-baiknya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 88), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Pemuka-pemuka dan kaum Syu''aib yang menyombongkan dan berkata: "Sesungguhnya kami akan mengusir kamu hai Syu''aib dan orang-orang yang beriman bersamamu dari kota kami, atau kamu kembali kepada agama kami". Berkata Syu''aib: "Dan apakah (kamu akan mengusir kami), kendatipun kami tidak menyukainya?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 89), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sungguh kami mengada-adakan kebohongan yang benar terhadap Allah, jika kami kembali kepada agamamu, sesudah Allah melepaskan kami dari padanya. Dan tidaklah patut kami kembali kepadanya, kecuali jika Allah, Tuhan kami menghendaki(nya). Pengetahuan Tuhan kami meliputi segala sesuatu. Kepada Allah sajalah kami bertawakkal. Ya Tuhan kami, berilah keputusan antara kami dan kaum kami dengan hak (adil) dan Engkaulah Pemberi keputusan yang sebaik-baiknya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 90), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Pemuka-pemuka kaum Syu''aib yang kafir berkata (kepada sesamanya): "Sesungguhnya jika kamu mengikuti Syu''aib, tentu kamu jika berbuat demikian (menjadi) orang-orang yang merugi".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 91), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kemudian mereka ditimpa gempa, maka jadilah mereka mayat-mayat yang bergelimpangan di dalam rumah-rumah mereka,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 92), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(yaitu) orang-orang yang mendustakan Syu''aib seolah-olah mereka belum pernah berdiam di kota itu; orang-orang yang mendustakan Syu''aib mereka itulah orang-orang yang merugi.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 93), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka Syu''aib meninggalkan mereka seraya berkata: "Hai kaumku, sesungguhnya aku telah menyampaikan kepadamu amanat-amanat Tuhanku dan aku telah memberi nasehat kepadamu. Maka bagaimana aku akan bersedih hati terhadap orang-orang yang kafir?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 94), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kami tidaklah mengutus seseorang nabipun kepada sesuatu negeri, (lalu penduduknya mendustakan nabi itu), melainkan Kami timpakan kepada penduduknya kesempitan dan penderitaan supaya mereka tunduk dengan merendahkan diri.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 95), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kemudian Kami ganti kesusahan itu dengan kesenangan hingga keturunan dan harta mereka bertambah banyak, dan mereka berkata: "Sesungguhnya nenek moyang kamipun telah merasai penderitaan dan kesenangan", maka Kami timpakan siksaan atas mereka dengan sekonyong-konyong sedang mereka tidak menyadarinya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 96), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Jikalau sekiranya penduduk negeri-negeri beriman dan bertakwa, pastilah Kami akan melimpahkan kepada mereka berkah dari langit dan bumi, tetapi mereka mendustakan (ayat-ayat Kami) itu, maka Kami siksa mereka disebabkan perbuatannya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 97), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka apakah penduduk negeri-negeri itu merasa aman dari kedatangan siksaan Kami kepada mereka di malam hari di waktu mereka sedang tidur?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 98), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Atau apakah penduduk negeri-negeri itu merasa aman dari kedatangan siksaan Kami kepada mereka di waktu matahari sepenggalahan naik ketika mereka sedang bermain?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 99), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka apakah mereka merasa aman dari azab Allah (yang tidak terduga-duga)? Tiada yang merasa aman dan azab Allah kecuali orang-orang yang merugi.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 100), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan apakah belum jelas bagi orang-orang yang mempusakai suatu negeri sesudah (lenyap) penduduknya, bahwa kalau Kami menghendaki tentu Kami azab mereka karena dosa-dosanya; dan Kami kunci mati hati mereka sehingga mereka tidak dapat mendengar (pelajaran lagi)?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 101), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Negeri-negeri (yang telah Kami binasakan) itu, Kami ceritakan sebagian dari berita-beritanya kepadamu. Dan sungguh telah datang kepada mereka rasul-rasul mereka dengan membawa bukti-bukti yang nyata, maka mereka (juga) tidak beriman kepada apa yang dahulunya mereka telah mendustakannya. Demikianlah Allah mengunci mata hati orang-orang kafir.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 102), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Kami tidak mendapati kebanyakan mereka memenuhi janji. Sesungguhnya Kami mendapati kebanyakan mereka orang-orang yang fasik.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 103), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kemudian Kami utus Musa sesudah rasul-rasul itu dengan membawa ayat-ayat Kami kepada Fir''aun dan pemuka-pemuka kaumnya, lalu mereka mengingkari ayat-ayat itu. Maka perhatikanlah bagaimana akibat orang-orang yang membuat kerusakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 104), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Musa berkata: "Hai Fir''aun, sesungguhnya aku ini adalah seorang utusan dari Tuhan semesta alam,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 105), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'wajib atasku tidak mengatakan sesuatu terhadap Allah, kecuali yang hak. Sesungguhnya aku datang kepadamu dengan membawa bukti yang nyata dari Tuhanmu, maka lepaskanlah Bani Israil (pergi) bersama aku".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 106), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Fir''aun menjawab: "Jika benar kamu membawa sesuatu bukti, maka datangkanlah bukti itu jika (betul) kamu termasuk orang-orang yang benar".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 107), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka Musa menjatuhkan tongkat-nya, lalu seketika itu juga tongkat itu menjadi ular yang sebenarnya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 108), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan ia mengeluarkan tangannya, maka ketika itu juga tangan itu menjadi putih bercahaya (kelihatan) oleh orang-orang yang melihatnya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 109), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Pemuka-pemuka kaum Fir''aun berkata: "Sesungguhnya Musa ini adalah ahli sihir yang pandai,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 110), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'yang bermaksud hendak mengeluarkan kamu dari negerimu". (Fir''aun berkata): "Maka apakah yang kamu anjurkan?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 111), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Pemuka-pemuka itu menjawab: "Beri tangguhlah dia dan saudaranya serta kirimlah ke kota-kota beberapa orang yang akan mengumpulkan (ahli-ahli sihir),', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 112), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'supaya mereka membawa kepadamu semua ahli sihir yang pandai".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 113), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan beberapa ahli sihir itu datang kepada Fir''aun mengatakan: "(Apakah) sesungguhnya kami akan mendapat upah, jika kamilah yang menang?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 114), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Fir''aun menjawab: "Ya, dan sesungguhnya kamu benar-benar akan termasuk orang-orang yang dekat (kepadaku)".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 115), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Ahli-ahli sihir berkata: "Hai Musa, kamukah yang akan melemparkan lebih dahulu, ataukah kami yang akan melemparkan?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 116), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Musa menjawab: "Lemparkanlah (lebih dahulu)!" Maka tatkala mereka melemparkan, mereka menyulap mata orang dan menjadikan orang banyak itu takut, serta mereka mendatangkan sihir yang besar (mena''jubkan).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 117), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Kami wahyukan kepada Musa: "Lemparkanlah tongkatmu!". Maka sekonyong-konyong tongkat itu menelan apa yang mereka sulapkan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 118), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Karena itu nyatalah yang benar dan batallah yang selalu mereka kerjakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 119), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka mereka kalah di tempat itu dan jadilah mereka orang-orang yang hina.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 120), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan ahli-ahli sihir itu serta merta meniarapkan diri dengan bersujud.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 121), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka berkata: "Kami beriman kepada Tuhan semesta alam,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 122), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '"(yaitu) Tuhan Musa dan Harun".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 123), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Fir''aun berkata: "Apakah kamu beriman kepadanya sebelum aku memberi izin kepadamu?, sesungguhnya (perbuatan ini) adalah suatu muslihat yang telah kamu rencanakan di dalam kota ini, untuk mengeluarkan penduduknya dari padanya; maka kelak kamu akan mengetahui (akibat perbuatanmu ini);', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 124), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'demi, sesungguhnya aku akan memotong tangan dan kakimu dengan bersilang secara bertimbal balik, kemudian sungguh-sungguh aku akan menyalib kamu semuanya".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 125), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Ahli-ahli sihir itu menjawab: "Sesungguhnya kepada Tuhanlah kami kembali.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 126), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan kamu tidak menyalahkan kami, melainkan karena kami telah beriman kepada ayat-ayat Tuhan kami ketika ayat-ayat itu datang kepada kami". (Mereka berdoa): "Ya Tuhan kami, limpahkanlah kesabaran kepada kami dan wafatkanlah kami dalam keadaan berserah diri (kepada-Mu)".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 127), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Berkatalah pembesar-pembesar dari kaum Fir''aun (kepada Fir''aun): "Apakah kamu membiarkan Musa dan kaumnya untuk membuat kerusakan di negeri ini (Mesir) dan meninggalkan kamu serta tuhan-tuhanmu?". Fir''aun menjawab: "Akan kita bunuh anak-anak lelaki mereka dan kita biarkan hidup perempuan-perempuan mereka; dan sesungguhnya kita berkuasa penuh di atas mereka".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 128), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Musa berkata kepada kaumnya: "Mohonlah pertolongan kepada Allah dan bersabarlah; sesungguhnya bumi (ini) kepunyaan Allah; dipusakakan-Nya kepada siapa yang dihendaki-Nya dari hamba-hamba-Nya. Dan kesudahan yang baik adalah bagi orang-orang yang bertakwa".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 129), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kaum Musa berkata: "Kami telah ditindas (oleh Fir''aun) sebelum kamu datang kepada kami dan sesudah kamu datang. Musa menjawab: "Mudah-mudahan Allah membinasakan musuhmu dan menjadikan kamu khalifah di bumi(Nya), maka Allah akan melihat bagaimana perbuatanmu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 130), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya Kami telah menghukum (Fir''aun dan) kaumnya dengan (mendatangkan) musim kemarau yang panjang dan kekurangan buah-buahan, supaya mereka mengambil pelajaran.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 131), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kemudian apabila datang kepada mereka kemakmuran, mereka berkata: "Itu adalah karena (usaha) kami". Dan jika mereka ditimpa kesusahan, mereka lemparkan sebab kesialan itu kepada Musa dan orang-orang yang besertanya. Ketahuilah, sesungguhnya kesialan mereka itu adalah ketetapan dari Allah, akan tetapi kebanyakan mereka tidak mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 132), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka berkata: "Bagaimanapun kamu mendatangkan keterangan kepada kami untuk menyihir kami dengan keterangan itu, maka kami sekali-kali tidak akan beriman kepadamu".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 133), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka Kami kirimkan kepada mereka taufan, belalang, kutu, katak dan darah sebagai bukti yang jelas, tetapi mereka tetap menyombongkan diri dan mereka adalah kaum yang berdosa.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 134), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan ketika mereka ditimpa azab (yang telah diterangkan itu) merekapun berkata: "Hai Musa, mohonkanlah untuk kami kepada Tuhamnu dengan (perantaraan) kenabian yang diketahui Allah ada pada sisimu. Sesungguhnya jika kamu dapat menghilangkan azab itu dan pada kami, pasti kami akan beriman kepadamu dan akan kami biarkan Bani Israil pergi bersamamu".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 135), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka setelah Kami hilangkan azab itu dari mereka hingga batas waktu yang mereka sampai kepadanya, tiba-tiba mereka mengingkarinya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 136), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kemudian Kami menghukum mereka, maka Kami tenggelamkan mereka di laut disebabkan mereka mendustakan ayat-ayat Kami dan mereka adalah orang-orang yang melalaikan ayat-ayat Kami itu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 137), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Kami pusakakan kepada kaum yang telah ditindas itu, negeri-negeri bahagian timur bumi dan bahagian baratnya yang telah Kami beri berkah padanya. Dan telah sempurnalah perkataan Tuhanmu yang baik (sebagai janji) untuk Bani Israil disebabkan kesabaran mereka. Dan Kami hancurkan apa yang telah dibuat Fir''aun dan kaumnya dan apa yang telah dibangun mereka.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 138), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Kami seberangkan Bani Israil ke seberang lautan itu, maka setelah mereka sampai kepada suatu kaum yang tetap menyembah berhala mereka, Bani lsrail berkata: "Hai Musa. buatlah untuk kami sebuah tuhan (berhala) sebagaimana mereka mempunyai beberapa tuhan (berhala)". Musa menjawab: "Sesungguh-nya kamu ini adalah kaum yang tidak mengetahui (sifat-sifat Tuhan)".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 139), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya mereka itu akan dihancurkan kepercayaan yang dianutnya dan akan batal apa yang seIalu mereka kerjakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 140), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Musa menjawab: "Patutkah aku mencari Tuhan untuk kamu yang selain dari pada Allah, padahal Dialah yang telah melebihkan kamu atas segala umat.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 141), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (ingatlah hai Bani Israil), ketika Kami menyelamatkan kamu dari (Fir''aun) dan kaumnya, yang mengazab kamu dengan azab yang sangat jahat, yaitu mereka membunuh anak-anak lelakimu dan membiarkan hidup wanita-wanitamu. Dan pada yang demikian itu cobaan yang besar dari Tuhanmu".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 142), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan telah Kami janjikan kepada Musa (memberikan Taurat) sesudah berlalu waktu tiga puluh malam, dan Kami sempurnakan jumlah malam itu dengan sepuluh (malam lagi), maka sempurnalah waktu yang telah ditentukan Tuhannya empat puluh malam. Dan berkata Musa kepada saudaranya yaitu Harun: "Gantikanlah aku dalam (memimpin) kaumku, dan perbaikilah, dan janganlah kamu mengikuti jalan orang-orang yang membuat kerusakan".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 143), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan tatkala Musa datang untuk (munajat dengan Kami) pada waktu yang telah Kami tentukan dan Tuhan telah berfirman (langsung) kepadanya, berkatalah Musa: "Ya Tuhanku, nampakkanlah (diri Engkau) kepadaku agar aku dapat melihat kepada Engkau". Tuhan berfirman: "Kamu sekali-kali tidak sanggup melihat-Ku, tapi lihatlah ke bukit itu, maka jika ia tetap di tempatnya (sebagai sediakala) niscaya kamu dapat melihat-Ku". Tatkala Tuhannya menampakkan diri kepada gunung itu, dijadikannya gunung itu hancur luluh dan Musa pun jatuh pingsan. Maka setelah Musa sadar kembali, dia berkata: "Maha Suci Engkau, aku bertaubat kepada Engkau dan aku orang yang pertama-tama beriman".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 144), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Allah berfirman: "Hai Musa, sesungguhnya Aku memilih (melebihkan) kamu dan manusia yang lain (di masamu) untuk membawa risalah-Ku dan untuk berbicara langsung dengan-Ku, sebab itu berpegang teguhlah kepada apa yang Aku berikan kepadamu dan hendaklah kamu termasuk orang-orang yang bersyukur".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 145), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan telah Kami tuliskan untuk Musa pada luh-luh (Taurat) segala sesuatu sebagai pelajaran dan penjelasan bagi segala sesuatu; maka (Kami berfirman): "Berpeganglah kepadanya dengan teguh dan suruhlah kaummu berpegang kepada (perintah-perintahnya) dengan sebaik-baiknya, nanti Aku akan memperlihatkan kepadamu negeri orang-orang yang fasik.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 146), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Aku akan memalingkan orang-orang yang menyombongkan dirinya di muka bumi tanpa alasan yang benar dari tanda-tanda kekuasaan-Ku. Mereka jika melihat tiap-tiap ayat(Ku), mereka tidak beriman kepadanya. Dan jika mereka melihat jalan yang membawa kepada petunjuk, mereka tidak mau menempuhnya, tetapi jika mereka melihat jalan kesesatan, mereka terus memenempuhnya. Yang demikian itu adalah karena mereka mendustakan ayat-ayat Kami dan mereka selalu lalai dari padanya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 147), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan orang-orang yang mendustakan ayat-ayat Kami dan mendustakan akan menemui akhirat, sia-sialah perbuatan mereka. Mereka tidak diberi balasan selain dari apa yang telah mereka kerjakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 148), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan kaum Musa, setelah kepergian Musa ke gunung Thur membuat dari perhiasan-perhiasan (emas) mereka anak lembu yang bertubuh dan bersuara. Apakah mereka tidak mengetahui bahwa anak lembu itu tidak dapat berbicara dengan mereka dan tidak dapat (pula) menunjukkan jalan kepada mereka? Mereka menjadikannya (sebagai sembahan) dan mereka adalah orang-orang yang zalim.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 149), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan setelah mereka sangat menyesali perbuatannya dan mengetahui bahwa mereka telah sesat, merekapun berkata: "Sungguh jika Tuhan kami tidak memberi rahmat kepada kami dan tidak mengampuni kami, pastilah kami menjadi orang-orang yang merugi".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 150), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan tatkala Musa telah kembali kepada kaumnya dengan marah dan sedih hati berkatalah dia: "Alangkah buruknya perbuatan yang kamu kerjakan sesudah kepergianku! Apakah kamu hendak mendahului janji Tuhanmu? Dan Musapun melemparkan luh-luh (Taurat) itu dan memegang (rambut) kepala saudaranya (Harun) sambil menariknya ke arahnya, Harun berkata: "Hai anak ibuku, sesungguhnya kaum ini telah menganggapku lemah dan hampir-hampir mereka membunuhku, sebab itu janganlah kamu menjadikan musuh-musuh gembira melihatku, dan janganlah kamu masukkan aku ke dalam golongan orang-orang yang zalim"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 151), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Musa berdoa: "Ya Tuhanku, ampunilah aku dan saudaraku dan masukkanlah kami ke dalam rahmat Engkau, dan Engkau adalah Maha Penyayang di antara para penyayang".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 152), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya orang-orang yang menjadikan anak lembu (sebagai sembahannya), kelak akan menimpa mereka kemurkaan dari Tuhan mereka dan kehinaan dalam kehidupan di dunia. Demikianlah Kami memberi balasan kepada orang-orang yang membuat-buat kebohongan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 153), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Orang-orang yang mengerjakan kejahatan, kemudian bertaubat sesudah itu dan beriman; sesungguhnya Tuhan kamu sesudah taubat yang disertai dengan iman itu adalah Maha Pengampun lagi Maha Penyayang.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 154), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesudah amarah Musa menjadi reda, lalu diambilnya (kembali) luh-luh (Taurat) itu; dan dalam tulisannya terdapat petunjuk dan rahmat untuk orang-orang yang takut kepada Tuhannya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 155), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Musa memilih tujuh puluh orang dari kaumnya untuk (memohonkan taubat kepada Kami) pada waktu yang telah Kami tentukan. Maka ketika mereka digoncang gempa bumi, Musa berkata: "Ya Tuhanku, kalau Engkau kehendaki, tentulah Engkau membinasakan mereka dan aku sebelum ini. Apakah Engkau membinasakan kami karena perbuatan orang-orang yang kurang akal di antara kami? Itu hanyalah cobaan dari Engkau, Engkau sesatkan dengan cobaan itu siapa yang Engkau kehendaki dan Engkau beri petunjuk kepada siapa yang Engkau kehendaki. Engkaulah Yang memimpin kami, maka ampunilah kami dan berilah kami rahmat dan Engkaulah Pemberi ampun yang sebaik-baiknya".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 156), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan tetapkanlah untuk kami kebajikan di dunia ini dan di akhirat; sesungguhnya kami kembali (bertaubat) kepada Engkau. Allah berfirman: "Siksa-Ku akan Kutimpakan kepada siapa yang Aku kehendaki dan rahmat-Ku meliputi segala sesuatu. Maka akan Aku tetapkan rahmat-Ku untuk orang-orang yang bertakwa, yang menunaikan zakat dan orang-orang yang beriman kepada ayat-ayat Kami".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 157), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Yaitu) orang-orang yang mengikut Rasul, Nabi yang ummi yang (namanya) mereka dapati tertulis di dalam Taurat dan Injil yang ada di sisi mereka, yang menyuruh mereka mengerjakan yang ma''ruf dan melarang mereka dari mengerjakan yang mungkar dan menghalalkan bagi mereka segala yang baik dan mengharamkan bagi mereka segala yang buruk dan membuang dari mereka beban-beban dan belenggu-belenggu yang ada pada mereka. Maka orang-orang yang beriman kepadanya. memuliakannya, menolongnya dan mengikuti cahaya yang terang yang diturunkan kepadanya (Al Quran), mereka itulah orang-orang yang beruntung.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 158), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Hai manusia sesungguhnya aku adalah utusan Allah kepadamu semua, yaitu Allah Yang mempunyai kerajaan langit dan bumi; tidak ada Tuhan (yang berhak disembah) selain Dia, Yang menghidupkan dan mematikan, maka berimanlah kamu kepada Allah dan Rasul-Nya, Nabi yang ummi yang beriman kepada Allah dan kepada kalimat-kalimat-Nya (kitab-kitab-Nya) dan ikutilah dia, supaya kamu mendapat petunjuk".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 159), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan di antara kaum Musa itu terdapat suatu umat yang memberi petunjuk (kepada manusia) dengan hak dan dengan yang hak itulah mereka menjalankan keadilan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 160), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan mereka Kami bagi menjadi dua belas suku yang masing-masingnya berjumlah besar dan Kami wahyukan kepada Musa ketika kaumnya meminta air kepadanya: "Pukullah batu itu dengan tongkatmu!". Maka memancarlah dari padanya duabelas mata air. Sesungguhnya tiap-tiap suku mengetahui tempat minum masing-masing. Dan Kami naungkan awan di atas mereka dan Kami turunkan kepada mereka manna dan salwa. (Kami berfirman): "Makanlah yang baik-baik dari apa yang telah Kami rezekikan kepadamu". Mereka tidak menganiaya Kami, tapi merekalah yang selalu menganiaya dirinya sendiri.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 161), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (ingatlah), ketika dikatakan kepada mereka (Bani Israil): "Diamlah di negeri ini saja (Baitul Maqdis) dan makanlah dari (hasil bumi)nya di mana saja kamu kehendaki". Dan katakanlah: "Bebaskanlah kami dari dosa kami dan masukilah pintu gerbangnya sambil membungkuk, niscaya Kami ampuni kesalahan-kesalahanmu". Kelak akan Kami tambah (pahala) kepada orang-orang yang berbuat baik.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 162), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka orang-orang yang zalim di antara mereka itu mengganti (perkataan itu) dengan perkataan yang tidak dikatakan kepada mereka, maka Kami timpakan kepada mereka azab dari langit disebabkan kezaliman mereka.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 163), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan tanyakanlah kepada Bani Israil tentang negeri yang terletak di dekat laut ketika mereka melanggar aturan pada hari Sabtu, di waktu datang kepada mereka ikan-ikan (yang berada di sekitar) mereka terapung-apung di permukaan air, dan di hari-hari yang bukan Sabtu, ikan-ikan itu tidak datang kepada mereka. Demikianlah Kami mencoba mereka disebabkan mereka berlaku fasik.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 164), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (ingatlah) ketika suatu umat di antara mereka berkata: "Mengapa kamu menasehati kaum yang Allah akan membinasakan mereka atau mengazab mereka dengan azab yang amat keras?" Mereka menjawab: "Agar kami mempunyai alasan (pelepas tanggung jawab) kepada Tuhanmu, dan supaya mereka bertakwa.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 165), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka tatkala mereka melupakan apa yang diperingatkan kepada mereka, Kami selamatkan orang-orang yang melarang dari perbuatan jahat dan Kami timpakan kepada orang-orang yang zalim siksaan yang keras, disebabkan mereka selalu berbuat fasik.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 166), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka tatkala mereka bersikap sombong terhadap apa yang dilarang mereka mengerjakannya, Kami katakan kepadanya: "Jadilah kamu kera yang hina.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 167), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (ingatlah), ketika Tuhanmu memberitahukan, bahwa sesungguhnya Dia akan mengirim kepada mereka (orang-orang Yahudi) sampai hari kiamat orang-orang yang akan menimpakan kepada mereka azab yang seburuk-buruknya. Sesungguhnya Tuhanmu amat cepat siksa-Nya, dan sesungguhnya Dia adalah Maha Pengampun lagi Maha Penyayang.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 168), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Kami bagi-bagi mereka di dunia ini menjadi beberapa golongan; di antaranya ada orang-orang yang saleh dan di antaranya ada yang tidak demikian. Dan Kami coba mereka dengan (nikmat) yang baik-baik dan (bencana) yang buruk-buruk, agar mereka kembali (kepada kebenaran).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 169), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka datanglah sesudah mereka generasi (yang jahat) yang mewarisi Taurat, yang mengambil harta benda dunia yang rendah ini, dan berkata: "Kami akan diberi ampun". Dan kelak jika datang kepada mereka harta benda dunia sebanyak itu (pula), niscaya mereka akan mengambilnya (juga). Bukankah perjanjian Taurat sudah diambil dari mereka, yaitu bahwa mereka tidak akan mengatakan terhadap Allah kecuali yang benar, padahal mereka telah mempelajari apa yang tersebut di dalamnya?. Dan kampung akhirat itu lebih bagi mereka yang bertakwa. Maka apakah kamu sekalian tidak mengerti?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 170), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan orang-orang yang berpegang teguh dengan Al Kitab (Taurat) serta mendirikan shalat, (akan diberi pahala) karena sesungguhnya Kami tidak menyia-nyiakan pahala orang-orang yang mengadakan perbaikan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 171), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (ingatlah), ketika Kami mengangkat bukit ke atas mereka seakan-akan bukit itu naungan awan dan mereka yakin bahwa bukit itu akan jatuh menimpa mereka. (Dan Kami katakan kepada mereka): "Peganglah dengan teguh apa yang telah Kami berikan kepadamu, serta ingatlah selalu (amalkanlah) apa yang tersebut di dalamnya supaya kamu menjadi orang-orang yang bertakwa".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 172), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (ingatlah), ketika Tuhanmu mengeluarkan keturunan anak-anak Adam dari sulbi mereka dan Allah mengambil kesaksian terhadap jiwa mereka (seraya berfirman): "Bukankah Aku ini Tuhanmu?" Mereka menjawab: "Betul (Engkau Tuhan kami), kami menjadi saksi". (Kami lakukan yang demikian itu) agar di hari kiamat kamu tidak mengatakan: "Sesungguhnya kami (bani Adam) adalah orang-orang yang lengah terhadap ini (keesaan Tuhan)",', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 173), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'atau agar kamu tidak mengatakan: "Sesungguhnya orang-orang tua kami telah mempersekutukan Tuhan sejak dahulu, sedang kami ini adalah anak-anak keturunan yang (datang) sesudah mereka. Maka apakah Engkau akan membinasakan kami karena perbuatan orang-orang yang sesat dahulu?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 174), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan demikianlah Kami menjelaskan ayat-ayat itu, agar mereka kembali (kepada kebenaran).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 175), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan bacakanlah kepada mereka berita orang yang telah Kami berikan kepadanya ayat-ayat Kami (pengetahuan tentang isi Al Kitab), kemudian dia melepaskan diri dari pada ayat-ayat itu, lalu dia diikuti oleh syaitan (sampai dia tergoda), maka jadilah dia termasuk orang-orang yang sesat.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 176), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan kalau Kami menghendaki, sesungguhnya Kami tinggikan (derajat)nya dengan ayat-ayat itu, tetapi dia cenderung kepada dunia dan menurutkan hawa nafsunya yang rendah, maka perumpamaannya seperti anjing jika kamu menghalaunya diulurkannya lidahnya dan jika kamu membiarkannya dia mengulurkan lidahnya (juga). Demikian itulah perumpamaan orang-orang yang mendustakan ayat-ayat Kami. Maka ceritakanlah (kepada mereka) kisah-kisah itu agar mereka berfikir.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 177), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Amat buruklah perumpamaan orang-orang yang mendustakan ayat-ayat Kami dan kepada diri mereka sendirilah mereka berbuat zalim.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 178), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Barangsiapa yang diberi petunjuk oleh Allah, maka dialah yang mendapat petunjuk; dan barangsiapa yang disesatkan Allah, maka merekalah orang-orang yang merugi.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 179), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya Kami jadikan untuk (isi neraka Jahannam) kebanyakan dari jin dan manusia, mereka mempunyai hati, tetapi tidak dipergunakannya untuk memahami (ayat-ayat Allah) dan mereka mempunyai mata (tetapi) tidak dipergunakannya untuk melihat (tanda-tanda kekuasaan Allah), dan mereka mempunyai telinga (tetapi) tidak dipergunakannya untuk mendengar (ayat-ayat Allah). Mereka itu sebagai binatang ternak, bahkan mereka lebih sesat lagi. Mereka itulah orang-orang yang lalai.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 180), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hanya milik Allah asmaa-ul husna, maka bermohonlah kepada-Nya dengan menyebut asmaa-ul husna itu dan tinggalkanlah orang-orang yang menyimpang dari kebenaran dalam (menyebut) nama-nama-Nya. Nanti mereka akan mendapat balasan terhadap apa yang telah mereka kerjakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 181), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan di antara orang-orang yang Kami ciptakan ada umat yang memberi petunjuk dengan hak, dan dengan yang hak itu (pula) mereka menjalankan keadilan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 182), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan orang-orang yang mendustakan ayat-ayat Kami, nanti Kami akan menarik mereka dengan berangaur-angsur (ke arah kebinasaan), dengan cara yang tidak mereka ketahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 183), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Aku memberi tangguh kepada mereka. Sesungguhnya rencana-Ku amat teguh.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 184), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Apakah (mereka lalai) dan tidak memikirkan bahwa teman mereka (Muhammad) tidak berpenyakit gila. Dia (Muhammad itu) tidak lain hanyalah seorang pemberi peringatan lagi pemberi penjelasan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 185), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan apakah mereka tidak memperhatikan kerajaan langit dan bumi dan segala sesuatu yang diciptakan Allah, dan kemungkinan telah dekatnya kebinasaan mereka? Maka kepada berita manakah lagi mereka akan beriman sesudah Al Quran itu?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 186), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Barangsiapa yang Allah sesatkan, maka baginya tak ada orang yang akan memberi petunjuk. Dan Allah membiarkan mereka terombang-ambing dalam kesesatan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 187), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka menanyakan kepadamu tentang kiamat: "Bilakah terjadinya?" Katakanlah: "Sesungguhnya pengetahuan tentang kiamat itu adalah pada sisi Tuhanku; tidak seorangpun yang dapat menjelaskan waktu kedatangannya selain Dia. Kiamat itu amat berat (huru haranya bagi makhluk) yang di langit dan di bumi. Kiamat itu tidak akan datang kepadamu melainkan dengan tiba-tiba". Mereka bertanya kepadamu seakan-akan kamu benar-benar mengetahuinya. Katakanlah: "Sesungguhnya pengetahuan tentang bari kiamat itu adalah di sisi Allah, tetapi kebanyakan manusia tidak mengetahui".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 188), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Aku tidak berkuasa menarik kemanfaatan bagi diriku dan tidak (pula) menolak kemudharatan kecuali yang dikehendaki Allah. Dan sekiranya aku mengetahui yang ghaib, tentulah aku membuat kebajikan sebanyak-banyaknya dan aku tidak akan ditimpa kemudharatan. Aku tidak lain hanyalah pemberi peringatan, dan pembawa berita gembira bagi orang-orang yang beriman".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 189), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dialah Yang menciptakan kamu dari diri yang satu dan dari padanya Dia menciptakan isterinya, agar dia merasa senang kepadanya. Maka setelah dicampurinya, isterinya itu mengandung kandungan yang ringan, dan teruslah dia merasa ringan (beberapa waktu). Kemudian tatkala dia merasa berat, keduanya (suami-isteri) bermohon kepada Allah, Tuhannya seraya berkata: "Sesungguhnya jika Engkau memberi kami anak yang saleh, tentulah kami termasuk orang-orang yang bersyukur".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 190), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tatkala Allah memberi kepada keduanya seorang anak yang sempurna, maka keduanya menjadikan sekutu bagi Allah terhadap anak yang telah dianugerahkan-Nya kepada keduanya itu. Maka Maha Tinggi Allah dari apa yang mereka persekutukan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 191), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Apakah mereka mempersekutukan (Allah dengan) berhada-berhala yang tak dapat menciptakan sesuatupun? Sedangkan berhala-berhala itu sendiri buatan orang.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 192), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan berhala-berhala itu tidak mampu memberi pertolongan kepada penyembah-penyembahnya dan kepada dirinya sendiripun berhala-berha]a itu tidak dapat memberi pertolongan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 193), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan jika kamu (hai orang-orang musyrik) menyerunya (berhala) untuk memberi petunjuk kepadamu, tidaklah berhala-berhala itu dapat memperkenankan seruanmu; sama saja (hasilnya) buat kamu menyeru mereka ataupun kamu herdiam diri.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 194), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya berhala-berhala yang kamu seru selain Allah itu adalah makhluk (yang lemah) yang serupa juga dengan kamu. Maka serulah berhala-berhala itu lalu biarkanlah mereka mmperkenankan permintaanmu, jika kamu memang orang-orang yang benar.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 195), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Apakah berhala-berhala mempunyai kaki yang dengan itu ia dapat berjalan, atau mempunyai tangan yang dengan itu ia dapat memegang dengan keras, atau mempunyai mata yang dengan itu ia dapat melihat, atau mempunyai telinga yang dengan itu ia dapat mendengar? Katakanlah: "Panggillah berhala-berhalamu yang kamu jadikan sekutu Allah, kemudian lakukanlah tipu daya (untuk mencelakakan)-ku. tanpa memberi tangguh (kepada-ku)".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 196), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya pelindungku ialahlah Yang telah menurunkan Al Kitab (Al Quran) dan Dia melindungi orang-orang yang saleh.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 197), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan berhala-berhala yang kamu seru selain Allah tidaklah sanggup menolongmu, bahkan tidak dapat menolong dirinya sendiri.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 198), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan jika kamu sekalian menyeru (berhala-berhala) untuk memberi petunjuk, niscaya berhala-herhala itu tidak dapat mendengarnya. Dan kamu melihat berhala-berhala itu memandang kepadamu padahal ia tidak melihat.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 199), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Jadilah engkau pemaaf dan suruhlah orang mengerjakan yang ma''ruf, serta berpalinglah dari pada orang-orang yang bodoh.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 200), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan jika kamu ditimpa sesuatu godaan syaitan maka berlindunglah kepada Allah', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 201), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya orang-orang yang bertakwa bila mereka ditimpa was-was dari syaitan, mereka ingat kepada Allah, maka ketika itu juga mereka melihat kesalahan-kesalahannya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 202), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan teman-teman mereka (orang-orang kafir dan fasik) membantu syaitan-syaitan dalam menyesatkan dan mereka tidak henti-hentinya (menyesatkan).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 203), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan apabila kamu tidak membawa suatu ayat Al Quran kepada mereka, mereka berkata: "Mengapa tidak kamu buat sendiri ayat itu?" Katakanlah: "Sesungguhnya aku hanya mengikut apa yang diwahyukan dari Tuhanku kepadaku. Al Quran ini adalah bukti-bukti yang nyata dari Tuhanmu, petunjuk dan rahmat bagi orang-orang yang beriman".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 204), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan apabila dibacakan Al Quran, maka dengarkanlah baik-baik, dan perhatikanlah dengan tenang agar kamu mendapat rahmat.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 205), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sebutlah (nama) Tuhanmu dalam hatimu dengan merendahkan diri dan rasa takut, dan dengan tidak mengeraskan suara, di waktu pagi dan petang, dan janganlah kamu termasuk orang-orang yang lalai.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 7 AND a.ayah_number = 206), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya malaikat-malaikat yang ada di sisi Tuhanmu tidaklah merasa enggan menyembah Allah dan mereka mentasbihkan-Nya dan hanya kepada-Nya-lah mereka bersujud.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka menanyakan kepadamu tentang (pembagian) harta rampasan perang. Katakanlah: "Harta rampasan perang kepunyaan Allah dan Rasul, oleh sebab itu bertakwalah kepada Allah dan perbaikilah perhubungan di antara sesamamu; dan taatlah kepada Allah dan Rasul-Nya jika kamu adalah orang-orang yang beriman".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya orang-orang yang beriman ialah mereka yang bila disebut nama Allah gemetarlah hati mereka, dan apabila dibacakan ayat-ayat-Nya bertambahlah iman mereka (karenanya), dan hanya kepada Tuhanlah mereka bertawakkal.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(yaitu) orang-orang yang mendirikan shalat dan yang menafkahkan sebagian dari rezeki yang Kami berikan kepada mereka.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Itulah orang-orang yang beriman dengan sebenar-benarnya. Mereka akan memperoleh beberapa derajat ketinggian di sisi Tuhannya dan ampunan serta rezeki (nikmat) yang mulia.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sebagaimana Tuhanmu menyuruhmu pergi dan rumahmu dengan kebenaran, padahal sesungguhnya sebagian dari orang-orang yang beriman itu tidak menyukainya,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'mereka membantahmu tentang kebenaran sesudah nyata (bahwa mereka pasti menang), seolah-olah mereka dihalau kepada kematian, sedang mereka melihat (sebab-sebab kematian itu).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (ingatlah), ketika Allah menjanjikan kepadamu bahwa salah satu dari dua golongan (yang kamu hadapi) adalah untukmu, sedang kamu menginginkan bahwa yang tidak mempunyai kekekuatan senjatalah yang untukmu, dan Allah menghendaki untuk membenarkan yang benar dengan ayat-ayat-Nya dan memusnahkan orang-orang kafir,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'agar Allah menetapkan yang hak (Islam) dan membatalkan yang batil (syirik) walaupun orang-orang yang berdosa (musyrik) itu tidak menyukainya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Ingatlah), ketika kamu memohon pertolongan kepada Tuhanmu, lalu diperkenankan-Nya bagimu: "Sesungguhnya Aku akan mendatangkan bala bantuan kepada kamu dengan seribu malaikat yang datang berturut-turut".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Allah tidak menjadikannya (mengirim bala bantuan itu), melainkan sebagai kabar gembira dan agar hatimu menjadi tenteram karenanya. Dan kemenangan itu hanyalah dari sisi Allah. Sesungguhnya Allah Maha Perkasa lagi Maha Bijaksana.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Ingatlah), ketika Allah menjadikan kamu mengantuk sebagai suatu penenteraman daripada-Nya, dan Allah menurunkan kepadamu hujan dari langit untuk mensucikan kamu dengan hujan itu dan menghilangkan dari kamu gangguan-gangguan syaitan dan untuk menguatkan hatimu dan mesmperteguh dengannya telapak kaki(mu).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Ingatlah), ketika Tuhanmu mewahyukan kepada para malaikat: "Sesungguhnya Aku bersama kamu, maka teguhkan (pendirian) orang-orang yang telah beriman". Kelak akan Aku jatuhkan rasa ketakutan ke dalam hati orang-orang kafir, maka penggallah kepala mereka dan pancunglah tiap-tiap ujung jari mereka.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Ketentuan) yang demikian itu adalah karena sesungguhnya mereka menentang Allah dan Rasul-Nya; dan barangsiapa menentang Allah dan Rasul-Nya, maka sesungguhnya Allah amat keras siksaan-Nya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Itulah (hukum dunia yang ditimpakan atasmu), maka rasakanlah hukuman itu. Sesungguhnya bagi orang-orang yang kafir itu ada (lagi) azab neraka.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai orang-orang yang beriman, apabila kamu bertemu dengan orang-orang yang kafir yang sedang menyerangmu, maka janganlah kamu membelakangi mereka (mundur).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Barangsiapa yang membelakangi mereka (mundur) di waktu itu, kecuali berbelok untuk (sisat) perang atau hendak menggabungkan diri dengan pasukan yang lain, maka sesungguhnya orang itu kembali dengan membawa kemurkaan dari Allah, dan tempatnya ialah neraka Jahannam. Dan amat buruklah tempat kembalinya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka (yang sebenarnya) bukan kamu yang membunuh mereka, akan tetapi Allahlah yang membunuh mereka, dan bukan kamu yang melempar ketika kamu melempar, tetapi Allah-lah yang melempar. (Allah berbuat demikian untuk membinasakan mereka) dan untuk memberi kemenangan kepada orang-orang mukmin, dengan kemenangan yang baik. Sesungguhnya Allah Maha Mendengar lagi Maha Mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Itulah (karunia Allah yang dilimpahkan kepadamu), dan sesungguhnya Allah melemahkan tipu daya orang-orang yang kafir.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Jika kamu (orang-orang musyrikin) mencari keputusan, maka telah datang keputusan kepadamu; dan jika kamu berhenti; maka itulah yang lehih baik bagimu; dan jika kamu kembali, niscaya Kami kembali (pula); dan angkatan perangmu sekali-kali tidak akan dapat menolak dari kamu sesuatu bahayapun, biarpun dia banyak dan sesungguhnya Allah beserta orang-orang yang beriman.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai orang-orang yang beriman, taatlah kepada Allah dan Rasul-Nya, dan janganlah kamu berpaling dari pada-Nya, sedang kamu mendengar (perintah-perintah-Nya),', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan janganlah kamu menjadi seperti orang-orang (munafik) vang berkata "Kami mendengarkan, padahal mereka tidak mendengarkan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya binatang (makhluk) yang seburuk-buruknya pada sisi Allah ialah; orang-orang yang pekak dan tuli yang tidak mengerti apa-apapun.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kalau sekiranya Allah mengetahui kebaikan ada pada mereka, tentulah Allah menjadikan mereka dapat mendengar. Dan jikalau Allah menjadikan mereka dapat mendengar, niscaya mereka pasti berpaling juga, sedang mereka memalingkan diri (dari apa yang mereka dengar itu).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai orang-orang yang beriman, penuhilah seruan Allah dan seruan Rasul apabila Rasul menyeru kamu kepada suatu yang memberi kehidupan kepada kamu, ketahuilah bahwa sesungguhnya Allah membatasi antara manusia dan hatinya dan sesungguhnya kepada-Nya-lah kamu akan dikumpulkan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan peliharalah dirimu dari pada siksaan yang tidak khusus menimpa orang-orang yang zalim saja di antara kamu. Dan ketahuilah bahwa Allah amat keras siksaan-Nya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan ingatlah (hai para muhajirin) ketika kamu masih berjumlah sedikit, lagi tertindas di muka bumi (Mekah), kamu takut orang-orang (Mekah) akan menculik kamu, maka Allah memberi kamu tempat menetap (Madinah) dan dijadikan-Nya kamu kuat dengan pertolongan-Nya dan diberi-Nya kamu rezeki dari yang baik-baik agar kamu bersyukur.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai orang-orang yang beriman, janganlah kamu mengkhianati Allah dan Rasul (Muhammad) dan (juga) janganlah kamu mengkhianati amanat-amanat yang dipercayakan kepadamu, sedang kamu mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan ketahuilah, bahwa hartamu dan anak-anakmu itu hanyalah sebagai cobaan dan sesungguhnya di sisi Allah-lah pahala yang besar.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai orang-orang beriman, jika kamu bertakwa kepada Allah, Kami akan memberikan kepadamu Furqaan. Dan kami akan jauhkan dirimu dari kesalahan-kesalahanmu, dan mengampuni (dosa-dosa)mu. Dan Allah mempunyai karunia yang besar.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (ingatlah), ketika orang-orang kafir (Quraisy) memikirkan daya upaya terhadapmu untuk menangkap dan memenjarakanmu atau membunuhmu, atau mengusirmu. Mereka memikirkan tipu daya dan Allah menggagalkan tipu daya itu. Dan Allah sebaik-baik Pembalas tipu daya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan apabila dibacakan kepada mereka ayat-ayat Kami, mereka berkata: "Sesungguhnya kami telah mendengar (ayat-ayat yang seperti ini), kalau kami menhendaki niscaya kami dapat membacakan yang seperti ini, (Al Quran) ini tidak lain hanyalah dongeng-dongengan orang-orang purbakala".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (ingatlah), ketika mereka (orang-orang musyrik) berkata: "Ya Allah, jika betul (Al Quran) ini, dialah yang benar dari sisi Engkau, maka hujanilah kami dengan batu dari langit, atau datangkanlah kepada kami azab yang pedih".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Allah sekali-kali tidak akan mengazab mereka, sedang kamu berada di antara mereka. Dan tidaklah (pula) Allah akan mengazab mereka, sedang mereka meminta ampun', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kenapa Allah tidak mengazab mereka padahal mereka menghalangi orang untuk (mendatangi) Masjidilharam, dan mereka bukanlah orang-orang yang berhak menguasainya? Orang-orang yang berhak menguasai(nya) hanyalah orang-orang yang bertakwa. tetapi kebanyakan mereka tidak mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sembahyang mereka di sekitar Baitullah itu, lain tidak hanyalah siulan dan tepukan tangan. Maka rasakanlah azab disebabkan kekafiranmu itu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya orang-orang yang kafir menafkahkan harta mereka untuk menghalangi (orang) dari jalan Allah. Mereka akan menafkahkan harta itu, kemudian menjadi sesalan bagi mereka, dan mereka akan dikalahkan. Dan ke dalam Jahannamlah orang-orang yang kafir itu dikumpulkan,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'supaya Allah memisahkan (golongan) yang buruk dari yang baik dan menjadikan (golongan) yang buruk itu sebagiannya di atas sebagian yang lain, lalu kesemuanya ditumpukkan-Nya, dan dimasukkan-Nya ke dalam neraka Jahannam. Mereka itulah orang-orang yang merugi.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah kepada orang-orang yang kafir itu: "Jika mereka berhenti (dari kekafirannya), niscaya Allah akan mengampuni mereka tentang dosa-dosa mereka yang sudah lalu; dan jika mereka kembali lagi sesungguhnya akan berlaku (kepada mereka) sunnah (Allah tenhadap) orang-orang dahulu".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan perangilah mereka, supaya jangan ada fitnah dan supaya agama itu semata-mata untuk Allah. Jika mereka berhenti (dari kekafiran), maka sesungguhnya Allah Maha Melihat apa yang mereka kerjakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan jika mereka berpaling, maka ketahuilah bahwasanya Allah Pelindungmu. Dia adalah sebaik-baik Pelindung dan sebaik-baik Penolong.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Ketahuilah, sesungguhnya apa saja yang dapat kamu peroleh sebagai rampasan perang, maka sesungguhnya seperlima untuk Allah, Rasul, kerabat Rasul, anak-anak yatim, orang-orang miskin dan ibnussabil, jika kamu beriman kepada Allah dan kepada apa yang kami turunkan kepada hamba Kami (Muhammad) di hari Furqaan, yaitu di hari bertemunya dua pasukan. Dan Allah Maha Kuasa atas segala sesuatu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Yaitu di hari) ketika kamu berada di pinggir lembah yang dekat dan mereka berada di pinggir lembah yang jauh sedang kafilah itu berada di bawah kamu. Sekiranya kamu mengadakan persetujuan (untuk menentukan hari pertempuran), pastilah kamu tidak sependapat dalam menentukan hari pertempuran itu, akan tetapi (Allah mempertemukan dua pasukan itu) agar Dia melakukan suatu urusan yang mesti dilaksanakan, yaitu agar orang yang binasa itu binasanya dengan keterangan yang nyata dan agar orang yang hidup itu hidupnya dengan keterangan yang nyata (pula). Sesungguhnya Allah Maha Mendengar lagi Maha Mengetahui,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(yaitu) ketika Allah menampakkan mereka kepadamu di dalam mimpimu (berjumlah) sedikit. Dan sekiranya Allah memperlihatkan mereka kepada kamu (berjumlah) banyak tentu saja kamu menjadi gentar dan tentu saja kamu akan berbantah-bantahan dalam urusan itu, akan tetapi Allah telah menyelamatkan kamu. Sesungguhnya Allah Maha Mengetahui segala isi hati.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 44), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan ketika Allah menampakkan mereka kepada kamu sekalian, ketika kamu berjumpa dengan mereka berjumlah sedikit pada penglihatan matamu dan kamu ditampakkan-Nya berjumlah sedikit pada penglihatan mata mereka, karena Allah hendak melakukan suatu urusan yang mesti dilaksanakan. Dan hanyalah kepada Allahlah dikembalikan segala urusan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 45), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai orang-orang yang beriman. apabila kamu memerangi pasukan (musuh), maka berteguh hatilah kamu dan sebutlah (nama) Allah sebanyak-banyaknya agar kamu beruntung.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 46), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan taatlah kepada Allah dan Rasul-Nya dan janganlah kamu berbantah-bantahan, yang menyebabkan kamu menjadi gentar dan hilang kekuatanmu dan bersabarlah. Sesungguhnya Allah beserta orang-orang yang sabar.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 47), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan janganlah kamu menjadi seperti orang-orang yang keluar dari kampungnya dengan rasa angkuh dan dengan maksud riya'' kepada manusia serta menghalangi (orang) dari jalan Allah. Dan (ilmu) Allah meliputi apa yang mereka kerjakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 48), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan ketika syaitan menjadikan mereka memandang baik pekerjaan mereka dan mengatakan: "Tidak ada seorang manusiapun yang dapat menang terhadapmu pada hari ini, dan sesungguhnya saya ini adalah pelindungmu". Maka tatkala kedua pasukan itu telah dapat saling lihat melihat (berhadapan), syaitan itu balik ke belakang seraya berkata: "Sesungguhnya saya berlepas diri daripada kamu, sesungguhnya saya dapat melihat apa yang kamu sekalian tidak dapat melihat; sesungguhnya saya takut kepada Allah". Dan Allah sangat keras siksa-Nya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 49), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Ingatlah), ketika orang-orang munafik dan orang-orang yang ada penyakit di dalam hatinya berkata: "Mereka itu (orang-orang mukmin) ditipu oleh agamanya". (Allah berfirman): "Barangsiapa yang bertawakkal kepada Allah, maka sesungguhnya Allah Maha Perkasa lagi Maha Bijaksana".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 50), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kalau kamu melihat ketika para malaikat mencabut jiwa orang-orang yang kafir seraya memukul muka dan belakang mereka (dan berkata): "Rasakanlah olehmu siksa neraka yang membakar", (tentulah kamu akan merasa ngeri).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 51), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Demikian itu disebabkan oleh perbuatan tanganmu sendiri. Sesungguhnya Allah sekali-kali tidak menganiaya hamba-Nya,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 52), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(keadaan mereka) serupa dengan keadaan Fir''aun dan pengikut-pengikutnya serta orang-orang yang sebelumnya. Mereka mengingkari ayat-ayat Allah, maka Allah menyiksa mereka disebabkan dosa-dosanya. Sesungguhnya Allah Maha Kuat lagi amat keras siksaan-Nya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 53), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Siksaan) yang demikian itu adalah karena sesungguhnya Allah sekali-kali tidak akan meubah sesuatu nikmat yang telah dianugerahkan-Nya kepada suatu kaum, hingga kaum itu meubah apa-apa yang ada pada diri mereka sendiri, dan sesungguhnya Allah Maha Mendengar lagi Maha Mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 54), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(keadaan mereka) serupa dengan keadaan Fir''aun dan pengikut-pengikutnya serta orang-orang yang sebelumnya. Mereka mendustakan ayat-ayat Tuhannya maka Kami membinasakan mereka disebabkan dosa-dosanya dan Kami tenggelamkan Fir''aun dan pengikut-pengikutnya; dan kesemuanya adalah orang-orang yang zalim.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 55), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya binatang (makhluk) yang paling buruk di sisi Allah ialah orang-orang yang kafir, karena mereka itu tidak beriman.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 56), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Yaitu) orang-orang yang kamu telah mengambil perjanjian dari mereka, sesudah itu mereka mengkhianati janjinya pada setiap kalinya, dan mereka tidak takut (akibat-akibatnya).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 57), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Jika kamu menemui mereka dalam peperangan, maka cerai beraikanlah orang-orang yang di belakang mereka dengan (menumpas) mereka, supaya mereka mengambil pelajaran.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 58), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan jika kamu khawatir akan (terjadinya) pengkhianatan dari suatu golongan, maka kembalikanlah perjanjian itu kepada mereka dengan cara yang jujur. Sesungguhnya Allah tidak menyukai orang-orang yang berkhianat.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 59), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan janganlah orang-orang yang kafir itu mengira, bahwa mereka akan dapat lolos (dari kekuasaan Allah). Sesungguhnya mereka tidak dapat melemahkan (Allah).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 60), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan siapkanlah untuk menghadapi mereka kekuatan apa saja yang kamu sanggupi dan dari kuda-kuda yang ditambat untuk berperang (yang dengan persiapan itu) kamu menggentarkan musuh Allah dan musuhmu dan orang orang selain mereka yang kamu tidak mengetahuinya; sedang Allah mengetahuinya. Apa saja yang kamu nafkahkan pada jalan Allah niscaya akan dibalasi dengan cukup kepadamu dan kamu tidak akan dianiaya (dirugikan).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 61), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan jika mereka condong kepada perdamaian, maka condonglah kepadanya dan bertawakkallah kepada Allah. Sesungguhnya Dialah Yang Maha Mendengar lagi Maha Mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 62), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan jika mereka bermaksud menipumu, maka sesungguhnya cukuplah Allah (menjadi pelindungmu). Dialah yang memperkuatmu dengan pertolongan-Nya dan dengan para mukmin,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 63), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan Yang mempersatukan hati mereka (orang-orang yang beriman). Walaupun kamu membelanjakan semua (kekayaan) yang berada di bumi, niscaya kamu tidak dapat mempersatukan hati mereka, akan tetapi Allah telah mempersatukan hati mereka. Sesungguhnya Dia Maha Gagah lagi Maha Bijaksana.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 64), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai Nabi, cukuplah Allah (menjadi Pelindung) bagimu dan bagi orang-orang mukmin yang mengikutimu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 65), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai Nabi, kobarkanlah semangat para mukmin untuk berperang. Jika ada dua puluh orang yang sabar diantaramu, niscaya mereka akan dapat mengalahkan dua ratus orang musuh. Dan jika ada seratus orang yang sabar diantaramu, niscaya mereka akan dapat mengalahkan seribu dari pada orang kafir, disebabkan orang-orang kafir itu kaum yang tidak mengerti.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 66), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sekarang Allah telah meringankan kepadamu dan dia telah mengetahui bahwa padamu ada kelemahan. Maka jika ada diantaramu seratus orang yang sabar, niscaya mereka akan dapat mengalahkan dua ratus orang kafir; dan jika diantaramu ada seribu orang (yang sabar), niscaya mereka akan dapat mengalahkan dua ribu orang, dengan seizin Allah. Dan Allah beserta orang-orang yang sabar.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 67), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tidak patut, bagi seorang Nabi mempunyai tawanan sebelum ia dapat melumpuhkan musuhnya di muka bumi. Kamu menghendaki harta benda duniawiyah sedangkan Allah menghendaki (pahala) akhirat (untukmu). Dan Allah Maha Perkasa lagi Maha Bijaksana.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 68), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kalau sekiranya tidak ada ketetapan yang telah terdahulu dari Allah, niscaya kamu ditimpa siksaan yang besar karena tebusan yang kamu ambil.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 69), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka makanlah dari sebagian rampasan perang yang telah kamu ambil itu, sebagai makanan yang halal lagi baik, dan bertakwalah kepada Allah; sesungguhnya Allah Maha Pengampun lagi Maha Penyayang.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 70), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai Nabi, katakanlah kepada tawanan-tawanan yang ada di tanganmu: "Jika Allah mengetahui ada kebaikan dalam hatimu, niscaya Dia akan memberikan kepadamu yang lebih baik dari apa yang telah diambil daripadamu dan Dia akan mengampuni kamu". Dan Allah Maha Pengampun lagi Maha Penyayang.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 71), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Akan tetapi jika mereka (tawanan-tawanan itu) bermaksud hendak berkhianat kepadamu, maka sesungguhnya mereka telah berkhianat kepada Allah sebelum ini, lalu Allah menjadikan(mu) berkuasa terhadap mereka. Dan Allah Maha Mengetahui lagi Maha Bijaksana.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 72), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya orang-orang yang beriman dan berhijrah serta berjihad dengan harta dan jiwanya pada jalan Allah dan orang-orang yang memberikan tempat kediaman dan pertoIongan (kepada orang-orang muhajirin), mereka itu satu sama lain lindung-melindungi. Dan (terhadap) orang-orang yang beriman, tetapi belum berhijrah, maka tidak ada kewajiban sedikitpun atasmu melindungi mereka, sebelum mereka berhijrah. (Akan tetapi) jika mereka meminta pertolongan kepadamu dalam (urusan pembelaan) agama, maka kamu wajib memberikan pertolongan kecuali terhadap kaum yang telah ada perjanjian antara kamu dengan mereka. Dan Allah Maha Melihat apa yang kamu kerjakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 73), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Adapun orang-orang yang kafir, sebagian mereka menjadi pelindung bagi sebagian yang lain. Jika kamu (hai para muslimin) tidak melaksanakan apa yang telah diperintahkan Allah itu, niscaya akan terjadi kekacauan di muka bumi dan kerusakan yang besar.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 74), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan orang-orang yang beriman dan berhijrah serta berjihad pada jalan Allah, dan orang-orang yang memberi tempat kediaman dan memberi pertolongan (kepada orang-orang muhajirin), mereka itulah orang-orang yang benar-benar beriman. Mereka memperoleh ampunan dan rezeki (nikmat) yang mulia.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 8 AND a.ayah_number = 75), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan orang-orang yang beriman sesudah itu kemudian berhijrah serta berjihad bersamamu maka orang-orang itu termasuk golonganmu (juga). Orang-orang yang mempunyai hubungan kerabat itu sebagiannya lebih berhak terhadap sesamanya (daripada yang bukan kerabat) di dalam kitab Allah. Sesungguhnya Allah Maha Mengetahui segala sesuatu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Inilah pernyataan) pemutusan hubungan dari Allah dan Rasul-Nya (yang dihadapkan) kepada orang-orang musyrikin yang kamu (kaum muslimin) telah mengadakan perjanjian (dengan mereka).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka berjalanlah kamu (kaum musyrikin) di muka bumi selama empat bulan dan ketahuilah bahwa sesungguhnya kamu tidak akan dapat melemahkan Allah, dan sesungguhnya Allah menghinakan orang-orang kafir.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (inilah) suatu permakluman daripada Allah dan Rasul-Nya kepada umat manusia pada hari haji akbar bahwa sesungguhnya Allah dan Rasul-Nya berlepas diri dari orang-orang musyrikin. Kemudian jika kamu (kaum musyrikin) bertobat, maka bertaubat itu lebih baik bagimu; dan jika kamu berpaling, maka ketahuilah bahwa sesungguhnya kamu tidak dapat melemahkan Allah. Dan beritakanlah kepada orang-orang kafir (bahwa mereka akan mendapat) siksa yang pedih.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'kecuali orang-orang musyrikin yang kamu telah mengadakan perjanjian (dengan mereka) dan mereka tidak mengurangi sesuatu pun (dari isi perjanjian)mu dan tidak (pula) mereka membantu seseorang yang memusuhi kamu, maka terhadap mereka itu penuhilah janjinya sampai batas waktunya. Sesungguhnya Allah menyukai orang-orang yang bertakwa.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Apabila sudah habis bulan-bulan Haram itu, maka bunuhlah orang-orang musyrikin itu dimana saja kamu jumpai mereka, dan tangkaplah mereka. Kepunglah mereka dan intailah ditempat pengintaian. Jika mereka bertaubat dan mendirikan sholat dan menunaikan zakat, maka berilah kebebasan kepada mereka untuk berjalan. Sesungguhnya Allah Maha Pengampun lagi maha Penyayang.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan jika seorang diantara orang-orang musyrikin itu meminta perlindungan kepadamu, maka lindungilah ia supaya ia sempat mendengar firman Allah, kemudian antarkanlah ia ketempat yang aman baginya. Demikian itu disebabkan mereka kaum yang tidak mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Bagaimana bisa ada perjanjian (aman) dari sisi Allah dan Rasul-Nya dengan orang-orang musyrikin, kecuali orang-orang yang kamu telah mengadakan perjanjian (dengan mereka) di dekat Masjidil haraam? maka selama mereka berlaku lurus terhadapmu, hendaklah kamu berlaku lurus (pula) terhadap mereka. Sesungguhnya Allah menyukai orang-orang yang bertakwa.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Bagaimana bisa (ada perjanjian dari sisi Allah dan Rasul-Nya dengan orang-orang musyrikin), padahal jika mereka memperoleh kemenangan terhadap kamu, mereka tidak memelihara hubungan kekerabatan terhadap kamu dan tidak (pula mengindahkan) perjanjian. Mereka menyenangkan hatimu dengan mulutnya, sedang hatinya menolak. Dan kebanyakan mereka adalah orang-orang yang fasik (tidak menepati perjanjian).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka menukarkan ayat-ayat Allah dengan harga yang sedikit, lalu mereka menghalangi (manusia) dari jalan Allah. Sesungguhnya amat buruklah apa yang mereka kerjakan itu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka tidak memelihara (hubungan) kerabat terhadap orang-orang mukmin dan tidak (pula mengindahkan) perjanjian. Dan mereka itulah orang-orang yang melampaui batas.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Jika mereka bertaubat, mendirikan sholat dan menunaikan zakat, maka (mereka itu) adalah saudara-saudaramu seagama. Dan Kami menjelaskan ayat-ayat itu bagi kaum yang mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Jika mereka merusak sumpah (janji)nya sesudah mereka berjanji, dan mereka mencerca agamamu, maka perangilah pemimpin-pemimpin orang-orang kafir itu, karena sesungguhnya mereka itu adalah orang-orang (yang tidak dapat dipegang) janjinya, agar supaya mereka berhenti.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mengapakah kamu tidak memerangi orang-orang yang merusak sumpah (janjinya), padahal mereka telah keras kemauannya untuk mengusir Rasul dan merekalah yang pertama mulai memerangi kamu? Mengapakah kamu takut kepada mereka padahal Allah-lah yang berhak untuk kamu takuti, jika kamu benar-benar orang yang beriman.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Perangilah mereka, niscaya Allah akan menghancurkan mereka dengan (perantaraan) tangan-tanganmu dan Allah akan menghinakan mereka dan menolong kamu terhadap mereka, serta melegakan hati orang-orang yang beriman.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan menghilangkan panas hati orang-orang mukmin. Dan Allah menerima taubat orang yang dikehendaki-Nya. Allah maha Mengetahui lagi Maha Bijaksana.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Apakah kamu mengira bahwa kamu akan dibiarkan, sedang Allah belum mengetahui (dalam kenyataan) orang-orang yang berjihad di antara kamu dan tidak mengambil menjadi teman yang setia selain Allah, Rasul-Nya dan orang-orang yang beriman. Dan Allah Maha Mengetahui apa yang kamu kerjakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tidaklah pantas orang-orang musyrik itu memakmurkan mesjid-mesjid Allah, sedang mereka mengakui bahwa mereka sendiri kafir. Itulah orang-orang yang sia-sia pekerjaannya, dan mereka kekal di dalam neraka.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hanya yang memakmurkan masjid-masjid Allah ialah orang-orang yang beriman kepada Allah dan Hari kemudian, serta tetap mendirikan shalat, menunaikan zakat dan tidak takut (kepada siapapun) selain kepada Allah, maka merekalah orang-orang yang diharapkan termasuk golongan orang-orang yang mendapat petunjuk.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Apakah (orang-orang) yang memberi minuman orang-orang yang mengerjakan haji dan mengurus Masjidilharam kamu samakan dengan orang-orang yang beriman kepada Allah dan hari kemudian serta bejihad di jalan Allah? Mereka tidak sama di sisi Allah; dan Allah tidak memberi petunjuk kepada kaum yang zalim.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'orang-orang yang beriman dan berhijrah serta berjihad di jalan Allah dengan harta, benda dan diri mereka, adalah lebih tinggi derajatnya di sisi Allah; dan itulah orang-orang yang mendapat kemenangan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tuhan mereka menggembirakan mereka dengan memberikan rahmat dari pada-Nya, keridhaan dan surga, mereka memperoleh didalamnya kesenangan yang kekal,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'mereka kekal di dalamnya selama-lamanya. Sesungguhnya di sisi Allah-lah pahala yang besar.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai orang-orang beriman, janganlah kamu jadikan bapa-bapa dan saudara-saudaramu menjadi wali(mu), jika mereka lebih mengutamakan kekafiran atas keimanan dan siapa di antara kamu yang menjadikan mereka wali, maka mereka itulah orang-orang yang zalim.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "jika bapa-bapa, anak-anak, saudara-saudara, isteri-isteri, kaum keluargamu, harta kekayaan yang kamu usahakan, perniagaan yang kamu khawatiri kerugiannya, dan tempat tinggal yang kamu sukai, adalah lebih kamu cintai dari Allah dan Rasul-Nya dan dari berjihad di jalan-Nya, maka tunggulah sampai Allah mendatangkan keputusan-Nya". Dan Allah tidak memberi petunjuk kepada orang-orang yang fasik.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya Allah telah menolong kamu (hai para mukminin) di medan peperangan yang banyak, dan (ingatlah) peperangan Hunain, yaitu diwaktu kamu menjadi congkak karena banyaknya jumlah(mu), maka jumlah yang banyak itu tidak memberi manfaat kepadamu sedikitpun, dan bumi yang luas itu telah terasa sempit olehmu, kemudian kamu lari kebelakang dengan bercerai-berai.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kemudian Allah menurunkan ketenangan kepada Rasul-Nya dan kepada orang-orang yang beriman, dan Allah menurunkan bala tentara yang kamu tiada melihatnya, dan Allah menimpakan bencana kepada orang-orang yang kafir, dan demikianlah pembalasan kepada orang-orang yang kafir.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesudah itu Allah menerima taubat dari orang-orang yang dikehendaki-Nya. Allah Maha Pengampun lagi Maha Penyayang.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai orang-orang yang beriman, Sesungguhnya orang-orang yang musyrik itu najis, maka janganlah mereka mendekati Masjidilharam sesudah tahun ini. Dan jika kamu khawatir menjadi miskin, maka Allah nanti akan memberimu kekayaan kepadamu dari karunia-Nya, jika Dia menghendaki. Sesungguhnya Allah Maha Mengetahui lagi Maha Bijaksana.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Perangilah orang-orang yang tidak beriman kepada Allah dan tidak (pula) kepada hari kemudian, dan mereka tidak mengharamkan apa yang diharamkan oleh Allah dan Rasul-Nya dan tidak beragama dengan agama yang benar (agama Allah), (yaitu orang-orang) yang diberikan Al-Kitab kepada mereka, sampai mereka membayar jizyah dengan patuh sedang mereka dalam keadaan tunduk.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Orang-orang Yahudi berkata: "Uzair itu putera Allah" dan orang-orang Nasrani berkata: "Al Masih itu putera Allah". Demikianlah itu ucapan mereka dengan mulut mereka, mereka meniru perkataan orang-orang kafir yang terdahulu. Dilaknati Allah mereka, bagaimana mereka sampai berpaling?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka menjadikan orang-orang alimnya dan rahib-rahib mereka sebagai tuhan selain Allah dan (juga mereka mempertuhankan) Al Masih putera Maryam, padahal mereka hanya disuruh menyembah Tuhan yang Esa, tidak ada Tuhan (yang berhak disembah) selain Dia. Maha suci Allah dari apa yang mereka persekutukan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka berkehendak memadamkan cahaya (agama) Allah dengan mulut (ucapan-ucapan) mereka, dan Allah tidak menghendaki selain menyempurnakan cahaya-Nya, walaupun orang-orang yang kafir tidak menyukai.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dialah yang telah mengutus Rasul-Nya (dengan membawa) petunjuk (Al-Quran) dan agama yang benar untuk dimenangkan-Nya atas segala agama, walaupun orang-orang musyrikin tidak menyukai.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai orang-orang yang beriman, sesungguhnya sebahagian besar dari orang-orang alim Yahudi dan rahib-rahib Nasrani benar-benar memakan harta orang dengan jalan batil dan mereka menghalang-halangi (manusia) dari jalan Allah. Dan orang-orang yang menyimpan emas dan perak dan tidak menafkahkannya pada jalan Allah, maka beritahukanlah kepada mereka, (bahwa mereka akan mendapat) siksa yang pedih,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'pada hari dipanaskan emas perak itu dalam neraka jahannam, lalu dibakar dengannya dahi mereka, lambung dan punggung mereka (lalu dikatakan) kepada mereka: "Inilah harta bendamu yang kamu simpan untuk dirimu sendiri, maka rasakanlah sekarang (akibat dari) apa yang kamu simpan itu".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya bilangan bulan pada sisi Allah adalah dua belas bulan, dalam ketetapan Allah di waktu Dia menciptakan langit dan bumi, di antaranya empat bulan haram. Itulah (ketetapan) agama yang lurus, maka janganlah kamu menganiaya diri kamu dalam bulan yang empat itu, dan perangilah kaum musyrikin itu semuanya sebagaimana merekapun memerangi kamu semuanya, dan ketahuilah bahwasanya Allah beserta orang-orang yang bertakwa.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya mengundur-undurkan bulan haram itu adalah menambah kekafiran. Disesatkan orang-orang yang kafir dengan mengundur-undurkan itu, mereka menghalalkannya pada suatu tahun dan mengharamkannya pada tahun yang lain, agar mereka dapat mempersesuaikan dengan bilangan yang Allah mengharamkannya, maka mereka menghalalkan apa yang diharamkan Allah. (Syaitan) menjadikan mereka memandang perbuatan mereka yang buruk itu. Dan Allah tidak memberi petunjuk kepada orang-orang yang kafir.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai orang-orang yang beriman, apakah sebabnya bila dikatakan kepadamu: "Berangkatlah (untuk berperang) pada jalan Allah" kamu merasa berat dan ingin tinggal di tempatmu? Apakah kamu puas dengan kehidupan di dunia sebagai ganti kehidupan di akhirat? Padahal kenikmatan hidup di dunia ini (dibandingkan dengan kehidupan) diakhirat hanyalah sedikit.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Jika kamu tidak berangkat untuk berperang, niscaya Allah menyiksa kamu dengan siksa yang pedih dan digantinya (kamu) dengan kaum yang lain, dan kamu tidak akan dapat memberi kemudharatan kepada-Nya sedikitpun. Allah Maha Kuasa atas segala sesuatu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Jikalau kamu tidak menolongnya (Muhammad) maka sesungguhnya Allah telah menolongnya (yaitu) ketika orang-orang kafir (musyrikin Mekah) mengeluarkannya (dari Mekah) sedang dia salah seorang dari dua orang ketika keduanya berada dalam gua, di waktu dia berkata kepada temannya: "Janganlah kamu berduka cita, sesungguhnya Allah beserta kita". Maka Allah menurunkan keterangan-Nya kepada (Muhammad) dan membantunya dengan tentara yang kamu tidak melihatnya, dan Al-Quran menjadikan orang-orang kafir itulah yang rendah. Dan kalimat Allah itulah yang tinggi. Allah Maha Perkasa lagi Maha Bijaksana.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Berangkatlah kamu baik dalam keadaan merasa ringan maupun berat, dan berjihadlah kamu dengan harta dan dirimu di jalan Allah. Yang demikian itu adalah lebih baik bagimu, jika kamu mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kalau yang kamu serukan kepada mereka itu keuntungan yang mudah diperoleh dan perjalanan yang tidak seberapa jauh, pastilah mereka mengikutimu, tetapi tempat yang dituju itu amat jauh terasa oleh mereka. Mereka akan bersumpah dengan (nama) Allah: "Jikalau kami sanggup tentulah kami berangkat bersama-samamu". Mereka membinasakan diri mereka sendiri dan Allah mengetahui bahwa sesungguhnya mereka benar-benar orang-orang yang berdusta.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Semoga Allah memaafkanmu. Mengapa kamu memberi izin kepada mereka (untuk tidak pergi berperang), sebelum jelas bagimu orang-orang yang benar (dalam keuzurannya) dan sebelum kamu ketahui orang-orang yang berdusta?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 44), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Orang-orang yang beriman kepada Allah dan hari kemudian, tidak akan meminta izin kepadamu untuk tidak ikut berjihad dengan harta dan diri mereka. Dan Allah mengetahui orang-orang yang bertakwa.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 45), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya yang akan meminta izin kepadamu, hanyalah orang-orang yang tidak beriman kepada Allah dan hari kemudian, dan hati mereka ragu-ragu, karena itu mereka selalu bimbang dalam keraguannya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 46), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan jika mereka mau berangkat, tentulah mereka menyiapkan persiapan untuk keberangkatan itu, tetapi Allah tidak menyukai keberangkatan mereka, maka Allah melemahkan keinginan mereka. dan dikatakan kepada mereka: "Tinggallah kamu bersama orang-orang yang tinggal itu".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 47), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Jika mereka berangkat bersama-sama kamu, niscaya mereka tidak menambah kamu selain dari kerusakan belaka, dan tentu mereka akan bergegas maju ke muka di celah-celah barisanmu, untuk mengadakan kekacauan di antara kamu; sedang di antara kamu ada orang-orang yang amat suka mendengarkan perkataan mereka. Dan Allah mengetahui orang-orang yang zalim.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 48), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya dari dahulupun mereka telah mencari-cari kekacauan dan mereka mengatur pelbagai macam tipu daya untuk (merusakkan)mu, hingga datanglah kebenaran (pertolongan Allah) dan menanglah agama Allah, padahal mereka tidak menyukainya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 49), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Di antara mereka ada orang yang berkata: "Berilah saya keizinan (tidak pergi berperang) dan janganlah kamu menjadikan saya terjerumus dalam fitnah". Ketahuilah bahwa mereka telah terjerumus ke dalam fitnah. Dan sesungguhnya Jahannam itu benar-benar meliputi orang-orang yang kafir.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 50), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Jika kamu mendapat suatu kebaikan, mereka menjadi tidak senang karenanya; dan jika kamu ditimpa oleh sesuatu bencana, mereka berkata: "Sesungguhnya kami sebelumnya telah memperhatikan urusan kami (tidak pergi perang)" dan mereka berpaling dengan rasa gembira.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 51), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Sekali-kali tidak akan menimpa kami melainkan apa yang telah ditetapkan Allah untuk kami. Dialah Pelindung kami, dan hanya kepada Allah orang-orang yang beriman harus bertawakal".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 52), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "tidak ada yang kamu tunggu-tunggu bagi kami, kecuali salah satu dari dua kebaikan. Dan Kami menunggu-nunggu bagi kamu bahwa Allah akan menimpakan kepadamu azab (yang besar) dari sisi-Nya. Sebab itu tunggulah, sesungguhnya kami menunggu-nunggu bersamamu".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 53), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Nafkahkanlah hartamu, baik dengan sukarela ataupun dengan terpaksa, namun nafkah itu sekali-kali tidak akan diterima dari kamu. Sesungguhnya kamu adalah orang-orang yang fasik.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 54), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan tidak ada yang menghalangi mereka untuk diterima dari mereka nafkah-nafkahnya melainkan karena mereka kafir kepada Allah dan Rasul-Nya dan mereka tidak mengerjakan sembahyang, melainkan dengan malas dan tidak (pula) menafkahkan (harta) mereka, melainkan dengan rasa enggan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 55), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka janganlah harta benda dan anak-anak mereka menarik hatimu. Sesungguhnya Allah menghendaki dengan (memberi) harta benda dan anak-anak itu untuk menyiksa mereka dalam kehidupan di dunia dan kelak akan melayang nyawa mereka, sedang mereka dalam keadaan kafir.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 56), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan mereka (orang-orang munafik) bersumpah dengan (nama) Allah, bahwa sesungguhnya mereka termasuk golonganmu; padahal mereka bukanlah dari golonganmu, akan tetapi mereka adalah orang-orang yang sangat takut (kepadamu).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 57), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Jikalau mereka memperoleh tempat perlindunganmu atau gua-gua atau lobang-lobang (dalam tanah) niscaya mereka pergi kepadanya dengan secepat-cepatnya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 58), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan di antara mereka ada orang yang mencelamu tentang (distribusi) zakat; jika mereka diberi sebahagian dari padanya, mereka bersenang hati, dan jika mereka tidak diberi sebahagian dari padanya, dengan serta merta mereka menjadi marah.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 59), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Jikalau mereka sungguh-sungguh ridha dengan apa yang diberikan Allah dan Rasul-Nya kepada mereka, dan berkata: "Cukuplah Allah bagi kami, Allah akan memberikan sebagian dari karunia-Nya dan demikian (pula) Rasul-Nya, sesungguhnya kami adalah orang-orang yang berharap kepada Allah," (tentulah yang demikian itu lebih baik bagi mereka).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 60), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya zakat-zakat itu, hanyalah untuk orang-orang fakir, orang-orang miskin, pengurus-pengurus zakat, para mu''allaf yang dibujuk hatinya, untuk (memerdekakan) budak, orang-orang yang berhutang, untuk jalan Allah dan untuk mereka yuang sedang dalam perjalanan, sebagai suatu ketetapan yang diwajibkan Allah, dan Allah Maha Mengetahui lagi Maha Bijaksana.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 61), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Di antara mereka (orang-orang munafik) ada yang menyakiti Nabi dan mengatakan: "Nabi mempercayai semua apa yang didengarnya". Katakanlah: "Ia mempercayai semua yang baik bagi kamu, ia beriman kepada Allah, mempercayai orang-orang mukmin, dan menjadi rahmat bagi orang-orang yang beriman di antara kamu". Dan orang-orang yang menyakiti Rasulullah itu, bagi mereka azab yang pedih.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 62), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka bersumpah kepada kamu dengan (nama) Allah untuk mencari keridhaanmu, padahal Allah dan Rasul-Nya itulah yang lebih patut mereka cari keridhaannya jika mereka adalah orang-orang yang mukmin.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 63), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tidaklah mereka (orang-orang munafik itu) mengetahui bahwasanya barangsiapa menentang Allah dan Rasul-Nya, maka sesungguhnya nerakan jahannamlah baginya, kekal mereka di dalamnya. Itu adalah kehinaan yang besar.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 64), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Orang-orang yang munafik itu takut akan diturunkan terhadap mereka sesuatu surat yang menerangkan apa yang tersembunyi dalam hati mereka. Katakanlah kepada mereka: "Teruskanlah ejekan-ejekanmu (terhadap Allah dan rasul-Nya)". Sesungguhnya Allah akan menyatakan apa yang kamu takuti itu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 65), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan jika kamu tanyakan kepada mereka (tentang apa yang mereka lakukan itu), tentulah mereka akan manjawab, "Sesungguhnya kami hanyalah bersenda gurau dan bermain-main saja". Katakanlah: "Apakah dengan Allah, ayat-ayat-Nya dan Rasul-Nya kamu selalu berolok-olok?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 66), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tidak usah kamu minta maaf, karena kamu kafir sesudah beriman. Jika Kami memaafkan segolongan kamu (lantaran mereka taubat), niscaya Kami akan mengazab golongan (yang lain) disebabkan mereka adalah orang-orang yang selalu berbuat dosa.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 67), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Orang-orang munafik laki-laki dan perempuan. sebagian dengan sebagian yang lain adalah sama, mereka menyuruh membuat yang munkar dan melarang berbuat yang ma''ruf dan mereka menggenggamkan tangannya. Mereka telah lupa kepada Allah, maka Allah melupakan mereka. Sesungguhnya orang-orang munafik itu adalah orang-orang yang fasik.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 68), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Allah mengancam orang-orang munafik laki-laki dan perempuan dan orang-orang kafir dengan neraka Jahannam, mereka kekal di dalamnya. Cukuplah neraka itu bagi mereka, dan Allah melaknati mereka, dan bagi mereka azab yang kekal.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 69), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(keadaan kamu hai orang-orang munafik dan musyrikin) adalah seperti keadaan orang-orang sebelum kamu, mereka lebih kuat daripada kamu, dan lebih banyak harta dan anak-anaknya dari kamu. Maka mereka telah menikmati bagian mereka, dan kamu telah menikmati bagian kamu sebagaimana orang-orang yang sebelummu menikmati bagiannya, dan kamu mempercakapkan (hal yang batil) sebagaimana mereka mempercakapkannya. Mereka itu amalannya menjadi sia-sia di dunia dan di akhirat; dan mereka itulah orang-orang yang merugi.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 70), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Belumkah datang kepada mereka berita penting tentang orang-orang yang sebelum mereka, (yaitu) kaum Nuh, ''Aad, Tsamud, kaum Ibrahim, penduduk Madyan dan negeri-negeri yang telah musnah?. Telah datang kepada mereka rasul-rasul dengan membawa keterangan yang nyata, maka Allah tidaklah sekali-kali menganiaya mereka, akan tetapi merekalah yang menganiaya diri mereka sendiri.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 71), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan orang-orang yang beriman, lelaki dan perempuan, sebahagian mereka (adalah) menjadi penolong bagi sebahagian yang lain. Mereka menyuruh (mengerjakan) yang ma''ruf, mencegah dari yang munkar, mendirikan shalat, menunaikan zakat dan mereka taat pada Allah dan Rasul-Nya. Mereka itu akan diberi rahmat oleh Allah; sesungguhnya Allah Maha Perkasa lagi Maha Bijaksana.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 72), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Allah menjanjikan kepada orang-orang mukmin, lelaki dan perempuan, (akan mendapat) surga yang dibawahnya mengalir sungai-sungai, kekal mereka di dalamnya, dan (mendapat) tempat-tempat yang bagus di surga ''Adn. Dan keridhaan Allah adalah lebih besar; itu adalah keberuntungan yang besar.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 73), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai Nabi, berjihadlah (melawan) orang-orang kafir dan orang-orang munafik itu, dan bersikap keraslah terhadap mereka. Tempat mereka ialah jahannam. Dan itu adalah tempat kembali yang seburuk-buruknya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 74), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka (orang-orang munafik itu) bersumpah dengan (nama) Allah, bahwa mereka tidak mengatakan (sesuatu yang menyakitimu). Sesungguhnya mereka telah mengucapkan perkataan kekafiran, dan telah menjadi kafir sesudah Islam dan mengingini apa yang mereka tidak dapat mencapainya, dan mereka tidak mencela (Allah dan Rasul-Nya), kecuali karena Allah dan Rasul-Nya telah melimpahkan karunia-Nya kepada mereka. Maka jika mereka bertaubat, itu adalah lebih baik bagi mereka, dan jika mereka berpaling, niscaya Allah akan mengazab mereka dengan azab yang pedih di dunia dan akhirat; dan mereka sekali-kali tidaklah mempunyai pelindung dan tidak (pula) penolong di muka bumi.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 75), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan diantara mereka ada orang yang telah berikrar kepada Allah: "Sesungguhnya jika Allah memberikan sebahagian karunia-Nya kepada kami, pastilah kami akan bersedekah dan pastilah kami termasuk orang-orang yang saleh.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 76), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka setelah Allah memberikan kepada mereka sebahagian dari karunia-Nya, mereka kikir dengan karunia itu, dan berpaling, dan mereka memanglah orang-orang yang selalu membelakangi (kebenaran).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 77), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka Allah menimbulkan kemunafikan pada hati mereka sampai kepada waktu mereka menemui Allah, karena mereka telah memungkiri terhadap Allah apa yang telah mereka ikrarkan kepada-Nya dan juga karena mereka selalu berdusta.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 78), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tidaklah mereka tahu bahwasanya Allah mengetahui rahasia dan bisikan mereka, dan bahwasanya Allah amat mengetahui segala yang ghaib.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 79), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Orang-orang munafik itu) yaitu orang-orang yang mencela orang-orang mukmin yang memberi sedekah dengan sukarela dan (mencela) orang-orang yang tidak memperoleh (untuk disedekahkan) selain sekedar kesanggupannya, maka orang-orang munafik itu menghina mereka. Allah akan membalas penghinaan mereka itu, dan untuk mereka azab yang pedih.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 80), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kamu memohonkan ampun bagi mereka atau tidak kamu mohonkan ampun bagi mereka (adalah sama saja). Kendatipun kamu memohonkan ampun bagi mereka tujuh puluh kali, namun Allah sekali-kali tidak akan memberi ampunan kepada mereka. Yang demikian itu adalah karena mereka kafir kepada Allah dan Rasul-Nya. Dan Allah tidak memberi petunjuk kepada kaum yang fasik.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 81), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Orang-orang yang ditinggalkan (tidak ikut perang) itu, merasa gembira dengan tinggalnya mereka di belakang Rasulullah, dan mereka tidak suka berjihad dengan harta dan jiwa mereka pada jalan Allah dan mereka berkata: "Janganlah kamu berangkat (pergi berperang) dalam panas terik ini". Katakanlah: "Api neraka jahannam itu lebih sangat panas(nya)" jika mereka mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 82), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka hendaklah mereka tertawa sedikit dan menangis banyak, sebagai pembalasan dari apa yang selalu mereka kerjakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 83), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka jika Allah mengembalikanmu kepada suatu golongan dari mereka, kemudian mereka minta izin kepadamu untuk keluar (pergi berperang), maka Katakanlah: "Kamu tidak boleh keluar bersamaku selama-lamanya dan tidak boleh memerangi musuh bersamaku. Sesungguhnya kamu telah rela tidak pergi berperang kali yang pertama. Karena itu duduklah bersama orang-orang yang tidak ikut berperang".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 84), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan janganlah kamu sekali-kali menyembahyangkan (jenazah) seorang yang mati di antara mereka, dan janganlah kamu berdiri (mendoakan) di kuburnya. Sesungguhnya mereka telah kafir kepada Allah dan Rasul-Nya dan mereka mati dalam keadaan fasik.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 85), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan janganlah harta benda dan anak-anak mereka menarik hatimu. Sesungguhnya Allah menghendaki akan mengazab mereka di dunia dengan harta dan anak-anak itu dan agar melayang nyawa mereka, dalam keadaan kafir.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 86), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan apabila diturunkan suatu surat (yang memerintahkan kepada orang munafik itu): "Berimanlah kamu kepada Allah dan berjihadlah beserta Rasul-Nya", niscaya orang-orang yang sanggup di antara mereka meminta izin kepadamu (untuk tidak berjihad) dan mereka berkata: "Biarkanlah kami berada bersama orang-orang yang duduk".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 87), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka rela berada bersama orang-orang yang tidak berperang, dan hati mereka telah dikunci mati maka mereka tidak mengetahui (kebahagiaan beriman dan berjihad).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 88), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tetapi Rasul dan orang-orang yang beriman bersama dia, mereka berjihad dengan harta dan diri mereka. Dan mereka itulah orang-orang yang memperoleh kebaikan, dan mereka itulah orang-orang yang beruntung.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 89), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Allah telah menyediakan bagi mereka surga yang mengalir di bawahnya sungai-sungai, mereka kekal di dalamnya. Itulah kemenangan yang besar.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 90), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan datang (kepada Nabi) orang-orang yang mengemukakan ''uzur, yaitu orang-orang Arab Baswi agar diberi izin bagi mereka (untuk tidak berjihad), sedang orang-orang yang mendustakan Allah dan Rasul-Nya, duduk berdiam diri saja. Kelak orang-orang yang kafir di antara mereka itu akan ditimpa azab yang pedih.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 91), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tiada dosa (lantaran tidak pergi berjihad) atas orang-orang yang lemah, orang-orang yang sakit dan atas orang-orang yang tidak memperoleh apa yang akan mereka nafkahkan, apabila mereka berlaku ikhlas kepada Allah dan Rasul-Nya. Tidak ada jalan sedikitpun untuk menyalahkan orang-orang yang berbuat baik. Dan Allah Maha Pengampun lagi Maha Penyayang,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 92), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan tiada (pula) berdosa atas orang-orang yang apabila mereka datang kepadamu, supaya kamu memberi mereka kendaraan, lalu kamu berkata: "Aku tidak memperoleh kendaraan untuk membawamu". lalu mereka kembali, sedang mata mereka bercucuran air mata karena kesedihan, lantaran mereka tidak memperoleh apa yang akan mereka nafkahkan.', NOW(), NOW());
